{"version":3,"sources":["uni_modules/uts-usage-stats/utssdk/app-android/UsageStatsForegroundService.uts","uni_modules/uts-sqlite-store/utssdk/app-android/SqliteStore.uts","uni_modules/uts-floating-overlay/utssdk/app-android/FloatingOverlay.uts","uni_modules/uts-audio-player/utssdk/app-android/AudioPlayer.uts","uni_modules/uts-audio-player/utssdk/app-android/SystemTts.uts","uni_modules/uts-usage-stats/utssdk/app-android/UsageStatsBridge.uts","App.uvue","services/CloudService.uts","D:/Program Files (x86)/HBuilderX/plugins/uniapp-cli-vite/node_modules/@dcloudio/uni-console/src/runtime/app/socket.ts","D:/Program Files (x86)/HBuilderX/plugins/uniapp-cli-vite/node_modules/@dcloudio/uni-console/src/runtime/utils.ts","D:/Program Files (x86)/HBuilderX/plugins/uniapp-cli-vite/node_modules/@dcloudio/uni-console/src/runtime/app/index.ts","models/EffectiveTriggerRule.uts","models/DailySummary.uts","models/WeeklyReport.uts","constants/LlmPrompts.uts","models/ActionLog.uts","constants/DefaultSettings.uts","database/DatabaseHelper.uts","models/ThreeStatus.uts","models/MicroAction.uts","database/DatabaseManager.uts","utils/DbRowUtils.uts","database/ActionLogDao.uts","models/TriggerLog.uts","database/TriggerLogDao.uts","utils/TimeUtils.uts","database/AppUsageDao.uts","models/DailyCount.uts","database/DailySummaryDao.uts","database/SettingsDao.uts","constants/CategoryMapping.uts","constants/Actions.uts","services/ScoreCalculator.uts","models/PersistedEffectiveRule.uts","database/EffectiveRuleDao.uts","utils/SystemAppUtils.uts","services/ActionManager.uts","services/RuleEngine.uts","services/NewbieGuard.uts","services/TriggerEngine.uts","services/EffectiveRuleEngine.uts","constants/EncourageTexts.uts","utils/VibrateUtils.uts","models/TtsCache.uts","database/TtsCacheDao.uts","models/LlmCache.uts","database/LlmCacheDao.uts","utils/HashUtils.uts","services/TtsService.uts","uni_modules/uts-usage-stats/utssdk/app-android/UsageTypes.uts","database/HeartbeatDao.uts","utils/NavigationHelper.uts","models/LlmHistoryEntry.uts","database/LlmHistoryDao.uts","services/LlmRejectTracker.uts","services/LlmTriggerFlow.uts","services/AppHistoryService.uts","services/UserProfileService.uts","services/EffectiveRuleService.uts","models/AppTag.uts","database/AppTagsDao.uts","services/AppCategoryService.uts","models/Achievement.uts","constants/Achievements.uts","database/AchievementDao.uts","services/AchievementService.uts","main.uts","services/PhoneUsageService.uts","components/HeatmapCalendar.uvue","services/Recommendation.uts","utils/NetworkUtils.uts","services/WeeklyReportService.uts","stores/appStore.uts","constants/MicroPlanetCopy.uts","pages/debug/logs.uvue","pages/debug/llm-rules.uvue","pages/settings/blacklist.uvue"],"sourcesContent":["// 使用情况监听：前台 Service\n// 5 秒轮询 queryUsageStats(INTERVAL_DAILY, now-24h, now) 找 lastTimeUsed 最大的非自家包\n// 作为\"当前前台 App\"，持续时长 = now - currentStartTime（=lastTimeUsed）\n// 每 30 分钟调 maybeReconcile 跑一次诊断 log（仅 debug 用）\n// 维护 currentPkg / currentStartTime / lastTickTime / lastReconcileTime / todayDate\n\nimport Service from 'android.app.Service'\nimport Context from 'android.content.Context'\nimport Intent from 'android.content.Intent'\nimport Handler from 'android.os.Handler'\nimport Looper from 'android.os.Looper'\nimport NotificationManager from 'android.app.NotificationManager'\nimport NotificationChannel from 'android.app.NotificationChannel'\nimport Notification from 'android.app.Notification'\nimport Build from 'android.os.Build'\nimport PowerManager from 'android.os.PowerManager'\nimport AppOpsManager from 'android.app.AppOpsManager'\nimport UsageStatsManager from 'android.app.usage.UsageStatsManager'\nimport UsageStats from 'android.app.usage.UsageStats'\nimport System from 'java.lang.System'\nimport Process from 'android.os.Process'\nimport SharedPreferences from 'android.content.SharedPreferences'\n\nimport { type AppForegroundInfo, type UsageStatEntry, type UsageMonitorCallbacks } from './UsageTypes'\nimport { insertHeartbeat } from '../../../../database/HeartbeatDao'\nimport { shouldFilterPackage } from '../../../../utils/SystemAppUtils'\n\nconst NOTIFICATION_ID: Int = 2\nconst CHANNEL_ID: string = 'micro_habit_usage_stats'\nconst FOREGROUND_TYPE_SPECIAL_USE: Int = 108\nconst WAKE_LOCK_TAG: string = 'MicroHabit:UsageStats'\nconst SERVICE_CLASS_NAME: string = 'uts.sdk.modules.utsUsageStats.UsageStatsForegroundService'\n\n// 模块级共享状态\nlet cachedCbs: UsageMonitorCallbacks | null = null\nlet thresholdMs: number = 60 * 60 * 1000\nlet pollIntervalMs: number = 5 * 60 * 1000\nlet serviceInstance: UsageStatsForegroundService | null = null\nlet monitoring: boolean = false\nlet lastReconcileTime: Long = 0\nlet triggerEnabled: boolean = false\n\nfunction getSelfPackageNameInternal(): string {\n  try {\n    const ctx = UTSAndroid.getAppContext()\n    if (ctx == null) return ''\n    const name = ctx.getPackageName() as string\n    if (name == null) return ''\n    return name\n  } catch (_) {\n    return ''\n  }\n}\n\nfunction currentDateString(): string {\n  const d = new Date()\n  const y = d.getFullYear()\n  const m = ('' + (d.getMonth() + 1)).padStart(2, '0')\n  const day = ('' + d.getDate()).padStart(2, '0')\n  return y + '-' + m + '-' + day\n}\n\nfunction startOfTodayMsLong(): Long {\n  const d = new Date()\n  d.setHours(0, 0, 0, 0)\n  return d.getTime().toLong()\n}\n\nfunction isInBlacklist(pkg: string, selfPkg: string): boolean {\n  // 委托给 SystemAppUtils.shouldFilterPackage（系统包 + 自身 + 空包名）\n  // 保留此函数作为内部 wrapper，调用方无需修改签名\n  return shouldFilterPackage(pkg, selfPkg)\n}\n\nfunction isUsagePermissionGrantedByContext(ctx: Context): boolean {\n  try {\n    const appOps = ctx.getSystemService(Context.APP_OPS_SERVICE) as AppOpsManager\n    if (appOps == null) return false\n    const mode = appOps.checkOpNoThrow(\n      AppOpsManager.OPSTR_GET_USAGE_STATS,\n      Process.myUid(),\n      ctx.getPackageName() as string\n    )\n    return mode == AppOpsManager.MODE_ALLOWED\n  } catch (_) {\n    return false\n  }\n}\n\n// 通过包名+类名字符串构造 Intent，避开 UTS 无法使用类引用作 Class 参数的限制\nfunction makeServiceIntent(ctx: Context): Intent {\n  const intent: Intent = Intent()\n  intent.setClassName(ctx, SERVICE_CLASS_NAME)\n  return intent\n}\n\n// ============================================================\n// 持久化偏好（SharedPreferences）\n// Service 被 START_STICKY 复活后，模块级 triggerEnabled/thresholdMs\n// 会被进程级 let 变量重置为默认值；通过 SharedPreferences 恢复\n// ============================================================\nconst PREFS_NAME: string = 'micro_habit_prefs'\nconst KEY_TRIGGER_ENABLED: string = 'trigger_enabled'\nconst KEY_POLL_THRESHOLD_MS: string = 'poll_threshold_ms'\n\nfunction getPrefs(): SharedPreferences | null {\n  try {\n    const ctx = UTSAndroid.getAppContext()\n    if (ctx == null) return null\n    return ctx.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)\n  } catch (_) {\n    return null\n  }\n}\n\n// 读回模块级 triggerEnabled / thresholdMs（默认值与模块级 let 初始值对齐）\nfunction loadPrefsFromDisk(): void {\n  try {\n    const prefs = getPrefs()\n    if (prefs == null) return\n    // 缺省值：triggerEnabled=false（避免复活后误触发），thresholdMs=1 小时\n    triggerEnabled = prefs.getBoolean(KEY_TRIGGER_ENABLED, false)\n    const defaultThresholdMs: number = 60 * 60 * 1000\n    thresholdMs = prefs.getLong(KEY_POLL_THRESHOLD_MS, defaultThresholdMs.toLong()) as number\n  } catch (_) {}\n}\n\nfunction savePrefsToDisk(triggerEnabledIn: boolean, thresholdMsIn: number): void {\n  try {\n    const prefs = getPrefs()\n    if (prefs == null) return\n    const editor = prefs.edit()\n    editor.putBoolean(KEY_TRIGGER_ENABLED, triggerEnabledIn)\n    editor.putLong(KEY_POLL_THRESHOLD_MS, thresholdMsIn.toLong())\n    editor.apply()\n  } catch (_) {}\n}\n\nexport class UsageStatsForegroundService extends Service {\n  private handler: Handler | null = null\n  private wakeLock: PowerManager.WakeLock | null = null\n  private lastTickTime: Long = 0\n  private todayDate: string = ''\n  private lastPeriod: string = ''\n  private started: boolean = false\n  private usm: UsageStatsManager | null = null\n  private selfPkgCache: string = ''\n\n  constructor() {\n    super()\n  }\n\n  override onCreate(): void {\n    try {\n      super.onCreate()\n      serviceInstance = this\n      // 优先读回持久化的 triggerEnabled / thresholdMs，\n      // 防止 START_STICKY 复活后模块级 let 重置为默认值导致 doPoll 静默空跑\n      loadPrefsFromDisk()\n      this.selfPkgCache = getSelfPackageNameInternal()\n      this.todayDate = currentDateString()\n      this.tryRefreshUsm()\n      this.createChannel()\n      this.startForegroundCompat()\n      this.acquireWakeLock()\n      this.startPolling()\n    } catch (e) {\n      __f__('error','at uni_modules/uts-usage-stats/utssdk/app-android/UsageStatsForegroundService.uts:168','[UsageStats] onCreate THREW: ' + JSON.stringify(e))\n    }\n  }\n\n  override onStartCommand(intent: Intent | null, flags: Int, startId: Int): Int {\n    if (!this.started) {\n      this.started = true\n      if (this.handler != null) {\n        // 清空旧 tick，避免 START_STICKY 复活后 callback 累积\n        this.handler!!.removeCallbacksAndMessages(null)\n      }\n      this.scheduleNextTick()\n    }\n    return Service.START_STICKY\n  }\n\n  override onDestroy(): void {\n    try { insertHeartbeat('stopped') } catch (e) {\n      __f__('warn','at uni_modules/uts-usage-stats/utssdk/app-android/UsageStatsForegroundService.uts:186','[UsageStats] heartbeat onDestroy write failed: ' + JSON.stringify(e))\n    }\n    this.stopPolling()\n    this.releaseWakeLock()\n    serviceInstance = null\n    monitoring = false\n    super.onDestroy()\n  }\n\n  override onBind(intent: Intent | null): android.os.IBinder | null {\n    return null\n  }\n\n  // 公开 stopPolling，让模块级 stopUsageMonitor 能调用\n  public stopPolling(): void {\n    this.started = false\n    if (this.handler != null) {\n      this.handler!!.removeCallbacksAndMessages(null)\n      this.handler = null\n    }\n  }\n\n  // 公开 runImmediatePoll，让模块级 setTriggerEnabled 在用户开启总开关时立即触发一次\n  public runImmediatePoll(): void {\n    if (!this.started) return\n    try {\n      this.doPoll()\n    } catch (e) {\n      __f__('warn','at uni_modules/uts-usage-stats/utssdk/app-android/UsageStatsForegroundService.uts:214','[UsageStats] immediate poll error: ' + JSON.stringify(e))\n    }\n  }\n\n  private createChannel(): void {\n    if (Build.VERSION.SDK_INT < 26) return\n    try {\n      const mgr = this.getSystemService(Context.NOTIFICATION_SERVICE) as NotificationManager\n      if (mgr == null) return\n      const ch = NotificationChannel(CHANNEL_ID, '微习惯健康守护', NotificationManager.IMPORTANCE_LOW)\n      ch.setDescription('前台使用情况监听')\n      mgr.createNotificationChannel(ch)\n    } catch (_) {}\n  }\n\n  private startForegroundCompat(): void {\n    const notif = this.buildNotification()\n    if (Build.VERSION.SDK_INT >= 30) {\n      this.startForeground(NOTIFICATION_ID, notif, FOREGROUND_TYPE_SPECIAL_USE)\n    } else {\n      this.startForeground(NOTIFICATION_ID, notif)\n    }\n  }\n\n  private buildNotification(): Notification {\n    return Notification.Builder(this, CHANNEL_ID)\n      .setContentTitle('微习惯健康伴侣')\n      .setContentText('正在守护你的健康')\n      .setSmallIcon(android.R.drawable.ic_popup_reminder)\n      .setOngoing(true)\n      .build()\n  }\n\n  private acquireWakeLock(): void {\n    // 先释放旧的，防止 tick 反复调用导致 WakeLock 累积\n    if (this.wakeLock != null) {\n      try { this.wakeLock!!.release() } catch (_) {}\n      this.wakeLock = null\n    }\n    try {\n      const pm = this.getSystemService(Context.POWER_SERVICE) as PowerManager\n      if (pm == null) return\n      this.wakeLock = pm.newWakeLock(PowerManager.PARTIAL_WAKE_LOCK, WAKE_LOCK_TAG)\n      if (this.wakeLock != null) {\n        this.wakeLock!!.acquire((30 * 60 * 1000).toLong())\n      }\n    } catch (_) {}\n  }\n\n  private releaseWakeLock(): void {\n    if (this.wakeLock != null) {\n      try { this.wakeLock!!.release() } catch (_) {}\n      this.wakeLock = null\n    }\n  }\n\n  private startPolling(): void {\n    if (this.started) return\n    this.handler = Handler(Looper.getMainLooper())\n    this.lastTickTime = System.currentTimeMillis()\n    this.started = true\n    monitoring = true\n    this.doPoll()  // 立即跑一次，不等首次 5 分钟（提升测试体验 + 启动即可拿数据）\n    this.scheduleNextTick()\n  }\n\n  private scheduleNextTick(): void {\n    if (this.handler == null) return\n    const self = this\n    this.handler!!.postDelayed(function(): void {\n      self.tick()\n    }, pollIntervalMs.toLong())\n  }\n\n  private tick(): void {\n    if (!this.started) return\n    // 每次 5 分钟 tick 写一条 'alive' 心跳，验证触发链路是否真的在跑\n    try { insertHeartbeat('alive') } catch (e) {\n      __f__('warn','at uni_modules/uts-usage-stats/utssdk/app-android/UsageStatsForegroundService.uts:292','[UsageStats] heartbeat tick write failed: ' + JSON.stringify(e))\n    }\n    try {\n      this.doPoll()\n    } catch (e) {\n      __f__('warn','at uni_modules/uts-usage-stats/utssdk/app-android/UsageStatsForegroundService.uts:297','[UsageStats] poll error: ' + JSON.stringify(e))\n    }\n    this.acquireWakeLock()\n    this.scheduleNextTick()\n  }\n\n  private doPoll(): void {\n    const nowMs: Long = System.currentTimeMillis()\n    // 触发总开关关闭：立即 return，不读 UsageStats、不写表、不触发\n    if (!triggerEnabled) {\n      return\n    }\n    if (this.usm == null) {\n      this.tryRefreshUsm()\n      if (this.usm == null) return\n    }\n    const ctx: Context = this\n    if (!isUsagePermissionGrantedByContext(ctx)) {\n      const cbs = cachedCbs\n      if (cbs != null) {\n        try { cbs.onPermissionMissing() } catch (_) {}\n      }\n      return\n    }\n\n    // ========== 核心：queryUsageStats 今日聚合数据遍历 ==========\n    try {\n      const todayStart: Long = startOfTodayMsLong()\n      const stats = this.usm!!.queryUsageStats(UsageStatsManager.INTERVAL_DAILY, todayStart, nowMs)\n      const sz: Int = stats.size\n      if (sz > 0) {\n        const cbs = cachedCbs\n        for (let i: Int = 0; i < sz; i++) {\n          const s: UsageStats = stats.get(i)\n          if (s == null) continue\n          const pkg: string = s.getPackageName() as string\n          if (isInBlacklist(pkg, this.selfPkgCache)) continue\n          const totalMs: Long = s.getTotalTimeInForeground() as number as Long\n          if (totalMs < 1) continue\n\n          // 写表：绝对值覆盖（与新聚合数据同步）\n          if (cbs != null) {\n            const totalSec: number = Math.floor(totalMs / 1000)\n            try { cbs.onUsageTick(pkg, totalSec) } catch (_) {}\n          }\n\n          // 触发判定：今日累计 >= 阈值（频率由 TriggerEngine 冷却期控制）\n          if (totalMs >= thresholdMs) {\n            if (cbs != null) {\n              const info: AppForegroundInfo = {\n                packageName: pkg,\n                startTime: nowMs,\n                continuousMs: totalMs\n              }\n              try { cbs.onAppDurationTrigger(info) } catch (_) {}\n            }\n          }\n        }\n      }\n    } catch (e) {\n      __f__('warn','at uni_modules/uts-usage-stats/utssdk/app-android/UsageStatsForegroundService.uts:357','[UsageStats] queryUsageStats 失败: ' + JSON.stringify(e))\n    }\n\n    this.checkTimePeriod(nowMs)\n    const rolled: boolean = this.checkDayRollover()\n    this.maybeReconcile(nowMs)\n    this.lastTickTime = nowMs\n  }\n\n  // 每 30 分钟跑一次诊断 log（仅 debug 用，不写库）\n  private maybeReconcile(now: Long): void {\n    if (lastReconcileTime < 1) {\n      lastReconcileTime = now\n      return\n    }\n    const interval: Long = 30 * 60 * 1000\n    if (now - lastReconcileTime < interval) return\n    lastReconcileTime = now\n    try {\n      const todayStart: Long = startOfTodayMsLong()\n      const usm = this.usm\n      if (usm == null) return\n      const stats = usm.queryUsageStats(UsageStatsManager.INTERVAL_DAILY, todayStart, now)\n      const sz: Int = stats.size\n      if (sz < 1) {\n        __f__('log','at uni_modules/uts-usage-stats/utssdk/app-android/UsageStatsForegroundService.uts:382','[UsageStats] reconcile: no system stats')\n        return\n      }\n      __f__('log','at uni_modules/uts-usage-stats/utssdk/app-android/UsageStatsForegroundService.uts:385','[UsageStats] reconcile: system has ' + sz + ' apps, top 3:')\n      let n: Int = 0\n      for (let i: Int = 0; i < sz && n < 3; i++) {\n        const s: UsageStats = stats.get(i)\n        if (s == null) continue\n        const pkg: string = s.getPackageName() as string\n        if (isInBlacklist(pkg, this.selfPkgCache)) continue\n        const totalMs: Long = s.getTotalTimeInForeground() as number as Long\n        __f__('log','at uni_modules/uts-usage-stats/utssdk/app-android/UsageStatsForegroundService.uts:393','[UsageStats]   ' + pkg + ' totalMs=' + totalMs)\n        n++\n      }\n    } catch (e) {\n      __f__('warn','at uni_modules/uts-usage-stats/utssdk/app-android/UsageStatsForegroundService.uts:397','[UsageStats] reconcile failed: ' + JSON.stringify(e))\n    }\n  }\n\n  private tryRefreshUsm(): void {\n    try {\n      this.usm = this.getSystemService(Context.USAGE_STATS_SERVICE) as UsageStatsManager\n    } catch (_) {\n      this.usm = null\n    }\n  }\n\n  private checkTimePeriod(now: Long): void {\n    const d = new Date(now as number)\n    const h = d.getHours()\n    let period: string = ''\n    if (h == 9) period = 'morning'\n    else if (h == 12) period = 'noon'\n    else if (h == 15) period = 'afternoon'\n    else if (h == 18) period = 'evening'\n    else if (h == 22) period = 'night'\n    if (period.length > 0 && period != this.lastPeriod) {\n      this.lastPeriod = period\n      const cbs = cachedCbs\n      if (cbs != null) {\n        try { cbs.onTimePeriodTrigger(period) } catch (_) {}\n      }\n    } else if (period.length < 1) {\n      this.lastPeriod = ''\n    }\n  }\n\n  private checkDayRollover(): boolean {\n    const today = currentDateString()\n    if (today != this.todayDate) {\n      const old = this.todayDate\n      this.todayDate = today\n      const cbs = cachedCbs\n      if (cbs != null) {\n        try { cbs.onDayRollover(old, today) } catch (_) {}\n      }\n      return true\n    }\n    return false\n  }\n\n}\n\n// ============================================================\n// 公共 API\n// ============================================================\n\nexport function startUsageMonitor(\n  cbs: UsageMonitorCallbacks,\n  thresholdMsIn: number,\n  pollIntervalMsIn: number,\n  triggerEnabledIn: boolean\n): void {\n  cachedCbs = cbs\n  if (thresholdMsIn > 0) {\n    thresholdMs = thresholdMsIn\n  }\n  if (pollIntervalMsIn > 0) {\n    pollIntervalMs = pollIntervalMsIn\n  }\n  triggerEnabled = triggerEnabledIn\n  // 持久化关键参数：START_STICKY 复活后由 onCreate 读回\n  savePrefsToDisk(triggerEnabled, thresholdMs)\n  monitoring = true\n  try {\n    const ctx = UTSAndroid.getAppContext()\n    if (ctx == null) return\n    ctx.startForegroundService(makeServiceIntent(ctx))\n  } catch (e) {\n    __f__('warn','at uni_modules/uts-usage-stats/utssdk/app-android/UsageStatsForegroundService.uts:471','[UsageStats] startForegroundService 失败: ' + JSON.stringify(e))\n  }\n}\n\n// 运行时切换触发总开关（settings 页 toggle 立即生效，无需等下次启动）\nexport function setTriggerEnabled(enabled: boolean): void {\n  triggerEnabled = enabled\n  // 开启时立即跑一次 doPoll，让用户快速看到效果\n  if (enabled) {\n    const svc = serviceInstance\n    if (svc != null) {\n      try { svc.runImmediatePoll() } catch (_) {}\n    }\n  }\n}\n\nexport function stopUsageMonitor(): void {\n  monitoring = false\n  cachedCbs = null\n  const svc = serviceInstance\n  if (svc != null) {\n    try { svc.stopPolling() } catch (_) {}\n  }\n  try {\n    const ctx = UTSAndroid.getAppContext()\n    if (ctx != null) {\n      ctx.stopService(makeServiceIntent(ctx))\n    }\n  } catch (_) {}\n}\n\nexport function isMonitoring(): boolean {\n  return monitoring\n}\n\nexport function isUsagePermissionGranted(): boolean {\n  try {\n    const ctx = UTSAndroid.getAppContext()\n    if (ctx == null) return false\n    return isUsagePermissionGrantedByContext(ctx)\n  } catch (_) {\n    return false\n  }\n}\n\nexport function getSelfPackageName(): string {\n  return getSelfPackageNameInternal()\n}\n\n// 已删除：getCurrentForeground — 不再维护\"当前前台\"概念\n// dashboard 改用 PhoneUsageDialog 读今日聚合数据展示\n\nexport function queryUsageStatsOnce(beginMs: number, endMs: number): UsageStatEntry[] {\n  const result: UsageStatEntry[] = []\n  try {\n    const ctx = UTSAndroid.getAppContext()\n    if (ctx == null) return result\n    if (!isUsagePermissionGrantedByContext(ctx)) return result\n    const usm = ctx.getSystemService(Context.USAGE_STATS_SERVICE) as UsageStatsManager\n    if (usm == null) return result\n    const begin: Long = beginMs.toLong()\n    const end: Long = endMs.toLong()\n    const stats = usm.queryUsageStats(UsageStatsManager.INTERVAL_BEST, begin, end)\n    const selfPkg = getSelfPackageNameInternal()\n    const n: Int = stats.size\n    for (let i: Int = 0; i < n; i++) {\n      const s = stats.get(i)\n      if (s == null) continue\n      const pkg = s.getPackageName() as string\n      if (pkg == null || pkg.length < 1) continue\n      // 改用 SystemAppUtils.shouldFilterPackage 一次性拦截系统包 + 自身\n      if (shouldFilterPackage(pkg, selfPkg)) continue\n      const entry: UsageStatEntry = {\n        packageName: pkg,\n        totalTimeInForeground: s.getTotalTimeInForeground() as number,\n        lastTimeUsed: s.getLastTimeUsed() as number\n      }\n      result.push(entry)\n    }\n  } catch (e) {\n    __f__('warn','at uni_modules/uts-usage-stats/utssdk/app-android/UsageStatsForegroundService.uts:551','[UsageStats] queryUsageStatsOnce 失败: ' + JSON.stringify(e))\n  }\n  return result\n}\n","import Context from 'android.content.Context'\r\nimport Cursor from 'android.database.Cursor'\r\nimport SQLiteDatabase from 'android.database.sqlite.SQLiteDatabase'\r\nimport SQLiteOpenHelper from 'android.database.sqlite.SQLiteOpenHelper'\r\nimport SQLiteStatement from 'android.database.sqlite.SQLiteStatement'\r\n\r\nexport type SqlRow = {\r\n  columns: string[]\r\n  values: (any | null)[]\r\n}\r\n\r\nclass MicroHabitSqliteHelper extends SQLiteOpenHelper {\r\n  private onCreateCallback: ((db: SQLiteDatabase) => void) | null = null\r\n  private onUpgradeCallback: ((db: SQLiteDatabase, oldV: number, newV: number) => void) | null = null\r\n\r\n  constructor(\r\n    ctx: Context,\r\n    name: string,\r\n    version: number,\r\n    onCreate: (db: SQLiteDatabase) => void,\r\n    onUpgrade: (db: SQLiteDatabase, oldV: number, newV: number) => void\r\n  ) {\r\n    super(ctx, name, null, version.toInt())\r\n    this.onCreateCallback = onCreate\r\n    this.onUpgradeCallback = onUpgrade\r\n  }\r\n\r\n  override onCreate(db: SQLiteDatabase): void {\r\n    const cb = this.onCreateCallback\r\n    if (cb != null) cb(db)\r\n  }\r\n\r\n  override onUpgrade(db: SQLiteDatabase, oldV: Int, newV: Int): void {\r\n    const cb = this.onUpgradeCallback\r\n    if (cb != null) cb(db, oldV, newV)\r\n  }\r\n}\r\n\r\nclass SqliteStore {\r\n  private helper: MicroHabitSqliteHelper | null = null\r\n  private db: SQLiteDatabase | null = null\r\n\r\n  openDatabase(\r\n    name: string,\r\n    version: number,\r\n    onCreate: () => void,\r\n    onUpgrade: (oldV: number, newV: number) => void\r\n  ): void {\r\n    if (this.db != null) return\r\n    const ctx: Context = UTSAndroid.getAppContext()!!\r\n    this.helper = new MicroHabitSqliteHelper(ctx!!, name, version,\r\n      (db: SQLiteDatabase): void => {\r\n        this.db = db\r\n        onCreate()\r\n      },\r\n      (db: SQLiteDatabase, oldV: number, newV: number): void => {\r\n        this.db = db\r\n        onUpgrade(oldV, newV)\r\n      }\r\n    )\r\n    this.db = this.helper!!.getWritableDatabase()\r\n  }\r\n\r\n  execSql(sql: string, params: any[] = []): void {\r\n    const d = this.db\r\n    if (d == null) return\r\n    if (params.length.toInt() < 1) {\r\n      d.execSQL(sql)\r\n      return\r\n    }\r\n    const stmt = d.compileStatement(sql)\r\n    try {\r\n      for (let i = 0; i < params.length; i++) {\r\n        this.bin