: (remainingMs: number) => void\r\n  onCountdownFinish: () => void\r\n  onPartialCompletion: (completedMs: number, totalMs: number) => void\r\n}\r\n\r\nlet overlayManager: FloatingOverlayManager | null = null\r\n\r\nexport function showOverlay(config: OverlayConfig, callbacks: OverlayCallbacks): void {\r\n  if (overlayManager == null) {\r\n    overlayManager = FloatingOverlayManager()\r\n  }\r\n  overlayManager!!.show(config, callbacks)\r\n}\r\n\r\nexport function dismissOverlay(): void {\r\n  if (overlayManager != null) {\r\n    overlayManager!!.dismiss()\r\n    overlayManager = null\r\n  }\r\n}\r\n\r\nexport function isOverlayShowing(): boolean {\r\n  return overlayManager != null && overlayManager!!.isShowing()\r\n}\r\n\r\nexport function hasOverlayPermission(): boolean {\r\n  if (Build.VERSION.SDK_INT >= 23) {\r\n    try {\r\n      const ctx = UTSAndroid.getAppContext()\r\n      if (ctx != null) {\r\n        return android.provider.Settings.canDrawOverlays(ctx)\r\n      }\r\n    } catch (_) {}\r\n  }\r\n  return true\r\n}\r\n\r\nexport function requestOverlayPermission(): void {\r\n  try {\r\n    if (Build.VERSION.SDK_INT >= 23) {\r\n      const ctx = UTSAndroid.getAppContext()\r\n      if (ctx != null) {\r\n        const intent = android.content.Intent(android.provider.Settings.ACTION_MANAGE_OVERLAY_PERMISSION)\r\n        intent.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK)\r\n        ctx.startActivity(intent)\r\n      }\r\n    }\r\n  } catch (_) {}\r\n}\r\n\r\nclass FloatingOverlayManager {\r\n  private wm: WindowManager | null = null\r\n  private rootView: FrameLayout | null = null\r\n  private showing: boolean = false\r\n  private handler: Handler | null = null\r\n  private remainingMs: number = 0\r\n  private totalMs: number = 0\r\n  private callbacks: OverlayCallbacks | null = null\r\n  private config: OverlayConfig | null = null\r\n  private state: string = 'hidden'\r\n\r\n  constructor() {}\r\n\r\n  show(config: OverlayConfig, callbacks: OverlayCallbacks): voi