 = Gravity.CENTER\r\n      content.setPadding(dp(20), dp(20), dp(20), dp(20))\r\n\r\n      const title = TextView(ctx)\r\n      title.setText(config.actionName)\r\n        title.setTextSize(22.0.toFloat())\r\n        title.setTextColor(Color.WHITE)\r\n        title.gravity = Gravity.CENTER\r\n        title.setPadding(0, 0, 0, dp(8))\r\n        content.addView(title)\r\n\r\n        const ttsView = TextView(ctx)\r\n        ttsView.setText(config.ttsText)\r\n        ttsView.setTextSize(15.0.toFloat())\r\n        ttsView.setTextColor(Color.parseColor('#DDDDDD'))\r\n        ttsView.gravity = Gravity.CENTER\r\n        ttsView.setPadding(0, 0, 0, dp(16))\r\n        content.addView(ttsView)\r\n\r\n        const btnRow1 = LinearLayout(ctx)\r\n        btnRow1.orientation = LinearLayout.HORIZONTAL\r\n        btnRow1.gravity = Gravity.CENTER\r\n\r\n        const selfBtn = Button(ctx)\r\n        selfBtn.setText('我做过了')\r\n        selfBtn.setTextSize(14.0.toFloat())\r\n        selfBtn.setTextColor(Color.WHITE)\r\n        selfBtn.setBackgroundColor(Color.parseColor('#555555'))\r\n        selfBtn.setPadding(dp(12), dp(8), dp(12), dp(8))\r\n        const self = this\r\n        selfBtn.setOnClickListener(function(v: View): void {\r\n          cbs.onSelfReported()\r\n          self.dismiss()\r\n        })\r\n        btnRow1.addView(selfBtn)\r\n\r\n        const gap = TextView(ctx)\r\n        gap.setText('   ')\r\n        btnRow1.addView(gap)\r\n\r\n        const busyBtn = Button(ctx)\r\n        busyBtn.setText('现在忙，晚点提醒我')\r\n        busyBtn.setTextSize(14.0.toFloat())\r\n      busyBtn.setTextColor(Color.WHITE)\r\n      busyBtn.setBackgroundColor(Color.parseColor('#555555'))\r\n      busyBtn.setPadding(dp(12), dp(8), dp(12), dp(8))\r\n      busyBtn.setOnClickListener(function(v: View): void {\r\n        cbs.onBusyRemindLater()\r\n        self.dismiss()\r\n      })\r\n      btnRow1.addView(busyBtn)\r\n\r\n      content.addView(btnRow1)\r\n\r\n      const spacer2 = TextView(ctx)\r\n      spacer2.setText('')\r\n      spacer2.setPadding(0, dp(12), 0, 0)\r\n      content.addView(spacer2)\r\n\r\n      const agreeBtn = Button(ctx)\r\n      agreeBtn.setText('好啊')\r\n      agreeBtn.setTextSize(18.0.toFloat())\r\n      agreeBtn.setTextColor(Color.WHITE)\r\n      agreeBtn.setBackgroundColor(Color.parseColor('#27AE60'))\r\n      agreeBtn.setPadding(dp(40), dp(12), dp(40), dp(12))\r\n      agreeBtn.setOnClickListener(function(v: View): void {\r\n        cbs.onAgree()\r\n        const r = self.rootView\r\n        if (r != null) {\r\n          r.removeAllViews()\r\n        }\r\n        self.switchToExec(ctx, config, cbs)\r\n      })\r\n      content.addView(agreeBtn)\r\n\r\n      root.addView(content)\r\n      return root\r\n    } catch (_) {\r\n      return null\r\n    }\r\n  }\r\n\r\n  private switchToExec(ctx: Context, config: OverlayConfig, cbs: OverlayCallbacks): void {\r\n    this.state = 'executing'\r\n    const root = this.rootView\r\n    if (root == null) return\r\n\r\n    const content = LinearLayout(ctx)\r\n    content.orientation = LinearLayout.VERTICAL\r\n    content.gravity = Gravity.CENTER\r\n    content.setPadding(dp(20), dp(20), dp(20), dp(20))\r\n\r\n    const title = TextView(ctx)\r\n    title.setText(config.actionName)\r\n    title.setTextSize(22.0.toFloat())\r\n    title.setTextColor(Color.WHITE)\r\n    title.gravity = Gravity.CENTER\r\n    title.setPadding(0, 0, 0, dp(16))\r\n    content.addView(title)\r\n\r\n    const ttsView = TextView(ctx)\r\n    ttsView.setText(config.ttsText)\r\n    ttsView.setTextSize(15.0.toFloat())\r\n    ttsView.setTextColor(Color.parseColor('#DDDDDD'))\r\n    ttsView.gravity = Gravity.CENTER\r\n    ttsView.setPadding(0, 0, 0, dp(20))\r\n    content.addView(ttsView)\r\n\r\n    const progressBar = ProgressBar(ctx, null, android.R.attr.progressBarStyleHorizontal)\r\n    progressBar.setMax(config.durationMs.toInt())\r\n    progressBar.setProgress(0)\r\n    progressBar.setPadding(0, 0, 0, dp(8))\r\n    content.addView(progressBar)\r\n\r\n    const countdownText = TextView(ctx)\r\n    countdownText.setText('' + Math.ceil(config.durationMs / 1000) + 's')\r\n    countdownText.setTextSize(18.0.toFloat())\r\n    countdownText.setTextColor(Color.WHITE)\r\n    countdownText.gravity = Gravity.CENTER\r\n    countdownText.setPadding(0, 0, 0, dp(20))\r\n    content.addView(countdownText)\r\n\r\n    const skipBtn = Button(ctx)\r\n    skipBtn.setText('跳过')\r\n    skipBtn.setTextSize(14.0.toFloat())\r\n    skipBtn.setTextColor(Color.WHITE)\r\n    skipBtn.setBackgroundColor(Color.parseColor('#E74C3C'))\r\n    skipBtn.setPadding(dp(20), dp(8), dp(20), dp(8))\r\n    const self = this\r\n    skipBtn.setOnClickListener(function(v: View): void {\r\n      cbs.onSkipDuringExec()\r\n      self.dismiss()\r\n    })\r\n    content.addView(skipBtn)\r\n\r\n    root.addView(content)\r\n    this.startCountdown(config.durationMs, cbs, progressBar, countdownText)\r\n  }\r\n\r\n  private startCountdown(total: number, cbs: OverlayCallbacks, bar: ProgressBar, text: TextView): void {\r\n    this.remainingMs = total\r\n    this.handler = Handler(Looper.getMainLooper())\r\n    const self = this\r\n    this.handler!!.postDelayed(function(): void {\r\n      self.remainingMs -= 100\r\n      const secs = Math.max(0, Math.ceil(self.remainingMs / 1000))\r\n      bar.setProgress((total - self.remainingMs).toInt())\r\n      text.setText('' + secs + 's')\r\n      if (self.remainingMs <= 0) {\r\n        cbs.onCountdownTick(0)\r\n        self.showDone(cbs)\r\n      } else {\r\n        cbs.onCountdownTick(self.remainingMs)\r\n        self.startCountdown(total, cbs, bar, text)\r\n      }\r\n    }, 100)\r\n  }\r\n\r\n  private showDone(cbs: OverlayCallbacks): void {\r\n    if (this.rootView == null) return\r\n    this.stopCountdown()\r\n    const root = this.rootView\r\n    root.removeAllViews()\r\n\r\n    const ctx = UTSAndroid.getAppContext()\r\n    if (ctx == null) return\r\n\r\n    const content = LinearLayout(ctx)\r\n    content.orientation = LinearLayout.VERTICAL\r\n    content.gravity = Gravity.CENTER\r\n    content.setPadding(dp(30), dp(40), dp(30), dp(40))\r\n\r\n    const checkMark = TextView(ctx)\r\n    checkMark.setText('✓')\r\n    checkMark.setTextSize(48.0.toFloat())\r\n    checkMark.setTextColor(Color.parseColor('#2ECC71'))\r\n    checkMark.gravity = Gravity.CENTER\r\n    content.addView(checkMark)\r\n\r\n    const doneText = TextView(ctx)\r\n    const encourage = this.config != null ? this.config!!.encourageText : '又完成一次！'\r\n    doneText.setText(encourage)\r\n    doneText.setTextSize(20.0.toFloat())\r\n    doneText.setTextColor(Color.WHITE)\r\n    doneText.gravity = Gravity.CENTER\r\n    doneText.setPadding(0, dp(12), 0, 0)\r\n    content.addView(doneText)\r\n\r\n    root.addView(content)\r\n\r\n    cbs.onCountdownFinish()\r\n    const self = this\r\n    Handler(Looper.getMainLooper()).postDelayed(function(): void {\r\n      self.dismiss()\r\n    }, 1500)\r\n  }\r\n\r\n  private stopCountdown(): void {\r\n    if (this.handler != null) {\r\n      this.handler!!.removeCallbacksAndMessages(null)\r\n      this.handler = null\r\n    }\r\n  }\r\n\r\n  private buildParams(config: OverlayConfig): WindowManagerLayoutParams | null {\r\n    try {\r\n      const ctx = UTSAndroid.getAppContext()\r\n      if (ctx == null) return null\r\n      const displayMetrics = ctx.getResources().getDisplayMetrics()\r\n\r\n      const w = config.level == 'gentle' ? (displayMetrics.widthPixels * 0.7).toInt() : WindowManagerLayoutParams.MATCH_PARENT\r\n      const h = WindowManagerLayoutParams.WRAP_CONTENT\r\n      const flags = WindowManagerLayoutParams.FLAG_NOT_FOCUSABLE | WindowManagerLayoutParams.FLAG_NOT_TOUCH_MODAL | WindowManagerLayoutParams.FLAG_LAYOUT_NO_LIMITS\r\n\r\n      const params = WindowManagerLayoutParams(w, h, WindowManagerLayoutParams.TYPE_APPLICATION_OVERLAY, flags, PixelFormat.TRANSLUCENT)\r\n      params.gravity = Gravity.CENTER\r\n      return params\r\n    } catch (_) {\r\n      return null\r\n    }\r\n  }\r\n\r\n  private dp(value: number): Int {\r\n    try {\r\n      const ctx = UTSAndroid.getAppContext()\r\n      if (ctx != null) {\r\n        const density = ctx.getResources().getDisplayMetrics().density\r\n        return (value * density + 0.5).toInt()\r\n      }\r\n    } catch (_) {}\r\n    return value.toInt()\r\n  }\r\n}\r\n","import MediaPlayer from 'android.media.MediaPlayer'\r\nimport Handler from 'android.os.Handler'\r\nimport Looper from 'android.os.Looper'\r\n\r\nexport type AudioPlayerCallbacks = {\r\n  onCompletion: () => void\r\n  onError: (error: string) => void\r\n  onProgress: (currentMs: number, totalMs: number) => void\r\n}\r\n\r\nlet player: NativeAudioPlayer | null = null\r\n\r\nexport function play(filePath: string, callbacks: AudioPlayerCallbacks): void {\r\n  ensurePlayer()\r\n  player!!.playFile(filePath, callbacks)\r\n}\r\n\r\nexport function playUrl(url: string, callbacks: AudioPlayerCallbacks): void {\r\n  ensurePlayer()\r\n  player!!.playUrl(url, callbacks)\r\n}\r\n\r\nexport function pause(): void {\r\n  if (player != null) player.pause()\r\n}\r\n\r\nexport function resume(): void {\r\n  if (player != null) player.resume()\r\n}\r\n\r\nexport function stop(): void {\r\n  if (player != null) {\r\n    player.stop()\r\n    player = null\r\n  }\r\n}\r\n\r\nexport function setVolume(vol: number): void {\r\n  if (player != null) player.setVolume(vol)\r\n}\r\n\r\nexport function isPlaying(): boolean {\r\n  return player != null && player!!.isPlaying()\r\n}\r\n\r\nfunction ensurePlayer(): void {\r\n  if (player == null) {\r\n    player = NativeAudioPlayer()\r\n  }\r\n}\r\n\r\nclass NativeAudioPlayer {\r\n  private mp: MediaPlayer | null = null\r\n  private handler: Handler | null = null\r\n  private callbacks: AudioPlayerCallbacks | null = null\r\n\r\n  playFile(filePath: string, cbs: AudioPlayerCallbacks): void {\r\n    this.stop()\r\n    this.callbacks = cbs\r\n    this.mp = MediaPlayer()\r\n    try {\r\n      this.mp!!.setDataSource(filePath)\r\n      this.setup()\r\n      this.mp!!.prepare()\r\n      this.mp!!.start()\r\n      this.startProgress()\r\n    } catch (e) {\r\n      cbs.onError('playFile failed')\r\n    }\r\n  }\r\n\r\n  playUrl(url: string, cbs: AudioPlayerCallbacks): void {\r\n    this.stop()\r\n    this.callbacks = cbs\r\n    this.mp = MediaPlayer()\r\n    try {\r\n      this.mp!!.setDataSource(url)\r\n      this.setup()\r\n      this.mp!!.prepareAsync()\r\n      this.mp!!.setOnPreparedListener(function(mp: MediaPlayer): void {\r\n        mp.start()\r\n      })\r\n      this.startProgress()\r\n    } catch (e) {\r\n      cbs.onError('playUrl failed')\r\n    }\r\n  }\r\n\r\n  pause(): void {\r\n    if (this.mp != null && this.mp!!.isPlaying()) {\r\n      this.mp!!.pause()\r\n    }\r\n  }\r\n\r\n  resume(): void {\r\n    if (this.mp != null && !this.mp!!.isPlaying()) {\r\n      this.mp!!.start()\r\n    }\r\n  }\r\n\r\n  stop(): void {\r\n    this.stopProgress()\r\n    if (this.mp != null) {\r\n      try {\r\n        this.mp!!.stop()\r\n        this.mp!!.release()\r\n      } catch (_) {}\r\n      this.mp = null\r\n    }\r\n    this.callbacks = null\r\n  }\r\n\r\n  setVolume(vol: number): void {\r\n    if (this.mp != null) {\r\n      const v: Float = vol.toFloat()\r\n      this.mp!!.setVolume(v, v)\r\n    }\r\n  }\r\n\r\n  isPlaying(): boolean {\r\n    return this.mp != null && this.mp!!.isPlaying()\r\n  }\r\n\r\n  private setup(): void {\r\n    if (this.mp != null && this.callbacks != null) {\r\n      const cbs = this.callbacks\r\n      this.mp!!.setOnCompletionListener(function(mp: MediaPlayer): void {\r\n        cbs.onCompletion()\r\n      })\r\n      this.mp!!.setOnErrorListener(function(mp: MediaPlayer, what: number, extra: number): boolean {\r\n        cbs.onError('error: ' + what + '/' + extra)\r\n        return true\r\n      })\r\n    }\r\n  }\r\n\r\n  private startProgress(): void {\r\n    this.stopProgress()\r\n    this.handler = Handler(Looper.getMainLooper())\r\n    const self = this\r\n    this.handler!!.postDelayed(function(): void {\r\n      const mp = self.mp\r\n      const cbs = self.callbacks\r\n      if (mp != null && mp.isPlaying() && cbs != null) {\r\n        cbs.onProgress(mp.getCurrentPosition(), mp.getDuration())\r\n        self.startProgress()\r\n      }\r\n    }, (100).toLong())\r\n  }\r\n\r\n  private stopProgress(): void {\r\n    if (this.handler != null) {\r\n      this.handler!!.removeCallbacksAndMessages(null)\r\n      this.handler = null\r\n    }\r\n  }\r\n}\r\n","import TextToSpeech from 'android.speech.tts.TextToSpeech'\nimport Locale from 'java.util.Locale'\nimport Bundle from 'android.os.Bundle'\n\nlet ttsInstance: TextToSpeech | null = null\nlet ttsReady: boolean = false\nlet pendingText: string = ''\nlet pendingVolume: number = 1.0\n\nfunction clampVolume(volume: number): number {\n  if (volume < 0) return 0\n  if (volume > 1) return 1\n  return volume\n}\n\nfunction makeVolumeParams(volume: number): Bundle {\n  const params = Bundle()\n  params.putFloat('volume', clampVolume(volume).toFloat())\n  return params\n}\n\nexport function speakSystemTts(text: string, volume: number = 1.0): void {\n  const v = clampVolume(volume)\n  if (ttsInstance != null && ttsReady) {\n    try {\n      ttsInstance!!.speak(text, TextToSpeech.QUEUE_FLUSH, makeVolumeParams(v), 'micro_habit_tts')\n    } catch (_) {\n      ttsInstance!!.speak(text, TextToSpeech.QUEUE_FLUSH, null, 'micro_habit_tts')\n    }\n  } else {\n    if (ttsInstance == null) {\n      initTts()\n    }\n    pendingText = text\n    pendingVolume = v\n  }\n}\n\nexport function isSystemTtsAvailable(): boolean {\n  return ttsReady\n}\n\nexport function stopSystemTts(): void {\n  if (ttsInstance != null) {\n    ttsInstance!!.stop()\n  }\n}\n\nexport function shutdownSystemTts(): void {\n  if (ttsInstance != null) {\n    ttsInstance!!.shutdown()\n    ttsInstance = null\n    ttsReady = false\n    pendingText = ''\n  }\n}\n\nfunction initTts(): void {\n  try {\n    const ctx = UTSAndroid.getAppContext()\n    if (ctx == null) return\n    ttsInstance = TextToSpeech(ctx, function(status: number): void {\n      if (status == TextToSpeech.SUCCESS) {\n        const result = ttsInstance!!.setLanguage(Locale.CHINESE)\n        ttsReady = result != TextToSpeech.LANG_MISSING_DATA && result != TextToSpeech.LANG_NOT_SUPPORTED\n        if (ttsReady && pendingText.length > 0) {\n          try {\n            ttsInstance!!.speak(pendingText, TextToSpeech.QUEUE_FLUSH, makeVolumeParams(pendingVolume), 'micro_habit_tts')\n          } catch (_) {\n            ttsInstance!!.speak(pendingText, TextToSpeech.QUEUE_FLUSH, null, 'micro_habit_tts')\n          }\n          pendingText = ''\n        }\n      }\n    })\n  } catch (_) {}\n}\n","// 使用情况监听：桥接层\n// 对外暴露跳转设置等便利函数\n\nimport Context from 'android.content.Context'\nimport Intent from 'android.content.Intent'\nimport Settings from 'android.provider.Settings'\n\nexport function openUsageAccessSettings(): void {\n  try {\n    const ctx = UTSAndroid.getAppContext()\n    if (ctx == null) return\n    const intent = Intent(Settings.ACTION_USAGE_ACCESS_SETTINGS)\n    intent.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK)\n    ctx.startActivity(intent)\n  } catch (e) {\n    __f__('warn','at uni_modules/uts-usage-stats/utssdk/app-android/UsageStatsBridge.uts:16','[UsageStats] openUsageAccessSettings 失败: ' + JSON.stringify(e))\n  }\n}\n","<script setup lang=\"uts\">\nimport { sqliteStore } from './uni_modules/uts-sqlite-store/utssdk/app-android/index'\nimport { onCreate, onUpgrade, getDbVersion } from './database/DatabaseHelper'\nimport { saveTodaySummary, getHomepageData } from './services/ScoreCalculator'\nimport { shouldTrigger, onActionResolved, onUserAccepted, TriggerDecision, TriggerContext, forceIdle } from './services/TriggerEngine'\nimport { insertActionLog, getRecentLogs, getTotalCompletedDurationSec, countSkippedToday } from './database/ActionLogDao'\nimport { setSnapshotTotal } from './database/AppUsageDao'\nimport { getInt, getBool, getSetting } from './database/SettingsDao'\nimport { insertRule as insertTriggerRule } from './database/EffectiveRuleDao'\nimport { PersistedEffectiveRule } from './models/PersistedEffectiveRule'\nimport { getActionById } from './constants/Actions'\nimport { getRandomEncourage } from './constants/EncourageTexts'\nimport { shortVibrate } from './utils/VibrateUtils'\nimport { speakAdhoc, speakFixedGuide, preGenerateAll, prewarmSystemTts } from './services/TtsService'\nimport {\n  startUsageMonitor,\n  stopUsageMonitor,\n  isUsagePermissionGranted,\n  setTriggerEnabled as setUsageTriggerEnabled,\n  queryUsageStatsOnce,\n  AppForegroundInfo,\n  UsageMonitorCallbacks\n} from './uni_modules/uts-usage-stats/utssdk/app-android/index'\nimport { showOverlay, dismissOverlay, OverlayConfig, OverlayCallbacks } from './uni_modules/uts-floating-overlay/utssdk/app-android/index'\nimport { setActionIdForNextPage, setAdhocForNextPage } from './utils/NavigationHelper'\nimport {\n  evaluatePre,\n  evaluatePost,\n  setPreContext,\n  setPostContext,\n  clearPreContext,\n  clearPostContext,\n  PreTriggerResult,\n  PostActionResult\n} from './services/LlmTriggerFlow'\nimport { PreTriggerContext, PostActionContext, getFallbackAdhoc, MatchedRuleInfo, PostContextRuleItem } from './constants/LlmPrompts'\nimport { EffectiveTriggerRule } from './models/EffectiveTriggerRule'\nimport { getAppHistory } from './services/AppHistoryService'\nimport { getUserProfile } from './services/UserProfileService'\nimport { getActiveRuleList } from './services/EffectiveRuleService'\nimport { ensureCategory as ensureAppCategory, batchClassifyTodayNewApps } from './services/AppCategoryService'\nimport { currentHour, today } from './utils/TimeUtils'\nimport * as AchievementService from './services/AchievementService'\n\nlet firstBackTime = 0\nlet triggeredActionId = ''\nlet pendingDecisionActionId = ''\nlet pendingDecisionLevel = ''\nlet pendingDecisionTts = ''\nlet pendingDecisionDuration = 0\nlet pendingAdhocText = ''\nlet pendingActionId = ''\n// 幂等守卫：$on 重复注册导致同一 actionId 被处理多次\nlet pendingActionIds: Map<string, boolean> = new Map<string, boolean>()\n// per-package 触发防抖：5min tick 命中同一包时按 (pkg, time) 二次去重，避免连续弹窗打架\nconst TRIGGER_COOL_DOWN_MS_PER_PKG: number = 30 * 60 * 1000\nlet lastTriggerPerPkg: Map<string, number> = new Map<string, number>()\nlet pendingActionName = ''\nlet pendingActionCategory = ''\n\nfunction safeNowHour(): number {\n  try { return currentHour() } catch (_) { return 12 }\n}\n\nfunction safeToday(): string {\n  try { return today() } catch (_) { return '' }\n}\n\nfunction buildPreContext(info: AppForegroundInfo, decision: TriggerDecision): PreTriggerContext {\n  const recent = getRecentLogs(5)\n  const names: string[] = []\n  for (let i = 0; i < recent.length; i++) {\n    const r = recent[i]\n    const a = getActionById(r.action_id)\n    if (a != null) names.push(a.name)\n    else names.push(r.action_id)\n  }\n  const homeData = getHomepageData(safeToday())\n  const guardMin = Math.floor(getTotalCompletedDurationSec(safeToday()) / 60)\n  const todaySkipCount = countSkippedToday()\n  const appHistory = getAppHistory(info.packageName, 7)\n  const profile = getUserProfile()\n  const matchedRule: MatchedRuleInfo = {\n    actionId: decision.actionId,\n    source: decision.matchedRuleSource,\n    timeWindow: null,\n    thresholdMinutes: decision.durationMs > 0 ? Math.round(decision.durationMs / 60000) : 0,\n    triggerLevel: decision.triggerLevel\n  }\n  return {\n    appLabel: info.packageName,\n    appPackage: info.packageName,\n    appCategory: appHistory != null ? appHistory.appCategory : 'other',\n    continuousMinutes: Math.floor(info.continuousMs / 60000),\n    hour: safeNowHour(),\n    todayCompletedCount: homeData.todayCompletedCount,\n    guardMinutes: guardMin,\n    todaySkipCount: todaySkipCount,\n    recentActions: names,\n    appHistory: appHistory != null ? {\n      totalTriggers: appHistory.totalTriggers,\n      totalCompletes: appHistory.totalCompletes,\n      totalSkips: appHistory.totalSkips,\n      acceptRate: appHistory.acceptRate,\n      typicalContinuousMin: appHistory.typicalContinuousMin,\n      lastTriggerAt: appHistory.lastTriggerAt\n    } : null,\n    matchedRule: matchedRule,\n    userPreference: {\n      healthFocus: profile.healthFocus,\n      bodyLimit: profile.bodyLimit\n    }\n  }\n}\n\nfunction buildPostContext(actionName: string, actionCategory: string, durationMs: number, appPackage: string): PostActionContext {\n  const recent = getRecentLogs(5)\n  const names: string[] = []\n  for (let i = 0; i < recent.length; i++) {\n    const r = recent[i]\n    const a = getActionById(r.action_id)\n    if (a != null) names.push(a.name)\n    else names.push(r.action_id)\n  }\n  const homeData = getHomepageData(safeToday())\n  const guardMin = Math.floor(getTotalCompletedDurationSec(safeToday()) / 60)\n  const todaySkipCount = countSkippedToday()\n  const profile = getUserProfile()\n  const appHistory = getAppHistory(appPackage, 7)\n  const rules = getActiveRuleList()\n  const currentRules: PostContextRuleItem[] = []\n  for (let i = 0; i < rules.length; i++) {\n    const r = rules[i]\n    const item: PostContextRuleItem = {\n      id: r.id,\n      actionId: r.actionId,\n      appPackages: r.appPackages,\n      timeWindow: r.timeWindow,\n      thresholdMinutes: r.timeThresholdMinutes,\n      triggerLevel: r.triggerLevel,\n      source: r.source,\n      createdAt: r.createdAt\n    }\n    currentRules.push(item)\n  }\n  return {\n    actionId: pendingActionId,\n    actionName: actionName,\n    actionCategory: actionCategory,\n    durationMs: durationMs,\n    originalContext: pendingAdhocText,\n    todayCompletedCount: homeData.todayCompletedCount,\n    guardMinutes: guardMin,\n    todaySkipCount: todaySkipCount,\n    recentActions: names,\n    appHistory: appHistory != null ? {\n      packageName: appHistory.packageName,\n      totalTriggers: appHistory.totalTriggers,\n      totalCompletes: appHistory.totalCompletes,\n      totalSkips: appHistory.totalSkips,\n      acceptRate: appHistory.acceptRate,\n      typicalContinuousMin: appHistory.typicalContinuousMin,\n      lastWeekTrend: appHistory.lastWeekTrend\n    } : null,\n    currentRules: currentRules,\n    userPreference: {\n      healthFocus: profile.healthFocus,\n      bodyLimit: profile.bodyLimit\n    },\n    lastWeekSameTime: null\n  }\n}\n\n// 触发成就检查：新解锁通过 uni.$emit 推送给主页\nfunction checkAchievementsAndNotify(): void {\n  try {\n    const newUnlocked = AchievementService.checkAndUnlock()\n    if (newUnlocked.length > 0) {\n      try {\n        uni.$emit('pendingAchievementUnlock', { ids: newUnlocked })\n      } catch (e) {\n        console.warn('[App.uvue] emit pendingAchievementUnlock 失败 type=' + (typeof e) + ' msg=' + (e != null ? ('' + e) : 'null'))\n      }\n    }\n  } catch (e) {\n    console.warn('[App.uvue] checkAchievementsAndNotify 异常 type=' + (typeof e) + ' msg=' + (e != null ? ('' + e) : 'null'))\n  }\n}\n\nfunction emitShowRuleDialog(payload: UTSJSONObject): void {\n  try {\n    uni.$emit('showTriggerRuleDialog', payload)\n  } catch (e) {\n    console.warn('[App.uvue] emitShowRuleDialog 失败: ' + JSON.stringify(e))\n  }\n}\n\nfunction onActionResolvedLLM(actionId: string, actionName: string, actionCategory: string, durationMs: number, appPackage: string): void {\n  // 幂等守卫：uni.$on 重复注册导致同一 actionId 被处理多次\n  if (pendingActionIds.has(actionId)) {\n    console.log('[App.uvue] onActionResolvedLLM skip duplicate: ' + actionId)\n    return\n  }\n  pendingActionIds.set(actionId, true)\n  setTimeout((): void => {\n    pendingActionIds.delete(actionId)\n  }, 5000)\n  const llmEnabled = getBool('llm_trigger_enabled', true)\n  if (!llmEnabled) {\n    clearPreContext()\n    clearPostContext()\n    return\n  }\n  pendingActionId = actionId\n  pendingActionName = actionName\n  pendingActionCategory = actionCategory\n  const postCtx = buildPostContext(actionName, actionCategory, durationMs, appPackage)\n  setPostContext(postCtx)\n  // 实际的 LLM 评估由 4 个 callback 各自触发（onSelfReported/onBusyRemindLater/onSkipDuringExec/onCountdownFinish）\n  // 此处仅完成上下文准备；评估入口在 callback 内 evaluatePost(...)\n}\n\n// 弹窗：LLM 评估结果出来后，让用户决定是否接受规则\nfunction tryShowLlmRuleDialog(postResult: PostActionResult, actionId: string): void {\n  try {\n    if (postResult.decision == 'no_change' || postResult.suggestedRule == null) return\n    const askEach = getBool('llm_trigger_ask_each_time', true)\n    if (askEach) {\n      const rule = postResult.suggestedRule\n      const payload: UTSJSONObject = {\n        rule: rule,\n        reasoning: postResult.reasoning,\n        confidence: postResult.confidence,\n        historyId: postResult.historyId,\n        decision: postResult.decision,\n        targetRuleId: postResult.historyId\n      }\n      emitShowRuleDialog(payload)\n    } else {\n      try {\n        if (actionId.length > 0) {\n          const nowSec = Math.floor(Date.now() / 1000)\n          const rule = postResult.suggestedRule\n          let pkgList: string[] = []\n          if (rule.screenConditions != null) {\n            pkgList = rule.screenConditions.appPackages\n          }\n          const ruleRow: PersistedEffectiveRule = {\n            id: 0,\n            actionId: rule.actionId,\n            appPackages: pkgList,\n            timeWindow: rule.timeWindow,\n            timeThresholdMinutes: rule.timeThresholdMinutes,\n            triggerLevel: 'gentle',\n            categoryFilter: null,\n            source: 'llm',\n            sourceHistoryId: postResult.historyId,\n            expiresAt: null,\n            enabled: true,\n            priority: 5,\n            createdAt: nowSec,\n            updatedAt: nowSec\n          }\n          insertTriggerRule(ruleRow)\n        }\n      } catch (e2) {\n        console.warn('[App.uvue] 静默保存 suggestedRule 失败: ' + JSON.stringify(e2))\n      }\n    }\n  } catch (e) {\n    console.warn('[App.uvue] tryShowLlmRuleDialog 异常: ' + JSON.stringify(e))\n  }\n}\n\nfunction showOverlayWithAdhoc(decision: TriggerDecision, adhocText: string, fallback: boolean): void {\n  triggeredActionId = decision.actionId\n  pendingDecisionActionId = decision.actionId\n  pendingDecisionLevel = decision.triggerLevel\n  pendingDecisionTts = decision.ttsText\n  pendingDecisionDuration = decision.durationMs\n  pendingAdhocText = adhocText\n  // 首次见到该包名时入册 app_tags\n  try { ensureAppCategory(decision.actionId == null ? '' : decision.actionId, decision.actionName) } catch (_) {}\n  const actionForEncourage = getActionById(decision.actionId)\n  const encourageText = actionForEncourage != null ? getRandomEncourage(actionForEncourage.category) : '又完成一次！'\n  const cfg: OverlayConfig = {\n    level: decision.triggerLevel,\n    actionName: decision.actionName,\n    ttsText: adhocText,\n    durationMs: decision.durationMs,\n    lottieAssetPath: null,\n    encourageText: encourageText\n  }\n  const cbs: OverlayCallbacks = {\n    onAgree: (): void => {\n      onUserAccepted()\n      dismissOverlay()\n      const aid = triggeredActionId\n      setActionIdForNextPage(aid)\n      uni.navigateTo({\n        url: '/pages/action/execute?actionId=' + aid\n      })\n    },\n    onSelfReported: (): void => {\n      const action = getActionById(pendingDecisionActionId)\n      if (action != null) {\n        insertActionLog({\n          id: 0,\n          action_id: action.id,\n          action_type: action.category,\n          result: 'self_reported',\n          skip_reason: null,\n          trigger_type: 'app_duration',\n          trigger_level: pendingDecisionLevel,\n          duration_ms: 0,\n          target_ms: action.defaultDurationMs,\n          triggered_at: Math.floor(Date.now() / 1000),\n          completed_at: Math.floor(Date.now() / 1000),\n          created_at: Math.floor(Date.now() / 1000)\n        })\n        checkAchievementsAndNotify()\n      }\n      onActionResolved()\n      // onSelfReported 路径无源包名上下文（前台切换链路未传包名），与其它 callback 保持一致传 ''\n      const pkgName = ''\n      onActionResolvedLLM(pendingDecisionActionId, action != null ? action.name : '', action != null ? action.category : '', action != null ? action.defaultDurationMs : 0, pkgName)\n      // LLM post 评估（异步）\n      if (getBool('llm_trigger_enabled', true)) {\n        try {\n          evaluatePost(\n            pendingDecisionActionId,\n            action != null ? action.name : '',\n            action != null ? action.category : '',\n            action != null ? action.defaultDurationMs : 0,\n            (postResult: PostActionResult): void => {\n              try { tryShowLlmRuleDialog(postResult, pendingDecisionActionId) } catch (e) {\n                console.warn('[App.uvue] onSelfReported post-result 异常: ' + JSON.stringify(e))\n              }\n            },\n            (): void => {\n              console.warn('[App.uvue] onSelfReported evaluatePost fail')\n            }\n          )\n        } catch (e) {\n          console.warn('[App.uvue] onSelfReported evaluatePost 异常: ' + JSON.stringify(e))\n        }\n      }\n      dismissOverlay()\n    },\n    onBusyRemindLater: (): void => {\n      const action = getActionById(pendingDecisionActionId)\n      if (action != null) {\n        insertActionLog({\n          id: 0,\n          action_id: action.id,\n          action_type: action.category,\n          result: 'skipped',\n          skip_reason: 'busy',\n          trigger_type: 'app_duration',\n          trigger_level: pendingDecisionLevel,\n          duration_ms: 0,\n          target_ms: action.defaultDurationMs,\n          triggered_at: Math.floor(Date.now() / 1000),\n          completed_at: Math.floor(Date.now() / 1000),\n          created_at: Math.floor(Date.now() / 1000)\n        })\n      }\n      onActionResolved()\n      onActionResolvedLLM(pendingDecisionActionId, action != null ? action.name : '', action != null ? action.category : '', 0, '')\n      // LLM post 评估（异步）\n      if (getBool('llm_trigger_enabled', true)) {\n        try {\n          evaluatePost(\n            pendingDecisionActionId,\n            action != null ? action.name : '',\n            action != null ? action.category : '',\n            0,\n            (postResult: PostActionResult): void => {\n              try { tryShowLlmRuleDialog(postResult, pendingDecisionActionId) } catch (e) {\n                console.warn('[App.uvue] onBusyRemindLater post-result 异常: ' + JSON.stringify(e))\n              }\n            },\n            (): void => {\n              console.warn('[App.uvue] onBusyRemindLater evaluatePost fail')\n            }\n          )\n        } catch (e) {\n          console.warn('[App.uvue] onBusyRemindLater evaluatePost 异常: ' + JSON.stringify(e))\n        }\n      }\n      dismissOverlay()\n    },\n    onSkipDuringExec: (): void => {\n      onActionResolved()\n      onActionResolvedLLM(pendingDecisionActionId, '', '', 0, '')\n      // LLM post 评估（异步）\n      if (getBool('llm_trigger_enabled', true)) {\n        try {\n          evaluatePost(\n            pendingDecisionActionId,\n            '',\n            '',\n            0,\n            (postResult: PostActionResult): void => {\n              try { tryShowLlmRuleDialog(postResult, pendingDecisionActionId) } catch (e) {\n                console.warn('[App.uvue] onSkipDuringExec post-result 异常: ' + JSON.stringify(e))\n              }\n            },\n            (): void => {\n              console.warn('[App.uvue] onSkipDuringExec evaluatePost fail')\n            }\n          )\n        } catch (e) {\n          console.warn('[App.uvue] onSkipDuringExec evaluatePost 异常: ' + JSON.stringify(e))\n        }\n      }\n      dismissOverlay()\n    },\n    onCountdownTick: (_remaining: number): void => {},\n    onCountdownFinish: (): void => {\n      shortVibrate(2)\n      const encourageTextFinal = encourageText\n      try { speakFixedGuide(encourageTextFinal) } catch (_) {}\n      const action = getActionById(pendingDecisionActionId)\n      if (action != null) {\n        insertActionLog({\n          id: 0,\n          action_id: action.id,\n          action_type: action.category,\n          result: 'completed',\n          skip_reason: null,\n          trigger_type: 'app_duration',\n          trigger_level: pendingDecisionLevel,\n          duration_ms: action.defaultDurationMs,\n          target_ms: action.defaultDurationMs,\n          triggered_at: Math.floor(Date.now() / 1000),\n          completed_at: Math.floor(Date.now() / 1000),\n          created_at: Math.floor(Date.now() / 1000)\n        })\n        checkAchievementsAndNotify()\n      }\n      onActionResolved()\n      onActionResolvedLLM(pendingDecisionActionId, action != null ? action.name : '', action != null ? action.category : '', action != null ? action.defaultDurationMs : 0, '')\n      // LLM post 评估（异步）\n      if (getBool('llm_trigger_enabled', true)) {\n        try {\n          evaluatePost(\n            pendingDecisionActionId,\n            action != null ? action.name : '',\n            action != null ? action.category : '',\n            action != null ? action.defaultDurationMs : 0,\n            (postResult: PostActionResult): void => {\n              try { tryShowLlmRuleDialog(postResult, pendingDecisionActionId) } catch (e) {\n                console.warn('[App.uvue] onCountdownFinish post-result 异常: ' + JSON.stringify(e))\n              }\n            },\n            (): void => {\n              console.warn('[App.uvue] onCountdownFinish evaluatePost fail')\n            }\n          )\n        } catch (e) {\n          console.warn('[App.uvue] onCountdownFinish evaluatePost 异常: ' + JSON.stringify(e))\n        }\n      }\n    },\n    onPartialCompletion: (_completed: number, _total: number): void => {}\n  }\n  try {\n    showOverlay(cfg, cbs)\n  } catch (e) {\n    console.warn('[App.uvue] showOverlay 失败: ' + JSON.stringify(e))\n  }\n  // 悬浮窗弹出时立即播 TTS：把 actionName 与 adhocText 拼成单条文本\n  // 避免连续两次 speakAdhoc 触发 SystemTts QUEUE_FLUSH 互吞\n  try {\n    if (getBool('tts_enabled', true)) {\n      const actionNameStr = decision.actionName ?? ''\n      const merged = actionNameStr + (adhocText.length > 0 ? ('，' + adhocText) : '')\n      if (merged.length > 0) speakAdhoc(merged)\n    }\n  } catch (e) {\n    console.warn('[App.uvue] 播 TTS 开场白失败: ' + JSON.stringify(e))\n  }\n}\n\nonLaunch(() => {\n  try {\n    uni.$on('llmActionCompleted', (data: any): void => {\n      try {\n        if (data == null) return\n        const obj = data as UTSJSONObject\n        if (obj == null) return\n        const actionId = obj['actionId'] as string\n        const actionName = obj['actionName'] as string\n        const actionCategory = obj['actionCategory'] as string\n        const durationMs = (obj['durationMs'] as number).toInt()\n        const appPackage = obj['appPackage'] != null ? (obj['appPackage'] as string) : ''\n        if (actionId == null || actionId.length < 1) return\n        onActionResolvedLLM(actionId, actionName, actionCategory, durationMs, appPackage)\n      } catch (e) {\n        console.warn('[App.uvue] llmActionCompleted 处理异常: ' + JSON.stringify(e))\n      }\n    })\n    uni.$on('manualTriggerCheck', (_data: any): void => {\n      try {\n        console.log('[manualTrigger] 开始检查')\n        const triggerVal = getBool('trigger_enabled', true)\n        console.log('[manualTrigger] trigger_enabled=' + triggerVal)\n        if (!triggerVal) {\n          console.log('[manualTrigger] 触发已关闭')\n          uni.showToast({ title: '触发已关闭', icon: 'none', position: 'bottom' })\n          return\n        }\n        if (!isUsagePermissionGranted()) {\n          console.log('[manualTrigger] 缺少使用情况权限')\n          uni.showToast({ title: '缺少使用情况权限', icon: 'none', position: 'bottom' })\n          return\n        }\n        const thresholdMs = getInt('app_duration_threshold', 60) * 60000\n        console.log('[manualTrigger] 阈值(ms): ' + thresholdMs)\n        const nowMs = Date.now()\n        const startMs = nowMs - 24 * 60 * 60 * 1000\n        const stats = queryUsageStatsOnce(startMs, nowMs)\n        console.log('[manualTrigger] queryUsageStatsOnce 返回 ' + stats.length + ' 条')\n        let triggered = false\n        for (let i = 0; i < stats.length; i++) {\n          const s = stats[i]\n          if (s == null) continue\n          const totalMs = s.totalTimeInForeground\n          if (totalMs < thresholdMs) continue\n          console.log('[manualTrigger] 超阈值 App: ' + s.packageName + ' totalMs=' + totalMs)\n          const ctx: TriggerContext = {\n            appPackage: s.packageName,\n            appLabel: s.packageName,\n            continuousMinutes: Math.floor(totalMs / 60000),\n            triggerType: 'app_duration'\n          }\n          forceIdle()\n          console.log('[manualTrigger] forceIdle done, calling shouldTrigger')\n          let decision: TriggerDecision | null = null\n          try {\n            decision = shouldTrigger(ctx)\n          } catch (e2) {\n            const errMsg = e2 != null ? ('' + e2) : 'null'\n            console.warn('[manualTrigger] shouldTrigger THREW: ' + errMsg)\n            continue\n          }\n          if (decision == null) {\n            console.log('[manualTrigger] shouldTrigger 返回 null, 跳过: ' + s.packageName)\n            continue\n          }\n          console.log('[manualTrigger] shouldTrigger 命中 actionId=' + decision.actionId + ' level=' + decision.triggerLevel)\n          const info: AppForegroundInfo = {\n            packageName: s.packageName,\n            startTime: nowMs,\n            continuousMs: totalMs\n          }\n          const llmEnabled = getBool('llm_trigger_enabled', true)\n          if (!llmEnabled) {\n            console.log('[manualTrigger] LLM 关闭，跳转健康卡片页')\n            setActionIdForNextPage(decision.actionId)\n            setAdhocForNextPage(decision.ttsText)\n            uni.navigateTo({ url: '/pages/action/execute?actionId=' + decision.actionId })\n          } else {\n            console.log('[manualTrigger] LLM 开启，走 evaluatePre + 跳转健康卡片页')\n            let preCtx: PreTriggerContext | null = null\n            try { preCtx = buildPreContext(info, decision) } catch (e3) {\n              console.warn('[manualTrigger] buildPreContext 异常: ' + ('' + e3))\n            }\n            if (preCtx == null) {\n              console.warn('[manualTrigger] buildPreContext 返回 null，降级跳转')\n              setActionIdForNextPage(decision.actionId)\n              setAdhocForNextPage(getFallbackAdhoc())\n              uni.navigateTo({ url: '/pages/action/execute?actionId=' + decision.actionId })\n              triggered = true\n              break\n            }\n            try { setPreContext(preCtx) } catch (e4) {\n              console.warn('[manualTrigger] setPreContext 异常: ' + ('' + e4))\n            }\n            try {\n              evaluatePre(\n                (preResult: PreTriggerResult): void => {\n                  console.log('[manualTrigger] evaluatePre 成功 adhocText=' + preResult.adhocText)\n                  setActionIdForNextPage(decision.actionId)\n                  setAdhocForNextPage(preResult.adhocText)\n                  uni.navigateTo({ url: '/pages/action/execute?actionId=' + decision.actionId })\n                  clearPreContext()\n                },\n                (): void => {\n                  console.log('[manualTrigger] evaluatePre 失败，降级跳转')\n                  setActionIdForNextPage(decision.actionId)\n                  setAdhocForNextPage(getFallbackAdhoc())\n                  uni.navigateTo({ url: '/pages/action/execute?actionId=' + decision.actionId })\n                  clearPreContext()\n                }\n              )\n            } catch (e) {\n              console.warn('[manualTrigger] evaluatePre 异常: ' + JSON.stringify(e))\n              setActionIdForNextPage(decision.actionId)\n              setAdhocForNextPage(getFallbackAdhoc())\n              uni.navigateTo({ url: '/pages/action/execute?actionId=' + decision.actionId })\n              clearPreContext()\n            }\n          }\n          triggered = true\n          break\n        }\n        if (!triggered) {\n          console.log('[manualTrigger] 无 App 超过阈值')\n          uni.showToast({ title: '当前无 App 超过阈值，无需触发', icon: 'none', position: 'bottom' })\n        }\n      } catch (e) {\n        const errMsg = e != null ? ('' + e) : 'null'\n        console.warn('[manualTrigger] 异常: ' + errMsg)\n        uni.showToast({ title: '检查失败', icon: 'none', position: 'bottom' })\n      }\n    })\n  } catch (e) {\n    console.warn('[App.uvue] $on 异常: ' + JSON.stringify(e))\n  }\n    try {\n      try {\n        sqliteStore.openDatabase('micro_habit_v2.db', getDbVersion(), (): void => onCreate(), (oldV: number, newV: number): void => {\n          try { onUpgrade(oldV, newV) } catch (e) { console.warn('[App.uvue] onUpgrade 异常: ' + JSON.stringify(e)) }\n        })\n      } catch (e) {\n        console.error('[App.uvue] sqliteStore.openDatabase 失败: ' + JSON.stringify(e))\n      }\n    // 启动期预热 TTS：延迟 3s 再开始（不阻塞启动），并立即触发 SystemTts 引擎初始化\n    try {\n      setTimeout((): void => {\n        try {\n          preGenerateAll()\n        } catch (e) {\n          const msg = e != null ? ('' + e) : 'null'\n          console.warn('[App.uvue] preGenerateAll 启动失败: ' + msg)\n        }\n      }, 3000)\n    } catch (e) {\n      const msg = e != null ? ('' + e) : 'null'\n      console.warn('[App.uvue] preGenerateAll setTimeout 失败: ' + msg)\n    }\n    try { prewarmSystemTts() } catch (e) {\n      const msg = e != null ? ('' + e) : 'null'\n      console.warn('[App.uvue] prewarmSystemTts 失败: ' + msg)\n    }\n    const callbacks: UsageMonitorCallbacks = {\n      onAppDurationTrigger: (info: AppForegroundInfo): void => {\n        try {\n          // per-package 触发防抖：5min tick 命中同一包时按 (pkg, time) 二次去重\n          const nowTs = Date.now()\n          const lastTs = lastTriggerPerPkg.get(info.packageName) ?? 0\n          if (nowTs - lastTs < TRIGGER_COOL_DOWN_MS_PER_PKG) {\n            console.log('[App.uvue] 跳过同包重复触发: ' + info.packageName)\n            return\n          }\n          lastTriggerPerPkg.set(info.packageName, nowTs)\n          // doPoll 已保证 info.continuousMs >= thresholdMs（聚合数据触发判定已通过）\n          // 首次见到该 App 立即入册 app_tags\n          try { ensureAppCategory(info.packageName, info.packageName) } catch (_) {}\n          let decision: TriggerDecision | null = null\n          try {\n            const ctx: TriggerContext = {\n              appPackage: info.packageName,\n              appLabel: info.packageName,\n              continuousMinutes: Math.floor(info.continuousMs / 60000),\n              triggerType: 'app_duration'\n            }\n            decision = shouldTrigger(ctx)\n          } catch (e) {\n            console.warn('[App.uvue] shouldTrigger 失败: ' + JSON.stringify(e))\n          }\n          if (decision == null) return\n\n          const llmEnabled = getBool('llm_trigger_enabled', true)\n          if (!llmEnabled) {\n            showOverlayWithAdhoc(decision, decision.ttsText, true)\n            return\n          }\n\n          const preCtx = buildPreContext(info, decision)\n          setPreContext(preCtx)\n          try {\n            evaluatePre(\n              (preResult: PreTriggerResult): void => {\n                try {\n                  showOverlayWithAdhoc(decision, preResult.adhocText, preResult.fallback)\n                } catch (e) {\n                  console.warn('[App.uvue] onReady 处理失败: ' + JSON.stringify(e))\n                }\n              },\n              (): void => {\n                try {\n                  showOverlayWithAdhoc(decision, getFallbackAdhoc(), true)\n                } catch (e) {\n                  console.warn('[App.uvue] onFail 降级失败: ' + JSON.stringify(e))\n                }\n                clearPreContext()\n              }\n            )\n          } catch (e) {\n            console.warn('[App.uvue] evaluatePre 异常: ' + JSON.stringify(e))\n            showOverlayWithAdhoc(decision, getFallbackAdhoc(), true)\n            clearPreContext()\n          }\n        } catch (e) {\n          console.warn('[App.uvue] onAppDurationTrigger 异常: ' + JSON.stringify(e))\n        }\n      },\n      onAppSwitch: (from: string, to: string): void => {\n        try { ensureAppCategory(to, to) } catch (_) {}\n      },\n      onUsageTick: (pkg: string, sec: number): void => {\n        try {\n          // 用绝对值覆盖语义（queryUsageStats 已是今日累计，不应再累加）\n          setSnapshotTotal(pkg, pkg, sec)\n        } catch (e) {\n          console.warn('[App.uvue] onUsageTick 写快照失败: ' + JSON.stringify(e))\n        }\n      },\n      onTimePeriodTrigger: (_name: string): void => {},\n      onDayRollover: (_old: string, _new: string): void => {\n        try { saveTodaySummary() } catch (_) {}\n      },\n      onPermissionMissing: (): void => {\n        console.warn('[App.uvue] PACKAGE_USAGE_STATS 权限缺失或被关闭')\n      }\n    }\n    if (isUsagePermissionGranted()) {\n      const thresholdMs = getInt('app_duration_threshold', 60) * 60000\n      const triggerEnabled = getBool('trigger_enabled', true)\n      // 5 分钟轮询：聚合数据查今日累计前台时长（INTERVAL_DAILY 一定有数据）\n      try {\n        startUsageMonitor(callbacks, thresholdMs, 5 * 60 * 1000, triggerEnabled)\n      } catch (e) {\n        console.error('[App.uvue] startUsageMonitor 失败: ' + JSON.stringify(e))\n      }\n    } else {\n      console.warn('[App.uvue] 启动时未授予使用情况权限，需在引导页授权')\n    }\n  } catch (e) {\n    console.error('App init error: ' + JSON.stringify(e))\n  }\n  console.log('App Launch')\n})\n\nonAppShow(() => {\n  try { saveTodaySummary() } catch (_) {}\n  try {\n    const h = safeNowHour()\n    if (h == 22) {\n      batchClassifyTodayNewApps(null)\n    }\n  } catch (_) {}\n  try { checkAchievementsAndNotify() } catch (_) {}\n  try {\n    const triggerOn = getBool('trigger_enabled', true)\n    setUsageTriggerEnabled(triggerOn)\n  } catch (_) {}\n  console.log('App Show')\n})\n\nonAppHide(() => {\n  console.log('App Hide')\n})\n\nonLastPageBackPress(() => {\n  if (firstBackTime == 0) {\n    uni.showToast({ title: '再按一次退出应用', position: 'bottom' })\n    firstBackTime = Date.now()\n    setTimeout((): void => {\n      firstBackTime = 0\n    }, 2000)\n  } else if (Date.now() - firstBackTime < 2000) {\n    firstBackTime = Date.now()\n    uni.exit()\n  }\n})\n\nonExit(() => {\n  try { stopUsageMonitor() } catch (_) {}\n  try { sqliteStore.close() } catch (_) {}\n  console.log('App Exit')\n})\n</script>\n\n<style>\n.uni-row { flex-direction: row; }\n.uni-column { flex-direction: column; }\n</style>\n","import { DailyData } from '../models/DailySummary'\r\nimport { WeeklyReportStats } from '../models/WeeklyReport'\r\nimport {\r\n  SYSTEM_PROMPT_EVALUATE, buildPreTriggerPrompt, buildPostActionPrompt,\r\n  SYSTEM_PROMPT_DAILY, buildDailySummaryPrompt,\r\n  SYSTEM_PROMPT_WEEKLY, buildWeeklyReportPrompt,\r\n  PreTriggerContext, PostActionContext\r\n} from '../constants/LlmPrompts'\r\nimport { save as saveTtsCache, getByHash as getTtsCacheByHash } from '../database/TtsCacheDao'\r\nimport { save as saveLlmCache, getByKey as getLlmCacheByKey } from '../database/LlmCacheDao'\r\n\r\nconst MINIMAX_BASE_URL = 'https://api.minimax.chat/v1'\r\nconst MINIMAX_CHAT_PATH = 'text/chatcompletion_v2'\r\nconst MINIMAX_CHAT_MODEL = 'MiniMax-M2.7'\r\nconst MINIMAX_API_KEY = 'sk-cp-Dd2_yFv0hINLsc2fnuWrrde0agYZQCzaRzW0DaK64CAl7Y-plAqRd7R2jSxQTSgSEWbl6teJc2oFL90HPMgyqLXel67OJhufLeLeVauln93DyXmA1277iQw'\r\n\r\nconst MINIMAX_TTS_URL = 'https://api.minimaxi.com/v1/t2a_v2'\r\nconst MINIMAX_TTS_MODEL = 'speech-02-hd'\r\nconst MINIMAX_TTS_VOICE_ID = 'male-qn-qingse'\r\n\r\nexport function callMinimaxChat(systemPrompt: string, userPrompt: string, maxTokens: number, onOK: (raw: string) => void, onFail: () => void): void {\r\n  if (MINIMAX_API_KEY === 'PLACEHOLDER_KEY') {\r\n    __f__('warn','at services/CloudService.uts:23','[CloudService] MiniMax API key 未配置，走降级路径')\r\n    onFail()\r\n    return\r\n  }\r\n\r\n  const reqBody = {\r\n    model: MINIMAX_CHAT_MODEL,\r\n    messages: [\r\n      { role: 'system', content: systemPrompt, name: 'MiniMax AI' },\r\n      { role: 'user', content: userPrompt, name: '用户' }\r\n    ],\r\n    temperature: 0.7,\r\n    max_completion_tokens: maxTokens,\r\n    reasoning_effort: 'low'\r\n  }\r\n\r\n  try {\r\n    uni.request({\r\n      url: MINIMAX_BASE_URL + '/' + MINIMAX_CHAT_PATH,\r\n      method: 'POST',\r\n      header: {\r\n        'Content-Type': 'application/json',\r\n        'Authorization': 'Bearer ' + MINIMAX_API_KEY\r\n      },\r\n      data: JSON.stringify(reqBody),\r\n      timeout: 30000,\r\n      success(res) {\r\n        try {\r\n          const data = res.data\r\n          const statusCode = (data != null) ? (data as UTSJSONObject).get('base_resp') : null\r\n          const finishReason = (data != null) ? extractFinishReason(data as UTSJSONObject) : ''\r\n          __f__('log','at services/CloudService.uts:54','[CloudService] callMinimaxChat response, finishReason=' + finishReason)\r\n          const content = extractChatContent(data != null ? data : '')\r\n          if (content.length > 0) {\r\n            __f__('log','at services/CloudService.uts:57','[CloudService] callMinimaxChat content OK, length=' + content.length)\r\n            onOK(content)\r\n          } else {\r\n            __f__('warn','at services/CloudService.uts:60','[CloudService] callMinimaxChat empty content, raw data=' + JSON.stringify(data))\r\n            onFail()\r\n          }\r\n        } catch (_) {\r\n          onFail()\r\n        }\r\n      },\r\n      fail(_err) {\r\n        __f__('warn','at services/CloudService.uts:68','[CloudService] callMinimaxChat network fail: ' + JSON.stringify(_err))\r\n        onFail()\r\n      }\r\n    })\r\n  } catch (_) {\r\n    onFail()\r\n  }\r\n}\r\n\r\nexport function callMinimaxTts(\r\n  text: string,\r\n  onOK: (audioUrl: string) => void,\r\n  onFail: (errMsg: string) => void\r\n): void {\r\n  if (MINIMAX_API_KEY === 'PLACEHOLDER_KEY' || MINIMAX_API_KEY.length < 8) {\r\n    onFail('MiniMax TTS key 未配置')\r\n    return\r\n  }\r\n  if (text.length < 1) {\r\n    onFail('TTS text 为空')\r\n    return\r\n  }\r\n  const reqBody = {\r\n    model: MINIMAX_TTS_MODEL,\r\n    text: text,\r\n    stream: false,\r\n    voice_setting: { voice_id: MINIMAX_TTS_VOICE_ID, speed: 1, vol: 1, pitch: 0 },\r\n    audio_setting: { sample_rate: 32000, bitrate: 128000, format: 'mp3', channel: 1 },\r\n    output_format: 'url'\r\n  }\r\n  try {\r\n    uni.request({\r\n      url: MINIMAX_TTS_URL,\r\n      method: 'POST',\r\n      header: {\r\n        'Content-Type': 'application/json',\r\n        'Authorization': 'Bearer ' + MINIMAX_API_KEY\r\n      },\r\n      data: JSON.stringify(reqBody),\r\n      timeout: 30000,\r\n      success(res) {\r\n        try {\r\n          const data = res.data\r\n          if (data == null) {\r\n            onFail('TTS 响应为空')\r\n            return\r\n          }\r\n          const obj = data as UTSJSONObject\r\n          const baseResp = obj.get('base_resp')\r\n          if (baseResp != null) {\r\n            const brObj = baseResp as UTSJSONObject\r\n            const sc = brObj.get('status_code')\r\n            if (sc != null && sc != 0) {\r\n              const sm = brObj.get('status_msg')\r\n              onFail('TTS 返回非 0 状态: ' + (sm != null ? ('' + sm) : ''))\r\n              return\r\n            }\r\n          }\r\n          const dataField = obj.get('data')\r\n          if (dataField == null) {\r\n            onFail('TTS 响应无 data 字段')\r\n            return\r\n          }\r\n          const dObj = dataField as UTSJSONObject\r\n          const audioField = dObj.get('audio')\r\n          if (audioField == null) {\r\n            onFail('TTS 响应无 data.audio 字段')\r\n            return\r\n          }\r\n          const audioUrl = '' + audioField\r\n          if (audioUrl.length < 8 || audioUrl.indexOf('http') < 0) {\r\n            onFail('TTS 响应 audio 非 url: ' + audioUrl.substring(0, 80))\r\n            return\r\n          }\r\n          __f__('log','at services/CloudService.uts:142','[CloudService] callMinimaxTts OK, textLen=' + text.length + ' urlLen=' + audioUrl.length)\r\n          onOK(audioUrl)\r\n        } catch (e) {\r\n          const msg = e != null ? ('' + e) : 'null'\r\n          onFail('TTS 响应解析异常: ' + msg)\r\n        }\r\n      },\r\n      fail(_err) {\r\n        const msg = _err != null ? ('' + _err) : 'null'\r\n        __f__('warn','at services/CloudService.uts:151','[CloudService] callMinimaxTts network fail: ' + msg)\r\n        onFail('TTS 网络失败: ' + msg)\r\n      }\r\n    })\r\n  } catch (e) {\r\n    const msg = e != null ? ('' + e) : 'null'\r\n    onFail('TTS 请求构造异常: ' + msg)\r\n  }\r\n}\r\n\r\nexport function downloadTtsAudio(\r\n  url: string,\r\n  cacheKey: string,\r\n  onOK: (localPath: string) => void,\r\n  onFail: (errMsg: string) => void\r\n): void {\r\n  if (url.length < 8) {\r\n    onFail('downloadTtsAudio url 为空')\r\n    return\r\n  }\r\n  if (cacheKey.length < 1) {\r\n    onFail('downloadTtsAudio cacheKey 为空')\r\n    return\r\n  }\r\n  try {\r\n    uni.request({\r\n      url: url,\r\n      method: 'GET',\r\n      responseType: 'arraybuffer',\r\n      timeout: 60000,\r\n      success(res) {\r\n        try {\r\n          const ab = res.data as ArrayBuffer\r\n          if (ab == null) {\r\n            onFail('下载响应无 ArrayBuffer')\r\n            return\r\n          }\r\n          const filePath: string = '_doc/' + cacheKey + '.mp3'\r\n          const abRef: ArrayBuffer = ab\r\n          // ArrayBuffer → base64 字符串，writeFile 在 App-Android 上只支持 base64/utf-8\r\n          let base64: string = ''\r\n          try {\r\n            base64 = uni.arrayBufferToBase64(abRef)\r\n          } catch (e) {\r\n            const msg = e != null ? ('' + e) : 'null'\r\n            onFail('TTS ArrayBuffer→base64 失败: ' + msg)\r\n            return\r\n          }\r\n          try {\r\n            uni.getFileSystemManager().writeFile({\r\n              filePath: filePath,\r\n              data: base64,\r\n              encoding: 'base64',\r\n              success: (): void => {\r\n                try {\r\n                  const fileSize: number = abRef.byteLength\r\n                  saveTtsCache(cacheKey, cacheKey, filePath, fileSize, 'minimax')\r\n                  __f__('log','at services/CloudService.uts:208','[CloudService] downloadTtsAudio OK, cacheKey=' + cacheKey + ' size=' + fileSize)\r\n                  onOK(filePath)\r\n                } catch (e) {\r\n                  const msg = e != null ? ('' + e) : 'null'\r\n                  onFail('TTS 缓存写库失败: ' + msg)\r\n                }\r\n              },\r\n              fail: (err): void => {\r\n                const msg = err != null ? ('' + err) : 'null'\r\n                __f__('warn','at services/CloudService.uts:217','[CloudService] writeFile fail: ' + msg)\r\n                onFail('TTS 文件写失败: ' + msg)\r\n              }\r\n            })\r\n          } catch (e) {\r\n            const msg = e != null ? ('' + e) : 'null'\r\n            onFail('TTS 写文件构造失败: ' + msg)\r\n          }\r\n        } catch (e) {\r\n          const msg = e != null ? ('' + e) : 'null'\r\n          onFail('TTS 下载处理异常: ' + msg)\r\n        }\r\n      },\r\n      fail(_err) {\r\n        const msg = _err != null ? ('' + _err) : 'null'\r\n        __f__('warn','at services/CloudService.uts:232','[CloudService] downloadTtsAudio network fail: ' + msg)\r\n        onFail('TTS 下载网络失败: ' + msg)\r\n      }\r\n    })\r\n  } catch (e) {\r\n    const msg = e != null ? ('' + e) : 'null'\r\n    onFail('TTS 下载请求构造失败: ' + msg)\r\n  }\r\n}\r\n\r\nexport function callDaily(date: string, data: DailyData, onOK: (raw: string) => void, onFail: () => void): void {\r\n  __f__('log','at services/CloudService.uts:243','[CloudService] callDaily start, date=' + date)\r\n  const userPrompt = buildDailySummaryPrompt(data)\r\n  callMinimaxChat(SYSTEM_PROMPT_DAILY, userPrompt, 1500, (raw: string): void => {\r\n    if (raw.length > 0) {\r\n      __f__('log','at services/CloudService.uts:247','[CloudService] callDaily OK, raw.length=' + raw.length)\r\n      onOK(raw)\r\n      return\r\n    }\r\n    __f__('warn','at services/CloudService.uts:251','[CloudService] callDaily empty raw')\r\n    onFail()\r\n  }, () => {\r\n    __f__('warn','at services/CloudService.uts:254','[CloudService] callDaily failed, fallback to local')\r\n    onFail()\r\n  })\r\n}\r\n\r\nexport function callWeekly(data: WeeklyReportStats, onOK: (raw: string) => void, onFail: () => void): void {\r\n  __f__('log','at services/CloudService.uts:260','[CloudService] callWeekly start, totalCompleted=' + data.totalCompleted)\r\n  const userPrompt = buildWeeklyReportPrompt(data)\r\n  callMinimaxChat(SYSTEM_PROMPT_WEEKLY, userPrompt, 2000, (raw: string): void => {\r\n    if (raw.length > 0) {\r\n      __f__('log','at services/CloudService.uts:264','[CloudService] callWeekly OK, raw.length=' + raw.length)\r\n      onOK(raw)\r\n      return\r\n    }\r\n    __f__('warn','at services/CloudService.uts:268','[CloudService] callWeekly empty raw')\r\n    onFail()\r\n  }, () => {\r\n    __f__('warn','at services/CloudService.uts:271','[CloudService] callWeekly failed, fallback to local')\r\n    onFail()\r\n  })\r\n}\r\n\r\nexport function callLlmEvaluate(\r\n  stage: 'pre' | 'post',\r\n  ctx: PreTriggerContext | PostActionContext,\r\n  onOK: (raw: string) => void,\r\n  onFail: () => void\r\n): void {\r\n  // 缓存命中短路：相同 (stage, pkg, hourBucket, contBucket) 直接复用\r\n  // 仅 pre 阶段构造缓存键：pre 有 appPackage + continuousMinutes，post 无\r\n  let cacheKey = ''\r\n  if (stage === 'pre') {\r\n    const pCtx = ctx as PreTriggerContext\r\n    const cacheCtx: LlmCacheContext = {\r\n      appPackage: pCtx.appPackage,\r\n      continuousMinutes: pCtx.continuousMinutes\r\n    }\r\n    cacheKey = buildLlmCacheKey(stage, cacheCtx)\r\n  }\r\n  if (cacheKey.length > 0) {\r\n    try {\r\n        const cached = getLlmCacheByKey(cacheKey)\n      if (cached != null && cached.response.length > 0) {\r\n        const nowSec = Math.floor(Date.now() / 1000)\r\n        if (cached.expires_at <= 0 || cached.expires_at > nowSec) {\r\n          __f__('log','at services/CloudService.uts:299','[CloudService] callLlmEvaluate ' + stage + ' cache HIT key=' + cacheKey)\r\n          onOK(cached.response)\r\n          return\r\n        }\r\n      }\r\n    } catch (e) {\r\n      __f__('warn','at services/CloudService.uts:305','[CloudService] callLlmEvaluate 读缓存异常: ' + (e != null ? ('' + e) : 'null'))\r\n    }\r\n  }\r\n  let userPrompt = ''\r\n  try {\r\n    if (stage === 'pre') {\r\n      const pCtx = ctx as PreTriggerContext\r\n      userPrompt = buildPreTriggerPrompt(pCtx)\r\n      __f__('log','at services/CloudService.uts:313','[CloudService] callLlmEvaluate pre userPrompt len=' + userPrompt.length)\r\n    } else {\r\n      const pCtx = ctx as PostActionContext\r\n      userPrompt = buildPostActionPrompt(pCtx)\r\n      __f__('log','at services/CloudService.uts:317','[CloudService] callLlmEvaluate post userPrompt len=' + userPrompt.length)\r\n    }\r\n  } catch (e) {\r\n    const msg = e != null ? ('' + e) : 'null'\r\n    __f__('warn','at services/CloudService.uts:321','[CloudService] callLlmEvaluate prompt 构造失败: ' + msg)\r\n    onFail()\r\n    return\r\n  }\r\n\r\n  callMinimaxChat(SYSTEM_PROMPT_EVALUATE, userPrompt, 1500, (raw: string): void => {\r\n    __f__('log','at services/CloudService.uts:327','[CloudService] callLlmEvaluate ' + stage + ' OK, rawLen=' + raw.length + ' preview=' + raw.substring(0, 80))\r\n    if (cacheKey.length > 0 && raw.length > 0) {\r\n      try {\r\n        const ttlSec = 24 * 60 * 60\r\n        const expiresAt = Math.floor(Date.now() / 1000) + ttlSec\r\n        saveLlmCache(cacheKey, stage, raw, expiresAt)\r\n      } catch (e) {\r\n        __f__('warn','at services/CloudService.uts:334','[CloudService] callLlmEvaluate 写缓存异常: ' + (e != null ? ('' + e) : 'null'))\r\n      }\r\n    }\r\n    onOK(raw)\r\n  }, (): void => {\r\n    __f__('warn','at services/CloudService.uts:339','[CloudService] callLlmEvaluate ' + stage + ' FAIL')\r\n    onFail()\r\n  })\r\n}\r\n\r\n// 缓存上下文：仅 pre 阶段有意义（post 阶段无 appPackage / continuousMinutes）\r\ntype LlmCacheContext = {\r\n  appPackage: string\r\n  continuousMinutes: number\r\n}\r\n\r\n// 构造缓存键：阶段 + 包名 + 整点 + 30min 连续桶\r\nfunction buildLlmCacheKey(stage: string, ctx: LlmCacheContext | null): string {\r\n  try {\r\n    if (ctx == null) return ''\r\n    const pkg = ctx.appPackage.length > 0 ? ctx.appPackage : 'unknown'\r\n    const dayMs = 24 * 60 * 60 * 1000\r\n    const hourBucket = Math.floor((Date.now() % dayMs) / (60 * 60 * 1000))\r\n    const contBucket = Math.floor(ctx.continuousMinutes / 30) * 30\r\n    return stage + ':' + pkg + ':' + hourBucket + ':' + contBucket\r\n  } catch (_) {\r\n    return ''\r\n  }\r\n}\r\n\r\nfunction extractChatContent(data: any): string {\r\n  try {\r\n    const obj = data as UTSJSONObject\r\n    if (obj == null) return ''\r\n    const baseResp = obj.get('base_resp')\r\n    if (baseResp != null) {\r\n      const brObj = baseResp as UTSJSONObject\r\n      const sc = brObj.get('status_code')\r\n      if (sc != null && sc != 0) {\r\n        const sm = brObj.get('status_msg')\r\n        __f__('warn','at services/CloudService.uts:374','[CloudService] MiniMax 返回非 0 状态: ' + (sm != null ? '' + sm : ''))\r\n        return ''\r\n      }\r\n    }\r\n    const choicesRaw = obj.get('choices')\r\n    if (choicesRaw == null) return ''\r\n    const choices = choicesRaw as Array<UTSJSONObject>\r\n    if (choices.length < 1) return ''\r\n    const first = choices[0]\r\n    if (first == null) return ''\r\n    const message = first.get('message')\r\n    if (message == null) return ''\r\n    const msgObj = message as UTSJSONObject\r\n    const content = msgObj.get('content')\r\n    if (content != null) {\r\n      const c = '' + content\r\n      if (c.length > 0) return c\r\n    }\r\n    const rc = msgObj.get('reasoning_content')\r\n    if (rc != null) {\r\n      const r = '' + rc\r\n      if (r.length > 0) return r\r\n    }\r\n  } catch (e) {\r\n    __f__('warn','at services/CloudService.uts:398','[CloudService] extractChatContent exception: ' + JSON.stringify(e))\r\n  }\r\n  return ''\r\n}\r\n\r\nfunction extractFinishReason(data: UTSJSONObject): string {\r\n  try {\r\n    const choices = data.get('choices')\r\n    if (choices == null) return ''\r\n    const arr = choices as Array<UTSJSONObject>\r\n    if (arr.length < 1) return ''\r\n    const first = arr[0]\r\n    if (first == null) return ''\r\n    const fr = first.get('finish_reason')\r\n    if (fr == null) return ''\r\n    return '' + fr\r\n  } catch (_) {\r\n    return ''\r\n  }\r\n}\r\n\r\nfunction parseJsonThreeLevels(raw: string): UTSJSONObject | null {\r\n  try {\r\n    const first = JSON.parse(raw)\r\n    if (first != null) {\r\n      if (typeof first === 'string') {\r\n        try {\r\n          const second = JSON.parse(first as string)\r\n          if (second != null && typeof second === 'object') return second as UTSJSONObject\r\n        } catch (_) {}\r\n      } else if (typeof first === 'object') {\r\n        return first as UTSJSONObject\r\n      }\r\n    }\r\n  } catch (_) {}\r\n  try {\r\n    const match = raw.match(/\\{[\\s\\S]*\\}/)\r\n    if (match != null) {\r\n      const m = match[0]\r\n      if (m != null && m.length > 0) {\r\n        const second = JSON.parse(m)\r\n        if (second != null && typeof second === 'object') return second as UTSJSONObject\r\n      }\r\n    }\r\n  } catch (_) {}\r\n  return null\r\n}\r\n","/// <reference types=\"@dcloudio/uni-app-x/types/uni/global\" />\n\nimport { currentPageCaptureScreenshot } from '../utils'\n\n// 之所以又写了一份，是因为外层的socket，connectSocket的时候必须传入multiple:true\n// 但是android又不能传入，目前代码里又不能写条件编译之类的。\nexport function initRuntimeSocket(\n  hosts: string,\n  port: string,\n  id: string\n): Promise<SocketTask | null> {\n  if (hosts == '' || port == '' || id == '') return Promise.resolve(null)\n  return hosts\n    .split(',')\n    .reduce<Promise<SocketTask | null>>(\n      (\n        promise: Promise<SocketTask | null>,\n        host: string\n      ): Promise<SocketTask | null> => {\n        return promise.then((socket): Promise<SocketTask | null> => {\n          if (socket != null) return Promise.resolve(socket)\n          return tryConnectSocket(host, port, id)\n        })\n      },\n      Promise.resolve(null)\n    )\n}\n\nconst SOCKET_TIMEOUT = 500\nfunction tryConnectSocket(\n  host: string,\n  port: string,\n  id: string\n): Promise<SocketTask | null> {\n  return new Promise((resolve, reject) => {\n    const socket = uni.connectSocket({\n      url: `ws://${host}:${port}/${id}`,\n      fail() {\n        resolve(null)\n      },\n    })\n    const timer = setTimeout(() => {\n      // @ts-expect-error\n      socket.close({\n        code: 1006,\n        reason: 'connect timeout',\n      } as CloseSocketOptions)\n      resolve(null)\n    }, SOCKET_TIMEOUT)\n\n    socket.onOpen((e) => {\n      clearTimeout(timer)\n      resolve(socket)\n    })\n    socket.onClose((e) => {\n      clearTimeout(timer)\n      resolve(null)\n    })\n    socket.onError((e) => {\n      clearTimeout(timer)\n      resolve(null)\n    })\n    // 接收 hx 消息，处理截屏请求\n    socket.onMessage((result) => {\n      if (typeof result['data'] == 'string') {\n        // @ts-expect-error\n        const message = JSON.parse<UTSJSONObject>(result['data'] as string)!\n        if ((message['type'] as string) == 'screencap') {\n          const id = message['id'] as string\n          currentPageCaptureScreenshot(\n            message['fullPage'] as boolean,\n            (base64: string, error: string) => {\n              // @ts-expect-error\n              socket.send({\n                data: JSON.stringify({\n                  id,\n                  base64,\n                  error,\n                }),\n              } as SendSocketMessageOptions)\n            }\n          )\n        }\n      }\n      resolve(null)\n    })\n  })\n}\n","export type SendFn = ((msg: string) => void) | null\n\nexport type currentPageCaptureScreenshotCallBack = (\n  base64: string,\n  error: string\n) => void\n\nexport function currentPageCaptureScreenshot(\n  fullPage: boolean,\n  callback: currentPageCaptureScreenshotCallBack\n) {\n  const pages = getCurrentPages() as UniPage[]\n  const currentPage = pages[pages.length - 1]\n  currentPage.vm?.$viewToTempFilePath({\n    wholeContent: fullPage,\n    overwrite: true,\n    success: (res) => {\n      const fileManager = uni.getFileSystemManager()\n      // @ts-expect-error\n      fileManager.readFile({\n        encoding: 'base64',\n        filePath: res.tempFilePath,\n        success(readFileRes) {\n          callback(readFileRes.data as string, '')\n        },\n        fail(err) {\n          callback('', `captureScreenshot fail: ${JSON.stringify(err)}`)\n        },\n      } as ReadFileOptions)\n    },\n    fail: (err) => {\n      callback('', `captureScreenshot fail: ${JSON.stringify(err)}`)\n    },\n  })\n}\n","import { initRuntimeSocket } from './socket'\n\nexport function initRuntimeSocketService(): Promise<boolean> {\n  const hosts: string = process.env.UNI_SOCKET_HOSTS\n  const port: string = process.env.UNI_SOCKET_PORT\n  const id: string = process.env.UNI_SOCKET_ID\n  if (hosts == '' || port == '' || id == '') return Promise.resolve(false)\n  let socketTask: SocketTask | null = null\n  return Promise.resolve()\n    .then((): Promise<boolean> => {\n      return initRuntimeSocket(hosts, port, id).then((socket): boolean => {\n        if (socket == null) {\n          return false\n        }\n        socketTask = socket\n        return true\n      })\n    })\n    .catch((): boolean => {\n      return false\n    })\n}\n\ninitRuntimeSocketService()\n","export type TimeWindow = {\n  start: string\n  end: string\n}\n\nexport type ScreenConditions = {\n  appPackages: string[]\n  includeHome: boolean\n}\n\nexport type TriggerLevel = 'gentle' | 'strong' | 'forced'\n\nexport type EffectiveTriggerRule = {\n  id: number\n  actionId: string\n  timeWindow: TimeWindow | null\n  screenConditions: ScreenConditions | null\n  timeThresholdMinutes: number\n  categoryFilter: string | null\n  source: 'local' | 'llm' | 'user' | 'system'\n  enabled: boolean\n  createdAt: number\n}\n","export type DailySummary = {\n  id: number\n  date: string\n  total_completed: number\n  total_skipped: number\n  total_duration_sec: number\n  eye_score: number\n  posture_score: number\n  vitality_score: number\n  penetration: number\n  phone_usage_min: number\n  guard_minutes: number\n  guard_count: number\n  created_at: number\n}\n\nexport type DailyData = {\n  totalCompleted: number\n  totalSkipped: number\n  totalDurationSec: number\n  guardMinutes: number\n  guardCount: number\n  penetration: number\n  eyeScore: number\n  postureScore: number\n  vitalityScore: number\n  todayCompletedCount: number\n}\n","export type WeeklyReportStats = {\n  totalCompleted: number\n  totalDurationSec: number\n  avgPenetration: number\n  avgGuardMinutes: number\n  bestDay: string\n  bestDayCount: number\n  worstDay: string\n  worstDayCount: number\n}\n\nexport type WeeklyReport = {\n  bodyMarkdown: string\n  stats: WeeklyReportStats\n}\n","import { EffectiveTriggerRule, TimeWindow, ScreenConditions, TriggerLevel } from '../models/EffectiveTriggerRule'\r\nimport { DailyData } from '../models/DailySummary'\r\nimport { WeeklyReportStats } from '../models/WeeklyReport'\r\n\r\n// 子类型：Pre 阶段的 App 7 天表现\r\nexport type PreAppHistory = {\r\n  totalTriggers: number\r\n  totalCompletes: number\r\n  totalSkips: number\r\n  acceptRate: number\r\n  typicalContinuousMin: number\r\n  lastTriggerAt: number\r\n}\r\n\r\n// 子类型：Post 阶段的 App 7 天表现（含周趋势）\r\nexport type PostAppHistory = {\r\n  packageName: string\r\n  totalTriggers: number\r\n  totalCompletes: number\r\n  totalSkips: number\r\n  acceptRate: number\r\n  typicalContinuousMin: number\r\n  lastWeekTrend: 'improving' | 'declining' | 'stable'\r\n}\r\n\r\n// 子类型：命中的触发规则\r\nexport type MatchedRuleInfo = {\r\n  actionId: string\r\n  source: 'user' | 'llm' | 'system'\r\n  timeWindow: TimeWindow | null\r\n  thresholdMinutes: number\r\n  triggerLevel: TriggerLevel\r\n}\r\n\r\n// 子类型：用户健康偏好\r\nexport type UserPreferenceInfo = {\r\n  healthFocus: 'eye' | 'posture' | 'vitality' | 'balanced'\r\n  bodyLimit: 'none' | 'neck' | 'waist' | 'knee'\r\n}\r\n\r\n// 子类型：Post 上下文中的当前规则条目\r\nexport type PostContextRuleItem = {\r\n  id: number\r\n  actionId: string\r\n  appPackages: string[]\r\n  timeWindow: TimeWindow | null\r\n  thresholdMinutes: number\r\n  triggerLevel: TriggerLevel\r\n  source: 'user' | 'llm' | 'system'\r\n  createdAt: number\r\n}\r\n\r\n// 子类型：上周同时段数据\r\nexport type LastWeekSameTime = {\r\n  avgContinuousMin: number\r\n  triggerCount: number\r\n}\r\n\r\n// 扩展后的 Pre-Trigger 上下文：含 App 历史、命中规则、用户偏好\r\nexport type PreTriggerContext = {\r\n  appLabel: string\r\n  appPackage: string\r\n  appCategory: string\r\n  continuousMinutes: number\r\n  hour: number\r\n  todayCompletedCount: number\r\n  guardMinutes: number\r\n  todaySkipCount: number\r\n  recentActions: string[]\r\n  appHistory: PreAppHistory | null\r\n  matchedRule: MatchedRuleInfo | null\r\n  userPreference: UserPreferenceInfo\r\n}\r\n\r\n// 扩展后的 Post-Action 上下文：含结构化当前规则\r\nexport type PostActionContext = {\r\n  actionId: string\r\n  actionName: string\r\n  actionCategory: string\r\n  durationMs: number\r\n  originalContext: string\r\n  todayCompletedCount: number\r\n  guardMinutes: number\r\n  todaySkipCount: number\r\n  recentActions: string[]\r\n  appHistory: PostAppHistory | null\r\n  currentRules: PostContextRuleItem[]\r\n  userPreference: UserPreferenceInfo\r\n  lastWeekSameTime: LastWeekSameTime | null\r\n}\r\n\r\nexport const SYSTEM_PROMPT_EVALUATE = '【角色】你是一个微习惯健康助手，名字叫“小球球”，目标是帮助用户做碎片化健康动作，养成健康微动作习惯。【性格】调皮，但是实际上很关心用户；友好，但是有自己的主见，个性强，对事物有好奇，喜欢问问题。【语言风格】日常，对话，短句，非常喜欢用比喻（但是不冒犯），有些时候会小顶嘴。【注意】不主动讨论隐私，不讨论敏感话题'\r\n\r\nexport function buildPreTriggerPrompt(context: PreTriggerContext): string {\r\n  if (context == null) {\r\n    return '用户当前状态：未知。请直接输出 {\"adhocText\": \"该动动了\", \"stateDescription\": \"需要休息\"}'\r\n  }\r\n  const recentArr = context.recentActions != null ? context.recentActions : []\r\n  const recentStr = recentArr.length > 0 ? recentArr.join('、') : '无'\r\n  const histLines: string[] = []\r\n  if (context.appHistory != null) {\r\n    const h = context.appHistory\r\n    const triggers = h.totalTriggers != null ? h.totalTriggers : 0\r\n    const accept = h.acceptRate != null ? h.acceptRate : 0\r\n    const typical = h.typicalContinuousMin != null ? h.typicalContinuousMin : 0\r\n    histLines.push('- 该 App 过去 7 天被触发 ' + triggers + ' 次')\r\n    histLines.push('- 接受率 ' + (accept * 100).toFixed(0) + '%')\r\n    histLines.push('- 平均连续使用 ' + typical + ' 分钟')\r\n  } else {\r\n    histLines.push('- 该 App 历史数据不足（首次见到）')\r\n  }\r\n  const ruleLines: string[] = []\r\n  if (context.matchedRule != null) {\r\n    const r = context.matchedRule\r\n    const thr = r.thresholdMinutes != null ? r.thresholdMinutes : 0\r\n    const lvl = r.triggerLevel != null ? r.triggerLevel : 'gentle'\r\n    ruleLines.push('- 命中规则：阈值 ' + thr + ' 分钟, 级别 ' + lvl)\r\n    if (r.timeWindow != null) {\r\n      ruleLines.push('- 时段：' + r.timeWindow.start + '-' + r.timeWindow.end)\r\n    }\r\n  }\r\n  const up = context.userPreference\r\n  const focus = up != null && up.healthFocus != null ? up.healthFocus : 'balanced'\r\n  const limit = up != null && up.bodyLimit != null ? up.bodyLimit : 'none'\r\n  const appLabel = context.appLabel != null ? context.appLabel : '某应用'\r\n  const appCat = context.appCategory != null ? context.appCategory : 'other'\r\n  const contMin = context.continuousMinutes != null ? context.continuousMinutes : 0\r\n  const hour = context.hour != null ? context.hour : 0\r\n  const todayCount = context.todayCompletedCount != null ? context.todayCompletedCount : 0\r\n  const guard = context.guardMinutes != null ? context.guardMinutes : 0\r\n  const skipCount = context.todaySkipCount != null ? context.todaySkipCount : 0\r\n  return '用户当前状态：\\n' +\r\n    '- 正在使用：' + appLabel + '（' + appCat + '）\\n' +\r\n    '- 已连续前台：' + contMin + ' 分钟\\n' +\r\n    '- 当前时间：' + hour + ':00\\n' +\r\n    '- 今日已完成微动作：' + todayCount + ' 次\\n' +\r\n    '- 今日已守护：' + guard + ' 分钟\\n' +\r\n    '- 今日已跳过：' + skipCount + ' 次\\n' +\r\n    '- 最近 5 次动作：' + recentStr + '\\n' +\r\n    '- 用户偏好：' + focus + ' / 限制部位 ' + limit + '\\n' +\r\n    histLines.join('\\n') + '\\n' +\r\n    (ruleLines.length > 0 ? ruleLines.join('\\n') + '\\n' : '') +\r\n    '\\n请基于以上状态生成：\\n' +\r\n    '1. adhocText：一句 10-30 字的 TTS 即兴文案\\n' +\r\n    '2. stateDescription：用 5-15 字概括当前状态（用于\"为什么提醒我\"展示）\\n\\n' +\r\n    '严格按 JSON 格式输出：{\"adhocText\": \"...\", \"stateDescription\": \"...\"}'\r\n}\r\n\r\nexport function buildPostActionPrompt(context: PostActionContext): string {\r\n  if (context == null) {\r\n    return '用户刚完成微动作。请直接输出 {\"decision\": \"no_change\", \"targetRuleId\": 0, \"suggestedRule\": null, \"reasoning\": \"数据缺失\", \"confidence\": 0.5, \"alternatives\": []}'\r\n  }\r\n  const recentArr = context.recentActions != null ? context.recentActions : []\r\n  const recentStr = recentArr.length > 0 ? recentArr.join('、') : '无'\r\n  const rulesArr = context.currentRules != null ? context.currentRules : []\r\n  const rulesStrParts: string[] = []\r\n  for (let i = 0; i < rulesArr.length; i++) {\r\n    const r = rulesArr[i]\r\n    const tw = r.timeWindow != null ? ('[' + r.timeWindow.start + '-' + r.timeWindow.end + ']') : '[全天]'\r\n    rulesStrParts.push('  ' + r.actionId + ' ' + tw + ' ≥' + r.thresholdMinutes + 'min ' + r.triggerLevel + ' [' + r.source + ']')\r\n  }\r\n  const rulesStr = rulesStrParts.length > 0 ? rulesStrParts.join('\\n') : '  暂无规则'\r\n  const histLines: string[] = []\r\n  if (context.appHistory != null) {\r\n    const h = context.appHistory\r\n    const accept = h.acceptRate != null ? h.acceptRate : 0\r\n    const typical = h.typicalContinuousMin != null ? h.typicalContinuousMin : 0\r\n    const trend = h.lastWeekTrend != null ? h.lastWeekTrend : 'stable'\r\n    histLines.push('- 该 App 接受率 ' + (accept * 100).toFixed(0) + '%，趋势 ' + trend)\r\n    histLines.push('- 该 App 平均连续使用 ' + typical + ' 分钟')\r\n  }\r\n  const defaultPref: UserPreferenceInfo = { healthFocus: 'balanced', bodyLimit: 'none' }\r\n  const pref: UserPreferenceInfo = context.userPreference != null\r\n    ? context.userPreference\r\n    : defaultPref\r\n  const aName = context.actionName != null ? context.actionName : '未知动作'\r\n  const aCat = context.actionCategory != null ? context.actionCategory : 'other'\r\n  const durMs = context.durationMs != null ? context.durationMs : 0\r\n  const origCtx = context.originalContext != null ? context.originalContext : ''\r\n  const tc = context.todayCompletedCount != null ? context.todayCompletedCount : 0\r\n  const ts = context.todaySkipCount != null ? context.todaySkipCount : 0\r\n  const gm = context.guardMinutes != null ? context.guardMinutes : 0\r\n  return '用户刚完成微动作：' + aName + '（' + aCat + '，' +\r\n    Math.round(durMs / 1000) + '秒）\\n' +\r\n    '原触发上下文：' + origCtx + '\\n' +\r\n    '今日累计：' + tc + ' 次完成 / ' + ts + ' 次跳过 / ' + gm + ' 分钟守护\\n' +\r\n    '最近 5 次：' + recentStr + '\\n' +\r\n    '用户偏好：' + pref.healthFocus + ' / 限制部位 ' + pref.bodyLimit + '\\n' +\r\n    '当前生效的触发规则：\\n' + rulesStr + '\\n' +\r\n    (histLines.length > 0 ? histLines.join('\\n') + '\\n' : '') +\r\n    '\\n请评估：\\n' +\r\n    '1. 用户的健康习惯是否稳定？是否需要调整触发频率或类型？\\n' +\r\n    '2. 是否需要新增/修改/删除某条触发规则？\\n\\n' +\r\n    '严格按以下 JSON 格式输出（decision 必须是以下之一：create_rule / modify_rule / delete_rule / no_change）：\\n' +\r\n    '{\"decision\": \"create_rule\", \"targetRuleId\": 0, \"suggestedRule\": {\"actionId\": \"eye_blink\", \"screenConditions\": {\"appPackages\": [\"com.zhihu.android\"], \"includeHome\": false}, \"timeWindow\": {\"start\": \"22:00\", \"end\": \"07:00\"}, \"timeThresholdMinutes\": 60}, \"reasoning\": \"...\", \"confidence\": 0.85, \"alternatives\": []}\\n\\n' +\r\n    '如果不调整，输出：\\n' +\r\n    '{\"decision\": \"no_change\", \"targetRuleId\": 0, \"suggestedRule\": null, \"reasoning\": \"当前规则合理，继续观察\", \"confidence\": 0.7, \"alternatives\": []}\\n\\n' +\r\n    '说明：\\n' +\r\n    '- decision: no_change（不动）/ create_rule（新增）/ modify_rule（修改 targetRuleId）/ delete_rule（删除 targetRuleId）\\n' +\r\n    '- targetRuleId: 仅 modify/delete 时填对应 rule id\\n' +\r\n    '- suggestedRule.actionId: 动作 ID（必填）\\n' +\r\n    '- suggestedRule.screenConditions.appPackages: 命中的应用包名列表（数组）\\n' +\r\n    '- suggestedRule.screenConditions.includeHome: 是否包含桌面（boolean）\\n' +\r\n    '- suggestedRule.timeWindow: {start, end} 格式 \"HH:MM\"；不需要时填 null\\n' +\r\n    '- suggestedRule.timeThresholdMinutes: 连续前台分钟阈值（数字）\\n' +\r\n    '- confidence: 0~1，你对这个建议的把握度\\n' +\r\n    '- alternatives: 备选方案数组（可为空）'\r\n}\r\n\r\nexport const FALLBACK_ADHOC_TEXTS: string[] = [\r\n  '该起来动动了——',\r\n  '休息一下，来——',\r\n  '你的身体发来一条提醒——',\r\n  '眼睛有点累，眨一眨吧——',\r\n  '坐久了吗？动一动——'\r\n]\r\n\r\nexport function getFallbackAdhoc(): string {\r\n  const idx = Math.floor(Math.random() * FALLBACK_ADHOC_TEXTS.length)\r\n  return FALLBACK_ADHOC_TEXTS[idx]\r\n}\r\n\r\nexport const SYSTEM_PROMPT_DAILY = '你是一个微习惯健康助手，负责生成每日健康小结。\\n请用**纯中文文本**回复（不要 JSON 格式，不要 Markdown 标题/列表标记）。\\n风格：温柔+轻度幽默+不油腻的中文。避免医学恐吓和引发焦虑的表述。\\n绝对禁止读取用户隐私内容，只能使用提供的脱敏聚合数据。'\r\n\r\nexport function buildDailySummaryPrompt(data: DailyData): string {\r\n  return '以下是用户今日（截止当前）的健康微动作数据：\\n' +\r\n    '- 今日完成微动作：' + data.todayCompletedCount + ' 次\\n' +\r\n    '- 今日跳过：' + data.totalSkipped + ' 次\\n' +\r\n    '- 累计守护时长：' + data.totalDurationSec + ' 秒\\n' +\r\n    '- 护眼评分：' + data.eyeScore + ' / 100\\n' +\r\n    '- 体态评分：' + data.postureScore + ' / 100\\n' +\r\n    '- 活力评分：' + data.vitalityScore + ' / 100\\n' +\r\n    '- 穿透率：' + Math.round(data.penetration * 100) + '%\\n\\n' +\r\n    '请用 2-3 段纯中文（用换行分段）生成今日小结：\\n' +\r\n    '1. 开场一句总结（15-25字，要温暖）\\n' +\r\n    '2. 今日表现小结（40-60字，指出具体数据）\\n' +\r\n    '3. 明日小目标（20-30字，给出可执行建议）\\n\\n' +\r\n    '回复必须是纯中文文本，禁止 JSON、禁止 Markdown 标题/列表标记。'\r\n}\r\n\r\nexport const SYSTEM_PROMPT_WEEKLY = '你是一个微习惯健康助手，负责生成每周健康报告。\\n请用**纯文本**回复（不要 JSON 格式，不要 Markdown 标题/列表标记）。\\n可以使用换行分段，风格温暖+鼓励+不油腻的中文。\\n绝对禁止读取用户隐私内容，只能使用提供的脱敏聚合数据。'\r\n\r\nexport function buildWeeklyReportPrompt(stats: WeeklyReportStats): string {\r\n  return '以下是用户本周（过去 7 天）的健康微动作汇总数据：\\n' +\r\n    '- 本周完成微动作总数：' + stats.totalCompleted + ' 次\\n' +\r\n    '- 本周累计守护时长：' + stats.totalDurationSec + ' 秒\\n' +\r\n    '- 平均穿透率：' + Math.round(stats.avgPenetration * 100) + '%\\n' +\r\n    '- 平均每日守护：' + stats.avgGuardMinutes + ' 分钟\\n' +\r\n    '- 最佳一天：' + (stats.bestDay.length > 0 ? stats.bestDay + '（' + stats.bestDayCount + '次）' : '无数据') + '\\n' +\r\n    '- 最弱一天：' + (stats.worstDay.length > 0 ? stats.worstDay + '（' + stats.worstDayCount + '次）' : '无数据') + '\\n\\n' +\r\n    '请用 2-4 段纯中文（可用换行分段）写一份周报：\\n' +\r\n    '1. 先给一个鼓励性的开场（30-50字）\\n' +\r\n    '2. 总结本周亮点和值得肯定的地方（50-80字）\\n' +\r\n    '3. 指出可以改进的地方（50-80字）\\n' +\r\n    '4. 给出下周的小目标（30-50字）\\n' +\r\n    '回复必须是纯中文文本，禁止 JSON、禁止 Markdown 标题/列表标记。'\r\n}\r\n","export type ActionResult = 'completed' | 'self_reported' | 'skipped' | 'feedback'\n\nexport type SkipReason = 'busy' | 'too_hard' | 'bad_timing' | 'dont_want' | string\n\nexport type ActionLog = {\n  id: number\n  action_id: string\n  action_type: string\n  result: ActionResult\n  skip_reason: string | null\n  trigger_type: string\n  trigger_level: string\n  duration_ms: number\n  target_ms: number\n  triggered_at: number\n  completed_at: number\n  created_at: number\n}\n","export type DefaultSetting = {\n  key: string\n  value: string\n}\n\nexport const DEFAULT_SETTINGS: DefaultSetting[] = [\n  { key: 'daily_goal', value: '20' },\n  { key: 'app_duration_threshold', value: '60' },\n  { key: 'dnd_start', value: '22:00' },\n  { key: 'dnd_end', value: '07:00' },\n  { key: 'dnd_enabled', value: '1' },\n  { key: 'app_blacklist', value: '[]' },\n  { key: 'action_duration_pref', value: '15' },\n  { key: 'tts_enabled', value: '1' },\n  { key: 'tts_volume', value: '70' },\n  { key: 'tts_night_quiet', value: '1' },\n  { key: 'cloud_sync_enabled', value: '0' },\n  { key: 'llm_analysis_enabled', value: '1' },\n  { key: 'daily_summary_time', value: '21:00' },\n  { key: 'weekly_report_enabled', value: '1' },\n  { key: 'dark_mode', value: 'system' },\n  { key: 'newbie_mode', value: '1' },\n  { key: 'guide_completed', value: '0' },\n  { key: 'health_preference', value: 'balanced' },\n  { key: 'body_limit', value: 'none' },\n  { key: 'llm_trigger_enabled', value: '1' },\n  { key: 'llm_trigger_ask_each_time', value: '1' },\n  { key: 'trigger_enabled', value: '1' }\n]\n","import { DEFAULT_SETTINGS } from '../constants/DefaultSettings'\nimport { sqliteStore } from '../uni_modules/uts-sqlite-store/utssdk/app-android/index'\n\nconst DB_NAME = 'micro_habit_v2.db'\nconst DB_VERSION = 9\n\nexport function getDbName(): string {\n  return DB_NAME\n}\n\nexport function getDbVersion(): number {\n  return DB_VERSION\n}\n\nfunction runSql(sql: string, params: any[] = []): void {\n  sqliteStore.execSql(sql, params)\n}\n\nexport function onCreate(): void {\n  createTables()\n  insertDefaultSettings()\n  insertDefaultSystemRule()\n  const nowSec = Math.floor(Date.now() / 1000)\n  runSql(\"UPDATE user_settings SET value = '1', updated_at = ? WHERE key = 'trigger_enabled'\", [nowSec])\n}\n\nexport function onUpgrade(oldVersion: number, newVersion: number): void {\n  if (oldVersion < 2) {\n    runSql(\"ALTER TABLE daily_summaries ADD COLUMN llm_one_liner TEXT DEFAULT ''\")\n  }\n  if (oldVersion < 3) {\n    runSql(\"ALTER TABLE daily_summaries ADD COLUMN guard_count INTEGER NOT NULL DEFAULT 0\")\n  }\n  if (oldVersion < 4) {\n    runSql(`CREATE TABLE IF NOT EXISTS llm_history (\n      id INTEGER PRIMARY KEY AUTOINCREMENT,\n      stage TEXT NOT NULL,\n      context_json TEXT NOT NULL,\n      ai_raw_response TEXT NOT NULL,\n      parsed_result_json TEXT DEFAULT '{}',\n      adhoc_text TEXT DEFAULT NULL,\n      suggested_rule_json TEXT DEFAULT NULL,\n      reasoning TEXT DEFAULT NULL,\n      created_at INTEGER NOT NULL\n    )`)\n    runSql(\"CREATE INDEX IF NOT EXISTS idx_llm_history_date ON llm_history(created_at)\")\n    runSql(\"CREATE INDEX IF NOT EXISTS idx_llm_history_stage ON llm_history(stage)\")\n  }\n  if (oldVersion < 5) {\n    runSql(\"DROP TABLE IF EXISTS trigger_rules\")\n    runSql(\"ALTER TABLE app_usage_snapshots ADD COLUMN category TEXT DEFAULT 'other'\")\n    runSql(\"ALTER TABLE app_usage_snapshots ADD COLUMN trigger_count INTEGER DEFAULT 0\")\n    runSql(\"ALTER TABLE app_usage_snapshots ADD COLUMN complete_count INTEGER DEFAULT 0\")\n    runSql(\"ALTER TABLE llm_history ADD COLUMN confidence REAL DEFAULT 0\")\n    runSql(\"ALTER TABLE llm_history ADD COLUMN decision TEXT DEFAULT NULL\")\n    runSql(\"ALTER TABLE llm_history ADD COLUMN target_rule_id INTEGER DEFAULT NULL\")\n    runSql(\"ALTER TABLE llm_history ADD COLUMN user_accepted INTEGER DEFAULT NULL\")\n    runSql(\"ALTER TABLE llm_history ADD COLUMN alternatives_json TEXT DEFAULT NULL\")\n    runSql(\"CREATE INDEX IF NOT EXISTS idx_llm_history_target ON llm_history(target_rule_id, decision, user_accepted)\")\n    runSql(`CREATE TABLE IF NOT EXISTS app_tags (\n      package_name TEXT PRIMARY KEY,\n      app_label TEXT NOT NULL DEFAULT '',\n      category TEXT NOT NULL DEFAULT 'other',\n      tag_source TEXT NOT NULL DEFAULT 'pending',\n      is_user_locked INTEGER NOT NULL DEFAULT 0,\n      is_in_rule INTEGER NOT NULL DEFAULT 0,\n      total_uses INTEGER NOT NULL DEFAULT 0,\n      last_seen_at INTEGER NOT NULL,\n      created_at INTEGER NOT NULL,\n      updated_at INTEGER NOT NULL\n    )`)\n    runSql(\"CREATE INDEX IF NOT EXISTS idx_app_tags_category ON app_tags(category)\")\n    runSql(\"CREATE INDEX IF NOT EXISTS idx_app_tags_locked ON app_tags(is_user_locked)\")\n    runSql(`CREATE TABLE IF NOT EXISTS effective_rules (\n      id INTEGER PRIMARY KEY AUTOINCREMENT,\n      action_id TEXT NOT NULL,\n      app_packages_json TEXT NOT NULL,\n      time_window_json TEXT,\n      time_threshold_minutes INTEGER NOT NULL,\n      trigger_level TEXT NOT NULL DEFAULT 'gentle',\n      category_filter TEXT,\n      source TEXT NOT NULL DEFAULT 'user',\n      source_history_id INTEGER,\n      expires_at INTEGER,\n      enabled INTEGER NOT NULL DEFAULT 1,\n      priority INTEGER NOT NULL DEFAULT 0,\n      created_at INTEGER NOT NULL,\n      updated_at INTEGER NOT NULL\n    )`)\n    runSql(\"CREATE INDEX IF NOT EXISTS idx_effective_rules_enabled ON effective_rules(enabled)\")\n  }\n  if (oldVersion < 6) {\n    const nowSec = Math.floor(Date.now() / 1000)\n    runSql(\"INSERT OR IGNORE INTO user_settings (key, value, updated_at) VALUES (?, ?, ?)\",\n      ['trigger_enabled', '0', nowSec])\n  }\n  if (oldVersion < 7) {\n    const nowSec = Math.floor(Date.now() / 1000)\n    runSql(\"INSERT OR IGNORE INTO effective_rules (action_id, app_packages_json, time_window_json, time_threshold_minutes, trigger_level, category_filter, source, source_history_id, expires_at, enabled, priority, created_at, updated_at) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)\",\n      ['', '[]', '', 60, 'gentle', '', 'system', '', '', 1, 0, nowSec, nowSec])\n  }\n  if (oldVersion < 8) {\n    const nowSec = Math.floor(Date.now() / 1000)\n    runSql(\"UPDATE user_settings SET value = '1', updated_at = ? WHERE key = 'trigger_enabled' AND value = '0'\", [nowSec])\n  }\n  if (oldVersion < 9) {\n    runSql(`CREATE TABLE IF NOT EXISTS user_achievements (\n      id INTEGER PRIMARY KEY AUTOINCREMENT,\n      achievement_id TEXT NOT NULL UNIQUE,\n      unlocked_at INTEGER NOT NULL,\n      current_progress REAL NOT NULL DEFAULT 0,\n      created_at INTEGER NOT NULL\n    )`)\n    runSql(\"CREATE INDEX IF NOT EXISTS idx_user_achievements_unlocked ON user_achievements(unlocked_at)\")\n  }\n}\n\nexport function clearAchievements(): void {\n  runSql(\"DELETE FROM user_achievements\")\n}\n\nfunction createTables(): void {\n  runSql(`CREATE TABLE IF NOT EXISTS action_logs (\n    id INTEGER PRIMARY KEY AUTOINCREMENT,\n    action_id TEXT NOT NULL,\n    action_type TEXT NOT NULL,\n    result TEXT NOT NULL,\n    skip_reason TEXT DEFAULT NULL,\n    trigger_type TEXT NOT NULL,\n    trigger_level TEXT NOT NULL,\n    duration_ms INTEGER NOT NULL,\n    target_ms INTEGER NOT NULL,\n    triggered_at INTEGER NOT NULL,\n    completed_at INTEGER NOT NULL,\n    created_at INTEGER NOT NULL\n  )`)\n  runSql(\"CREATE INDEX IF NOT EXISTS idx_action_logs_date ON action_logs(created_at)\")\n  runSql(\"CREATE INDEX IF NOT EXISTS idx_action_logs_action_id ON action_logs(action_id)\")\n  runSql(\"CREATE INDEX IF NOT EXISTS idx_action_logs_result ON action_logs(result)\")\n\n  runSql(`CREATE TABLE IF NOT EXISTS trigger_logs (\n    id INTEGER PRIMARY KEY AUTOINCREMENT,\n    trigger_type TEXT NOT NULL,\n    trigger_level TEXT NOT NULL DEFAULT 'gentle',\n    app_package TEXT DEFAULT NULL,\n    app_category TEXT DEFAULT NULL,\n    continuous_minutes INTEGER DEFAULT 0,\n    action_id TEXT DEFAULT NULL,\n    user_action TEXT DEFAULT NULL,\n    created_at INTEGER NOT NULL\n  )`)\n  runSql(\"CREATE INDEX IF NOT EXISTS idx_trigger_logs_date ON trigger_logs(created_at)\")\n  runSql(\"CREATE INDEX IF NOT EXISTS idx_trigger_logs_type ON trigger_logs(trigger_type)\")\n\n  runSql(`CREATE TABLE IF NOT EXISTS daily_summaries (\n    id INTEGER PRIMARY KEY AUTOINCREMENT,\n    date TEXT NOT NULL UNIQUE,\n    total_completed INTEGER NOT NULL DEFAULT 0,\n    total_skipped INTEGER NOT NULL DEFAULT 0,\n    total_duration_sec INTEGER NOT NULL DEFAULT 0,\n    eye_score REAL NOT NULL DEFAULT 0,\n    posture_score REAL NOT NULL DEFAULT 0,\n    vitality_score REAL NOT NULL DEFAULT 0,\n    penetration REAL NOT NULL DEFAULT 0,\n    phone_usage_min INTEGER NOT NULL DEFAULT 0,\n    guard_minutes INTEGER NOT NULL DEFAULT 0,\n    guard_count INTEGER NOT NULL DEFAULT 0,\n    created_at INTEGER NOT NULL\n  )`)\n  runSql(\"CREATE UNIQUE INDEX IF NOT EXISTS idx_daily_summaries_date ON daily_summaries(date)\")\n\n  runSql(`CREATE TABLE IF NOT EXISTS user_settings (\n    key TEXT PRIMARY KEY,\n    value TEXT NOT NULL,\n    updated_at INTEGER NOT NULL\n  )`)\n\n  runSql(`CREATE TABLE IF NOT EXISTS app_usage_snapshots (\n    id INTEGER PRIMARY KEY AUTOINCREMENT,\n    date TEXT NOT NULL,\n    package_name TEXT NOT NULL,\n    app_label TEXT DEFAULT '',\n    total_foreground_sec INTEGER NOT NULL DEFAULT 0,\n    category TEXT DEFAULT 'other',\n    trigger_count INTEGER DEFAULT 0,\n    complete_count INTEGER DEFAULT 0,\n    created_at INTEGER NOT NULL\n  )`)\n  runSql(\"CREATE INDEX IF NOT EXISTS idx_app_usage_snapshots_date ON app_usage_snapshots(date)\")\n\n  runSql(`CREATE TABLE IF NOT EXISTS tts_cache (\n    text_hash TEXT PRIMARY KEY,\n    text_content TEXT NOT NULL,\n    file_path TEXT NOT NULL,\n    file_size INTEGER NOT NULL DEFAULT 0,\n    source TEXT NOT NULL DEFAULT 'minimax',\n    created_at INTEGER NOT NULL\n  )`)\n\n  runSql(`CREATE TABLE IF NOT EXISTS heartbeat_logs (\n    id INTEGER PRIMARY KEY AUTOINCREMENT,\n    service_status TEXT NOT NULL,\n    timestamp INTEGER NOT NULL\n  )`)\n  runSql(\"CREATE INDEX IF NOT EXISTS idx_heartbeat_timestamp ON heartbeat_logs(timestamp)\")\n\n  runSql(`CREATE TABLE IF NOT EXISTS llm_cache (\n    cache_key TEXT PRIMARY KEY,\n    cache_type TEXT NOT NULL,\n    response TEXT NOT NULL,\n    model TEXT NOT NULL DEFAULT '',\n    created_at INTEGER NOT NULL,\n    expires_at INTEGER NOT NULL\n  )`)\n\n  runSql(`CREATE TABLE IF NOT EXISTS llm_history (\n    id INTEGER PRIMARY KEY AUTOINCREMENT,\n    stage TEXT NOT NULL,\n    context_json TEXT NOT NULL,\n    ai_raw_response TEXT NOT NULL,\n    parsed_result_json TEXT DEFAULT '{}',\n    adhoc_text TEXT DEFAULT NULL,\n    suggested_rule_json TEXT DEFAULT NULL,\n    reasoning TEXT DEFAULT NULL,\n    confidence REAL DEFAULT 0,\n    decision TEXT DEFAULT NULL,\n    target_rule_id INTEGER DEFAULT NULL,\n    user_accepted INTEGER DEFAULT NULL,\n    alternatives_json TEXT DEFAULT NULL,\n    created_at INTEGER NOT NULL\n  )`)\n  runSql(\"CREATE INDEX IF NOT EXISTS idx_llm_history_date ON llm_history(created_at)\")\n  runSql(\"CREATE INDEX IF NOT EXISTS idx_llm_history_stage ON llm_history(stage)\")\n  runSql(\"CREATE INDEX IF NOT EXISTS idx_llm_history_target ON llm_history(target_rule_id, decision, user_accepted)\")\n\n  runSql(`CREATE TABLE IF NOT EXISTS app_tags (\n    package_name TEXT PRIMARY KEY,\n    app_label TEXT NOT NULL DEFAULT '',\n    category TEXT NOT NULL DEFAULT 'other',\n    tag_source TEXT NOT NULL DEFAULT 'pending',\n    is_user_locked INTEGER NOT NULL DEFAULT 0,\n    is_in_rule INTEGER NOT NULL DEFAULT 0,\n    total_uses INTEGER NOT NULL DEFAULT 0,\n    last_seen_at INTEGER NOT NULL,\n    created_at INTEGER NOT NULL,\n    updated_at INTEGER NOT NULL\n  )`)\n  runSql(\"CREATE INDEX IF NOT EXISTS idx_app_tags_category ON app_tags(category)\")\n  runSql(\"CREATE INDEX IF NOT EXISTS idx_app_tags_locked ON app_tags(is_user_locked)\")\n\n  runSql(`CREATE TABLE IF NOT EXISTS effective_rules (\n    id INTEGER PRIMARY KEY AUTOINCREMENT,\n    action_id TEXT NOT NULL,\n    app_packages_json TEXT NOT NULL,\n    time_window_json TEXT,\n    time_threshold_minutes INTEGER NOT NULL,\n    trigger_level TEXT NOT NULL DEFAULT 'gentle',\n    category_filter TEXT,\n    source TEXT NOT NULL DEFAULT 'user',\n    source_history_id INTEGER,\n    expires_at INTEGER,\n    enabled INTEGER NOT NULL DEFAULT 1,\n    priority INTEGER NOT NULL DEFAULT 0,\n    created_at INTEGER NOT NULL,\n    updated_at INTEGER NOT NULL\n  )`)\n  runSql(\"CREATE INDEX IF NOT EXISTS idx_effective_rules_enabled ON effective_rules(enabled)\")\n\n  runSql(`CREATE TABLE IF NOT EXISTS user_achievements (\n    id INTEGER PRIMARY KEY AUTOINCREMENT,\n    achievement_id TEXT NOT NULL UNIQUE,\n    unlocked_at INTEGER NOT NULL,\n    current_progress REAL NOT NULL DEFAULT 0,\n    created_at INTEGER NOT NULL\n  )`)\n  runSql(\"CREATE INDEX IF NOT EXISTS idx_user_achievements_unlocked ON user_achievements(unlocked_at)\")\n}\n\nfunction insertDefaultSettings(): void {\n  const now = Math.floor(Date.now() / 1000)\n  for (const s of DEFAULT_SETTINGS) {\n    runSql(\"INSERT OR IGNORE INTO user_settings (key, value, updated_at) VALUES (?, ?, ?)\", [s.key, s.value, now])\n  }\n}\n\nfunction insertDefaultSystemRule(): void {\n  const now = Math.floor(Date.now() / 1000)\n  runSql(\"INSERT OR IGNORE INTO effective_rules (action_id, app_packages_json, time_window_json, time_threshold_minutes, trigger_level, category_filter, source, source_history_id, expires_at, enabled, priority, created_at, updated_at) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)\",\n    ['', '[]', '', 60, 'gentle', '', 'system', '', '', 1, 0, now, now])\n}\n","export type StatusLevel = 'good' | 'normal' | 'warning' | 'no_data'\n\nexport type ThreeStatus = {\n  eyeScore: number\n  eyeLevel: StatusLevel\n  postureScore: number\n  postureLevel: StatusLevel\n  vitalityScore: number\n  vitalityLevel: StatusLevel\n}\n","export type ActionCategory = '护眼' | '肩颈' | '核心' | '下肢' | '呼吸'\n\nexport type DifficultyLevel = 1 | 2 | 3\n\nexport type MicroAction = {\n  id: string\n  name: string\n  category: ActionCategory\n  defaultDurationMs: number\n  difficulty: DifficultyLevel\n  ttsText: string\n  iconPath: string\n}\n","import { sqliteStore, type SqlRow } from '../uni_modules/uts-sqlite-store/utssdk/app-android/index'\r\n\r\nexport { type SqlRow }\r\n\r\nclass DbManagerShim {\r\n  init(): void {\r\n  }\r\n\r\n  execSql(sql: string, params: any[] = []): void {\r\n    sqliteStore.execSql(sql, params)\r\n  }\r\n\r\n  query(sql: string, params: any[] = []): Map<string, any>[] {\r\n    return sqliteStore.query(sql, params)\r\n  }\r\n\r\n  queryOne(sql: string, params: any[] = []): Map<string, any> | null {\r\n    return sqliteStore.queryOne(sql, params)\r\n  }\r\n\r\n  insert(table: string, row: SqlRow): number {\r\n    return sqliteStore.insert(table, row)\r\n  }\r\n\r\n  update(table: string, row: SqlRow, where: string, whereArgs: any[] = []): number {\r\n    return sqliteStore.update(table, row, where, whereArgs)\r\n  }\r\n\r\n  delete(table: string, where: string, whereArgs: any[] = []): number {\r\n    return sqliteStore.delete(table, where, whereArgs)\r\n  }\r\n\r\n  close(): void {\r\n    sqliteStore.close()\r\n  }\r\n}\r\n\r\nexport const dbManager = DbManagerShim()\r\n","// Database row null-safe getters\n// dbManager.queryOne()/query() 实际返回类型是 Map<string, any> | null\n// 直接 row.get(col) 会被 UTS 编译器推断为 String.get(index) 歧义候选\n// 必须用 Map<string, any> 类型 + null 守卫\n\nexport function getNum(row: Map<string, any> | null, col: string): number {\n  if (row == null) return 0\n  const v = row.get(col)\n  if (v == null) return 0\n  if (typeof v === 'number') return v as number\n  if (typeof v === 'string') {\n    const s = v as string\n    if (s.length < 1) return 0\n    const n = parseFloat(s)\n    return isNaN(n) ? 0 : n\n  }\n  return 0\n}\n\nexport function getStr(row: Map<string, any> | null, col: string): string {\n  if (row == null) return ''\n  const v = row.get(col)\n  if (v == null) return ''\n  return v as string\n}\n\nexport function getStrOrNull(row: Map<string, any> | null, col: string): string | null {\n  if (row == null) return null\n  const v = row.get(col)\n  if (v == null) return null\n  return v as string\n}\n","import { dbManager, type SqlRow } from './DatabaseManager'\r\nimport { ActionLog, ActionResult } from '../models/ActionLog'\r\nimport { getNum, getStr, getStrOrNull } from '../utils/DbRowUtils'\r\n\r\nexport function insertActionLog(log: ActionLog): number {\r\n  const row: SqlRow = {\r\n    columns: [\r\n      'action_id', 'action_type', 'result', 'skip_reason',\r\n      'trigger_type', 'trigger_level', 'duration_ms', 'target_ms',\r\n      'triggered_at', 'completed_at', 'created_at'\r\n    ],\r\n    values: [\r\n      log.action_id, log.action_type, log.result, log.skip_reason,\r\n      log.trigger_type, log.trigger_level, log.duration_ms, log.target_ms,\r\n      log.triggered_at, log.completed_at, log.created_at\r\n    ]\r\n  }\r\n  return dbManager.insert('action_logs', row)\r\n}\r\n\r\nexport function insertManualActionLog(\r\n  actionId: string,\r\n  actionType: string,\r\n  result: string,\r\n  skipReason: string | null,\r\n  durationMs: number,\r\n  targetMs: number,\r\n  triggeredAt: number,\r\n  completedAt: number,\r\n  createdAt: number\r\n): number {\r\n  const log: ActionLog = {\r\n    id: 0,\r\n    action_id: actionId,\r\n    action_type: actionType,\r\n    result: result as ActionResult,\r\n    skip_reason: skipReason,\r\n    trigger_type: 'manual',\r\n    trigger_level: 'gentle',\r\n    duration_ms: durationMs,\r\n    target_ms: targetMs,\r\n    triggered_at: triggeredAt,\r\n    completed_at: completedAt,\r\n    created_at: createdAt\r\n  }\r\n  return insertActionLog(log)\r\n}\r\n\r\nexport function getTodayLogs(): ActionLog[] {\r\n  const start = getDayStartTimestamp()\r\n  const end = start + 86400\r\n  const rows = dbManager.query(\r\n    'SELECT * FROM action_logs WHERE created_at >= ? AND created_at < ? ORDER BY created_at DESC',\r\n    [start, end]\r\n  )\r\n  const result: ActionLog[] = []\r\n  for (let i = 0; i < rows.length; i++) {\r\n    result.push(mapRow(rows[i]))\r\n  }\r\n  return result\r\n}\r\n\r\nexport function getTodayCompletedLogs(): ActionLog[] {\r\n  const start = getDayStartTimestamp()\r\n  const end = start + 86400\r\n  const rows = dbManager.query(\r\n    'SELECT * FROM action_logs WHERE created_at >= ? AND created_at < ? AND result IN (?,?) ORDER BY created_at DESC',\r\n    [start, end, 'completed', 'self_reported']\r\n  )\r\n  const result: ActionLog[] = []\r\n  for (let i = 0; i < rows.length; i++) {\r\n    result.push(mapRow(rows[i]))\r\n  }\r\n  return result\r\n}\r\n\r\nexport function getCompletedLogsByDateAndActions(date: string, actionIds: string[]): ActionLog[] {\r\n  const start = getTimestampFromDate(date)\r\n  const end = start + 86400\r\n  const ids = actionIds.map((id: string): string => \"'\" + id + \"'\").join(',')\r\n  const rows = dbManager.query(\r\n    'SELECT * FROM action_logs WHERE created_at >= ? AND created_at < ? AND result IN (?,?) AND action_id IN (' + ids + ') ORDER BY created_at DESC',\r\n    [start, end, 'completed', 'self_reported']\r\n  )\r\n  const result: ActionLog[] = []\r\n  for (let i = 0; i < rows.length; i++) {\r\n    result.push(mapRow(rows[i]))\r\n  }\r\n  return result\r\n}\r\n\r\nexport function countCompletedByDateAndActions(date: string, actionIds: string[]): number {\r\n  const start = getTimestampFromDate(date)\r\n  const end = start + 86400\r\n  const ids = actionIds.map((id: string): string => \"'\" + id + \"'\").join(',')\r\n  const row = dbManager.queryOne(\r\n    'SELECT COUNT(*) as cnt FROM action_logs WHERE created_at >= ? AND created_at < ? AND result IN (?,?) AND action_id IN (' + ids + ')',\r\n    [start, end, 'completed', 'self_reported']\r\n  )\r\n  return getNum(row, 'cnt')\r\n}\r\n\r\nexport function getTotalCompletedDurationSec(date: string): number {\r\n  const start = getTimestampFromDate(date)\r\n  const end = start + 86400\r\n  const row = dbManager.queryOne(\r\n    'SELECT COALESCE(SUM(duration_ms), 0) as total FROM action_logs WHERE created_at >= ? AND created_at < ? AND result IN (?,?)',\r\n    [start, end, 'completed', 'self_reported']\r\n  )\r\n  return Math.floor(getNum(row, 'total') / 1000)\r\n}\r\n\r\nexport function countCompletedToday(): number {\r\n  const start = getDayStartTimestamp()\r\n  const end = start + 86400\r\n  const row = dbManager.queryOne(\r\n    'SELECT COUNT(*) as cnt FROM action_logs WHERE created_at >= ? AND created_at < ? AND result IN (?,?)',\r\n    [start, end, 'completed', 'self_reported']\r\n  )\r\n  return getNum(row, 'cnt')\r\n}\r\n\r\nexport function countSkippedToday(): number {\r\n  const start = getDayStartTimestamp()\r\n  const end = start + 86400\r\n  const row = dbManager.queryOne(\r\n    'SELECT COUNT(*) as cnt FROM action_logs WHERE created_at >= ? AND created_at < ? AND result = ?',\r\n    [start, end, 'skipped']\r\n  )\r\n  return getNum(row, 'cnt')\r\n}\r\n\r\nexport function getRecentLogs(count: number): ActionLog[] {\r\n  const rows = dbManager.query('SELECT * FROM action_logs ORDER BY created_at DESC LIMIT ?', [count])\r\n  const result: ActionLog[] = []\r\n  for (let i = 0; i < rows.length; i++) {\r\n    result.push(mapRow(rows[i]))\r\n  }\r\n  return result\r\n}\r\n\r\nexport type BarItem = {\r\n  label: string\r\n  value: number\r\n}\r\n\r\nexport function getHourlyCompletionData(date: string): BarItem[] {\r\n  const result: BarItem[] = []\r\n  for (let h = 0; h < 24; h++) {\r\n    const label = (h < 10 ? '0' : '') + h + ':00'\r\n    result.push({ label: label, value: 0 })\r\n  }\r\n\r\n  const rows = dbManager.query(\r\n    'SELECT * FROM action_logs WHERE created_at >= ? AND created_at < ? AND result IN (?,?)',\r\n    [getTimestampFromDate(date), getTimestampFromDate(date) + 86400, 'completed', 'self_reported']\r\n  )\r\n\r\n  for (const row of rows) {\r\n    const created = getNum(row, 'created_at')\r\n    const d = new Date(created)\r\n    const hour = d.getHours()\r\n    result[hour].value = result[hour].value + 1\r\n  }\r\n\r\n  return result\r\n}\r\n\r\nexport function cleanOldData(): void {\r\n  const thirtyDaysAgo = Math.floor(Date.now() / 1000) - 30 * 86400\r\n  dbManager.delete('action_logs', 'created_at < ?', [thirtyDaysAgo])\r\n}\r\n\r\nfunction mapRow(row: Map<string, any>): ActionLog {\r\n  return {\r\n    id: getNum(row, 'id'),\r\n    action_id: getStr(row, 'action_id'),\r\n    action_type: getStr(row, 'action_type'),\r\n    result: getStr(row, 'result') as ActionResult,\r\n    skip_reason: getStrOrNull(row, 'skip_reason'),\r\n    trigger_type: getStr(row, 'trigger_type'),\r\n    trigger_level: getStr(row, 'trigger_level'),\r\n    duration_ms: getNum(row, 'duration_ms'),\r\n    target_ms: getNum(row, 'target_ms'),\r\n    triggered_at: getNum(row, 'triggered_at'),\r\n    completed_at: getNum(row, 'completed_at'),\r\n    created_at: getNum(row, 'created_at')\r\n  }\r\n}\r\n\r\nfunction getDayStartTimestamp(): number {\r\n  const d = new Date()\r\n  return Math.floor(new Date(d.getFullYear(), d.getMonth(), d.getDate()).getTime() / 1000)\r\n}\r\n\r\nfunction getTimestampFromDate(date: string): number {\r\n  const parts = date.split('-')\r\n  return Math.floor(new Date(parseInt(parts[0] as string), parseInt(parts[1] as string) - 1, parseInt(parts[2] as string)).getTime() / 1000)\r\n}\r\n","export type UserAction = 'completed' | 'self_reported' | 'skipped' | 'feedback' | 'ignored' | 'timeout' | 'busy_remind_later'\n\nexport type TriggerLog = {\n  id: number\n  trigger_type: string\n  trigger_level: string\n  app_package: string | null\n  app_category: string | null\n  continuous_minutes: number\n  action_id: string | null\n  user_action: UserAction | null\n  created_at: number\n}\n","import { dbManager, type SqlRow } from './DatabaseManager'\r\nimport { TriggerLog, UserAction } from '../models/TriggerLog'\r\nimport { getNum, getStr, getStrOrNull } from '../utils/DbRowUtils'\r\n\r\nexport function insertTriggerLog(log: TriggerLog): number {\r\n  const row: SqlRow = {\r\n    columns: [\r\n      'trigger_type', 'trigger_level', 'app_package', 'app_category',\r\n      'continuous_minutes', 'action_id', 'user_action', 'created_at'\r\n    ],\r\n    values: [\r\n      log.trigger_type, log.trigger_level, log.app_package, log.app_category,\r\n      log.continuous_minutes, log.action_id, log.user_action, log.created_at\r\n    ]\r\n  }\r\n  return dbManager.insert('trigger_logs', row)\r\n}\r\n\r\nexport function countTriggersByDateAndActionIds(date: string, actionIds: string[]): number {\r\n  const start = getTimestampFromDate(date)\r\n  const end = start + 86400\r\n  const ids = actionIds.map((id: string): string => \"'\" + id + \"'\").join(',')\r\n  const row = dbManager.queryOne(\r\n    'SELECT COUNT(*) as cnt FROM trigger_logs WHERE created_at >= ? AND created_at < ? AND action_id IN (' + ids + ')',\r\n    [start, end]\r\n  )\r\n  return getNum(row, 'cnt')\r\n}\r\n\r\nexport function countTriggersToday(): number {\r\n  const start = getDayStartTimestamp()\r\n  const end = start + 86400\r\n  const row = dbManager.queryOne(\r\n    'SELECT COUNT(*) as cnt FROM trigger_logs WHERE created_at >= ? AND created_at < ?',\r\n    [start, end]\r\n  )\r\n  return getNum(row, 'cnt')\r\n}\r\n\r\nexport function getTodayTriggerLogs(): TriggerLog[] {\r\n  const start = getDayStartTimestamp()\r\n  const end = start + 86400\r\n  const rows = dbManager.query(\r\n    'SELECT * FROM trigger_logs WHERE created_at >= ? AND created_at < ? ORDER BY created_at DESC',\r\n    [start, end]\r\n  )\r\n  const result: TriggerLog[] = []\r\n  for (let i = 0; i < rows.length; i++) {\r\n    result.push(mapRow(rows[i]))\r\n  }\r\n  return result\r\n}\r\n\r\nexport function cleanOldTriggerLogs(): void {\r\n  const thirtyDaysAgo = Math.floor(Date.now() / 1000) - 30 * 86400\r\n  dbManager.delete('trigger_logs', 'created_at < ?', [thirtyDaysAgo])\r\n}\r\n\r\nfunction mapRow(row: Map<string, any>): TriggerLog {\r\n  return {\r\n    id: getNum(row, 'id'),\r\n    trigger_type: getStr(row, 'trigger_type'),\r\n    trigger_level: getStr(row, 'trigger_level'),\r\n    app_package: getStrOrNull(row, 'app_package'),\r\n    app_category: getStrOrNull(row, 'app_category'),\r\n    continuous_minutes: getNum(row, 'continuous_minutes'),\r\n    action_id: getStrOrNull(row, 'action_id'),\r\n    user_action: getStrOrNull(row, 'user_action') as UserAction | null,\r\n    created_at: getNum(row, 'created_at')\r\n  }\r\n}\r\n\r\nfunction getDayStartTimestamp(): number {\r\n  const d = new Date()\r\n  return Math.floor(new Date(d.getFullYear(), d.getMonth(), d.getDate()).getTime() / 1000)\r\n}\r\n\r\nfunction getTimestampFromDate(date: string): number {\r\n  const parts = date.split('-')\r\n  return Math.floor(new Date(parseInt(parts[0] as string), parseInt(parts[1] as string) - 1, parseInt(parts[2] as string)).getTime() / 1000)\r\n}\r\n","export function now(): number {\n  return Date.now()\n}\n\nexport function today(): string {\n  const d = new Date()\n  const y = d.getFullYear()\n  const m = ('' + (d.getMonth() + 1)).padStart(2, '0')\n  const day = ('' + d.getDate()).padStart(2, '0')\n  return y + '-' + m + '-' + day\n}\n\nexport function yesterday(): string {\n  const d = new Date()\n  d.setDate(d.getDate() - 1)\n  const y = d.getFullYear()\n  const m = ('' + (d.getMonth() + 1)).padStart(2, '0')\n  const day = ('' + d.getDate()).padStart(2, '0')\n  return y + '-' + m + '-' + day\n}\n\nexport function daysAgo(n: number): string {\n  const d = new Date()\n  d.setDate(d.getDate() - n)\n  const y = d.getFullYear()\n  const m = ('' + (d.getMonth() + 1)).padStart(2, '0')\n  const day = ('' + d.getDate()).padStart(2, '0')\n  return y + '-' + m + '-' + day\n}\n\nexport function currentHour(): number {\n  return new Date().getHours()\n}\n\nexport function getHour(timestamp: number): number {\n  return new Date(timestamp).getHours()\n}\n\nexport function formatDate(timestamp: number): string {\n  const d = new Date(timestamp)\n  const y = d.getFullYear()\n  const m = ('' + (d.getMonth() + 1)).padStart(2, '0')\n  const day = ('' + d.getDate()).padStart(2, '0')\n  const h = ('' + d.getHours()).padStart(2, '0')\n  const min = ('' + d.getMinutes()).padStart(2, '0')\n  return y + '-' + m + '-' + day + ' ' + h + ':' + min\n}\n\nexport function isInTimeRange(start: string, end: string): boolean {\n  const h = currentHour()\n  const sHour = parseInt(start.split(':')[0] as string)\n  const eHour = parseInt(end.split(':')[0] as string)\n  if (sHour <= eHour) {\n    return h >= sHour && h < eHour\n  }\n  return h >= sHour || h < eHour\n}\n","import { dbManager, type SqlRow } from './DatabaseManager'\nimport { AppUsageSnapshot } from '../models/AppUsageSnapshot'\nimport { today } from '../utils/TimeUtils'\n\nexport type AppUsageItem = {\n  packageName: string\n  appLabel: string\n  foregroundSec: number\n  minutes: number\n}\n\nfunction getNum(row: Map<string, any> | null, col: string): number {\n  if (row == null) return 0\n  const v = row.get(col)\n  if (v == null) return 0\n  return v as number\n}\n\nfunction getStr(row: Map<string, any> | null, col: string): string {\n  if (row == null) return ''\n  const v = row.get(col)\n  if (v == null) return ''\n  return v as string\n}\n\nexport function insertOrUpdateSnapshot(packageName: string, appLabel: string, foregroundSec: number): void {\n  const date = today()\n  const existing = dbManager.queryOne(\n    'SELECT id, total_foreground_sec FROM app_usage_snapshots WHERE date = ? AND package_name = ?',\n    [date, packageName]\n  )\n  if (existing != null) {\n    const prevSec = getNum(existing, 'total_foreground_sec')\n    const nextSec = prevSec + foregroundSec\n    const id = getNum(existing, 'id')\n    const row: SqlRow = {\n      columns: ['total_foreground_sec', 'app_label'],\n      values: [nextSec, appLabel]\n    }\n    dbManager.update('app_usage_snapshots', row, 'id = ?', [id])\n  } else {\n    const row: SqlRow = {\n      columns: ['date', 'package_name', 'app_label', 'total_foreground_sec', 'created_at'],\n      values: [date, packageName, appLabel, foregroundSec, Math.floor(Date.now() / 1000)]\n    }\n    dbManager.insert('app_usage_snapshots', row)\n  }\n}\n\n// 绝对值写入（覆盖已有 total_foreground_sec），用于 doPoll 把 queryUsageStats 聚合数据同步到表\n// 区别于 insertOrUpdateSnapshot 的累加语义\nexport function setSnapshotTotal(packageName: string, appLabel: string, totalSec: number): void {\n  const date = today()\n  const existing = dbManager.queryOne(\n    'SELECT id FROM app_usage_snapshots WHERE date = ? AND package_name = ?',\n    [date, packageName]\n  )\n  if (existing != null) {\n    const id = getNum(existing, 'id')\n    const row: SqlRow = {\n      columns: ['total_foreground_sec', 'app_label'],\n      values: [totalSec, appLabel]\n    }\n    dbManager.update('app_usage_snapshots', row, 'id = ?', [id])\n  } else {\n    const row: SqlRow = {\n      columns: ['date', 'package_name', 'app_label', 'total_foreground_sec', 'created_at'],\n      values: [date, packageName, appLabel, totalSec, Math.floor(Date.now() / 1000)]\n    }\n    dbManager.insert('app_usage_snapshots', row)\n  }\n}\n\nexport function getTodayTotalUsageMinutes(): number {\n  const date = today()\n  const row = dbManager.queryOne(\n    'SELECT COALESCE(SUM(total_foreground_sec), 0) as total FROM app_usage_snapshots WHERE date = ?',\n    [date]\n  )\n  return Math.floor(getNum(row, 'total') / 60)\n}\n\nexport function getTodayTotalUsageSeconds(): number {\n  const date = today()\n  const row = dbManager.queryOne(\n    'SELECT COALESCE(SUM(total_foreground_sec), 0) as total FROM app_usage_snapshots WHERE date = ?',\n    [date]\n  )\n  return getNum(row, 'total')\n}\n\nexport function getTodayAppBreakdown(): AppUsageItem[] {\n  const date = today()\n  const rows = dbManager.query(\n    'SELECT package_name, app_label, total_foreground_sec FROM app_usage_snapshots WHERE date = ? ORDER BY total_foreground_sec DESC',\n    [date]\n  )\n  const result: AppUsageItem[] = []\n  for (let i = 0; i < rows.length; i++) {\n    const r = rows[i]\n    const sec = getNum(r, 'total_foreground_sec')\n    const pkg = getStr(r, 'package_name')\n    const label = getStr(r, 'app_label')\n    if (pkg.length < 1) continue\n    result.push({\n      packageName: pkg,\n      appLabel: label.length > 0 ? label : pkg,\n      foregroundSec: sec,\n      minutes: Math.floor(sec / 60)\n    })\n  }\n  return result\n}\n\nexport function getTop5Apps(): AppUsageItem[] {\n  const all = getTodayAppBreakdown()\n  const r: AppUsageItem[] = []\n  for (let i = 0; i < all.length && i < 5; i++) {\n    r.push(all[i])\n  }\n  return r\n}\n\nexport function cleanOldSnapshots(): void {\n  const thirtyDaysAgo = Math.floor(Date.now() / 1000) - 30 * 86400\n  const thirtyDaysDate = new Date(thirtyDaysAgo * 1000)\n  const y = thirtyDaysDate.getFullYear()\n  const m = ('' + (thirtyDaysDate.getMonth() + 1)).padStart(2, '0')\n  const d = ('' + thirtyDaysDate.getDate()).padStart(2, '0')\n  const cutoff = y + '-' + m + '-' + d\n  dbManager.delete('app_usage_snapshots', 'date < ?', [cutoff])\n}\n","export type DailyCount = {\n  date: string\n  count: number\n}\n","import { dbManager, type SqlRow } from './DatabaseManager'\r\nimport { DailySummary } from '../models/DailySummary'\r\nimport { daysAgo } from '../utils/TimeUtils'\r\nimport { DailyCount } from '../models/DailyCount'\r\nimport { getNum, getStr } from '../utils/DbRowUtils'\r\n\r\nexport function insertOrUpdateSummary(summary: DailySummary): void {\r\n  const existing = dbManager.queryOne('SELECT id FROM daily_summaries WHERE date = ?', [summary.date])\r\n  if (existing != null) {\r\n    const row: SqlRow = {\r\n      columns: [\r\n        'total_completed', 'total_skipped', 'total_duration_sec',\r\n        'eye_score', 'posture_score', 'vitality_score',\r\n        'penetration', 'phone_usage_min', 'guard_minutes', 'guard_count'\r\n      ],\r\n      values: [\r\n        summary.total_completed, summary.total_skipped, summary.total_duration_sec,\r\n        summary.eye_score, summary.posture_score, summary.vitality_score,\r\n        summary.penetration, summary.phone_usage_min, summary.guard_minutes, summary.guard_count\r\n      ]\r\n    }\r\n    dbManager.update('daily_summaries', row, 'date = ?', [summary.date])\r\n  } else {\r\n    const row: SqlRow = {\r\n      columns: [\r\n        'date', 'total_completed', 'total_skipped', 'total_duration_sec',\r\n        'eye_score', 'posture_score', 'vitality_score',\r\n        'penetration', 'phone_usage_min', 'guard_minutes', 'guard_count', 'created_at'\r\n      ],\r\n      values: [\r\n        summary.date, summary.total_completed, summary.total_skipped, summary.total_duration_sec,\r\n        summary.eye_score, summary.posture_score, summary.vitality_score,\r\n        summary.penetration, summary.phone_usage_min, summary.guard_minutes, summary.guard_count, Math.floor(Date.now() / 1000)\r\n      ]\r\n    }\r\n    dbManager.insert('daily_summaries', row)\r\n  }\r\n}\r\n\r\nexport function getRecent28Days(): DailyCount[] {\r\n  const startDate = daysAgo(28)\r\n  const rows = dbManager.query(\r\n    'SELECT date, total_completed as count FROM daily_summaries WHERE date >= ? ORDER BY date ASC',\r\n    [startDate]\r\n  )\r\n  const result: DailyCount[] = []\r\n  for (let i = 0; i < rows.length; i++) {\r\n    const row = rows[i]\r\n    result.push({ date: getStr(row, 'date'), count: getNum(row, 'count') })\r\n  }\r\n  return result\r\n}\r\n\r\nexport function getSummaryByDate(date: string): DailySummary | null {\r\n  const row = dbManager.queryOne('SELECT * FROM daily_summaries WHERE date = ?', [date])\r\n  return row != null ? mapRow(row) : null\r\n}\r\n\r\nfunction mapRow(row: Map<string, any>): DailySummary {\r\n  return {\r\n    id: getNum(row, 'id'),\r\n    date: getStr(row, 'date'),\r\n    total_completed: getNum(row, 'total_completed'),\r\n    total_skipped: getNum(row, 'total_skipped'),\r\n    total_duration_sec: getNum(row, 'total_duration_sec'),\r\n    eye_score: getNum(row, 'eye_score'),\r\n    posture_score: getNum(row, 'posture_score'),\r\n    vitality_score: getNum(row, 'vitality_score'),\r\n    penetration: getNum(row, 'penetration'),\r\n    phone_usage_min: getNum(row, 'phone_usage_min'),\r\n    guard_minutes: getNum(row, 'guard_minutes'),\r\n    guard_count: getNum(row, 'guard_count'),\r\n    created_at: getNum(row, 'created_at')\r\n  }\r\n}\r\n","import { dbManager, type SqlRow } from './DatabaseManager'\r\nimport { getStr } from '../utils/DbRowUtils'\r\n\r\nexport function getSetting(key: string, defaultValue: string = ''): string {\r\n  const row = dbManager.queryOne('SELECT value FROM user_settings WHERE key = ?', [key])\r\n  const v = getStr(row, 'value')\r\n  return v.length > 0 ? v : defaultValue\r\n}\r\n\r\nexport function getInt(key: string, defaultVal: number = 0): number {\r\n  const val = getSetting(key, '' + defaultVal)\r\n  const n = parseInt(val)\r\n  return isNaN(n) ? defaultVal : n\r\n}\r\n\r\nexport function getLong(key: string, defaultVal: number = 0): number {\r\n  return getInt(key, defaultVal)\r\n}\r\n\r\nexport function getFloat(key: string, defaultVal: number = 0): number {\r\n  const val = getSetting(key, '' + defaultVal)\r\n  const n = parseFloat(val)\r\n  return isNaN(n) ? defaultVal : n\r\n}\r\n\r\nexport function getBool(key: string, defaultVal: boolean = false): boolean {\r\n  const val = getSetting(key, defaultVal ? '1' : '0')\r\n  return val == '1' || val == 'true'\r\n}\r\n\r\nexport function putSetting(key: string, value: string): void {\r\n  const now = Math.floor(Date.now() / 1000)\r\n  const existing = dbManager.queryOne('SELECT key FROM user_settings WHERE key = ?', [key])\r\n  if (existing != null) {\r\n    const row: SqlRow = {\r\n      columns: ['value', 'updated_at'],\r\n      values: [value, now]\r\n    }\r\n    dbManager.update('user_settings', row, 'key = ?', [key])\r\n  } else {\r\n    const row: SqlRow = {\r\n      columns: ['key', 'value', 'updated_at'],\r\n      values: [key, value, now]\r\n    }\r\n    dbManager.insert('user_settings', row)\r\n  }\r\n}\r\n\r\nexport function putInt(key: string, value: number): void {\r\n  putSetting(key, '' + value)\r\n}\r\n\r\nexport function putBool(key: string, value: boolean): void {\r\n  putSetting(key, value ? '1' : '0')\r\n}\r\n","export const EYE_ACTION_IDS: string[] = ['eye_blink', 'eye_rotate', 'far_gaze']\nexport const POSTURE_ACTION_IDS: string[] = ['neck_rotate', 'shoulder_roll', 'neck_stretch']\nexport const VITALITY_ACTION_IDS: string[] = ['core_tighten', 'heel_raise', 'deep_breath']\n\nexport function getActionCategory(actionId: string): string {\n  if (EYE_ACTION_IDS.indexOf(actionId) >= 0) return '护眼'\n  if (POSTURE_ACTION_IDS.indexOf(actionId) >= 0) return '体态'\n  if (VITALITY_ACTION_IDS.indexOf(actionId) >= 0) return '活力'\n  return '其他'\n}\n","import { MicroAction } from '../models/MicroAction'\n\nexport const ALL_ACTIONS: MicroAction[] = [\n  {\n    id: 'eye_blink',\n    name: '眨眼休息',\n    category: '护眼',\n    defaultDurationMs: 10000,\n    difficulty: 1,\n    ttsText: '闭上眼睛，1、2、3，感受眼部放松',\n    iconPath: '/static/icons/eye_blink.png'\n  },\n  {\n    id: 'eye_rotate',\n    name: '眼球转动',\n    category: '护眼',\n    defaultDurationMs: 10000,\n    difficulty: 1,\n    ttsText: '眼球缓慢顺时针转一圈，再逆时针转一圈',\n    iconPath: '/static/icons/eye_rotate.png'\n  },\n  {\n    id: 'neck_rotate',\n    name: '颈部转动',\n    category: '肩颈',\n    defaultDurationMs: 15000,\n    difficulty: 1,\n    ttsText: '头缓慢向左转，保持3秒，回正，再向右转',\n    iconPath: '/static/icons/neck_rotate.png'\n  },\n  {\n    id: 'shoulder_roll',\n    name: '绕肩放松',\n    category: '肩颈',\n    defaultDurationMs: 15000,\n    difficulty: 1,\n    ttsText: '双肩向上提起，向后画圈，缓慢放下',\n    iconPath: '/static/icons/shoulder_roll.png'\n  },\n  {\n    id: 'neck_stretch',\n    name: '拉斜方肌',\n    category: '肩颈',\n    defaultDurationMs: 15000,\n    difficulty: 2,\n    ttsText: '右手扶左耳，缓慢向右拉伸，保持5秒',\n    iconPath: '/static/icons/neck_stretch.png'\n  },\n  {\n    id: 'core_tighten',\n    name: '收紧核心',\n    category: '核心',\n    defaultDurationMs: 10000,\n    difficulty: 1,\n    ttsText: '收紧腹部，像被人打了一拳，保持住',\n    iconPath: '/static/icons/core_tighten.png'\n  },\n  {\n    id: 'heel_raise',\n    name: '踮脚拉伸',\n    category: '下肢',\n    defaultDurationMs: 20000,\n    difficulty: 1,\n    ttsText: '双脚与肩同宽，缓慢踮起脚跟，再缓慢放下',\n    iconPath: '/static/icons/heel_raise.png'\n  },\n  {\n    id: 'deep_breath',\n    name: '腹式呼吸',\n    category: '呼吸',\n    defaultDurationMs: 15000,\n    difficulty: 1,\n    ttsText: '鼻子深吸气4秒，肚子鼓起，嘴巴缓慢呼气6秒',\n    iconPath: '/static/icons/deep_breath.png'\n  },\n  {\n    id: 'far_gaze',\n    name: '远眺放松',\n    category: '护眼',\n    defaultDurationMs: 10000,\n    difficulty: 1,\n    ttsText: '看向远处至少6米外，放松眼部肌肉',\n    iconPath: '/static/icons/far_gaze.png'\n  }\n]\n\nexport function getActionById(id: string): MicroAction | null {\n  for (const a of ALL_ACTIONS) {\n    if (a.id === id) return a\n  }\n  return null\n}\n","import { ThreeStatus, StatusLevel } from '../models/ThreeStatus'\nimport { MicroAction } from '../models/MicroAction'\nimport { getTodayCompletedLogs, countCompletedToday, countSkippedToday, BarItem, getHourlyCompletionData, countCompletedByDateAndActions, getTotalCompletedDurationSec } from '../database/ActionLogDao'\nimport { countTriggersToday } from '../database/TriggerLogDao'\nimport { getTodayTotalUsageMinutes } from '../database/AppUsageDao'\nimport { getRecent28Days, insertOrUpdateSummary, getSummaryByDate } from '../database/DailySummaryDao'\nimport { dbManager } from '../database/DatabaseManager'\nimport { getInt } from '../database/SettingsDao'\nimport { EYE_ACTION_IDS, POSTURE_ACTION_IDS, VITALITY_ACTION_IDS } from '../constants/CategoryMapping'\nimport { getActionById } from '../constants/Actions'\nimport { DailyCount } from '../models/DailyCount'\nimport { daysAgo, today, formatDate } from '../utils/TimeUtils'\n\nfunction getTimestampFromDate(date: string): number {\n  const parts = date.split('-')\n  return Math.floor(new Date(parseInt(parts[0] as string), parseInt(parts[1] as string) - 1, parseInt(parts[2] as string)).getTime() / 1000)\n}\n\nfunction countCompletedForDate(date: string): number {\n  const start = getTimestampFromDate(date)\n  const end = start + 86400\n  const row = dbManager.queryOne(\n    'SELECT COUNT(*) as cnt FROM action_logs WHERE created_at >= ? AND created_at < ? AND result IN (?,?)',\n    [start, end, 'completed', 'self_reported']\n  )\n  const rawCnt = row != null ? row.get(\"cnt\") : null\n  return rawCnt != null ? parseFloat('' + rawCnt) : 0\n}\n\nexport function calculateThreeStatus(date: string): ThreeStatus {\n  const target = getTargetCount()\n  const eyeScore = calcCategoryScore(date, EYE_ACTION_IDS, target)\n  const postureScore = calcCategoryScore(date, POSTURE_ACTION_IDS, target)\n  const vitalityScore = calcCategoryScore(date, VITALITY_ACTION_IDS, target)\n\n  return {\n    eyeScore: eyeScore,\n    eyeLevel: getStatusLevel(eyeScore),\n    postureScore: postureScore,\n    postureLevel: getStatusLevel(postureScore),\n    vitalityScore: vitalityScore,\n    vitalityLevel: getStatusLevel(vitalityScore)\n  }\n}\n\nconst DEFAULT_DAILY_TARGET = 3\n\nfunction getTargetCount(): number {\n  const v = getInt('category_target_count', DEFAULT_DAILY_TARGET)\n  if (v < 1) return 1\n  if (v > 20) return 20\n  return v\n}\n\nfunction calcCategoryScore(date: string, actionIds: string[], target: number): number {\n  const count = countCompletedByDateAndActions(date, actionIds)\n  if (count < 1) return -1\n  if (target <= 0) return 0\n  const score = (count / target) * 100\n  if (score > 100) return 100\n  return Math.round(score)\n}\n\nexport function getStatusLevel(score: number): StatusLevel {\n  if (score < 0) return 'no_data'\n  if (score >= 70) return 'good'\n  if (score >= 40) return 'normal'\n  return 'warning'\n}\n\nexport function calcPenetration(date: string): number {\n  const completed = countCompletedToday()\n  const triggered = countTriggersToday()\n  if (triggered < 1) return 0\n  return (completed / triggered) * 10\n}\n\nexport type HomepageData = {\n  eyeScore: number\n  eyeLevel: StatusLevel\n  postureScore: number\n  postureLevel: StatusLevel\n  vitalityScore: number\n  vitalityLevel: StatusLevel\n  guardCount: number\n  penetration: number\n  todayCompletedCount: number\n  heatmapData: DailyCount[]\n  targetCount: number\n}\n\nexport function getHomepageData(date: string): HomepageData {\n  const threeStatus = calculateThreeStatus(date)\n  const guardCount = countCompletedToday()\n  const penetration = calcPenetration(date)\n  const todayCompletedCount = countCompletedToday()\n  const heatmapData = getRecent28Days()\n  const targetCount = getTargetCount()\n\n  return {\n    eyeScore: threeStatus.eyeScore,\n    eyeLevel: threeStatus.eyeLevel,\n    postureScore: threeStatus.postureScore,\n    postureLevel: threeStatus.postureLevel,\n    vitalityScore: threeStatus.vitalityScore,\n    vitalityLevel: threeStatus.vitalityLevel,\n    guardCount: guardCount,\n    penetration: penetration,\n    todayCompletedCount: todayCompletedCount,\n    heatmapData: heatmapData,\n    targetCount: targetCount\n  }\n}\n\nexport function getHourlyData(date: string): BarItem[] {\n  return getHourlyCompletionData(date)\n}\n\ntype WeekCountRow = {\n  date: string\n  count: number\n}\n\nexport function getWeeklyCounts(): WeekCountRow[] {\n  const result: WeekCountRow[] = []\n  for (let i = 6; i >= 0; i--) {\n    const d = daysAgo(i)\n    const summary = getSummaryByDate(d)\n    const cnt = summary != null ? summary.total_completed : countCompletedForDate(d)\n    result.push({ date: d, count: cnt })\n  }\n  return result\n}\n\nexport type LinePoint = {\n  label: string\n  value: number\n}\n\nexport type LineSeries = {\n  name: string\n  color: string\n  points: LinePoint[]\n}\n\nexport function getWeeklyTrend(): LineSeries[] {\n  const rows = getWeeklyCounts()\n  const points: LinePoint[] = []\n  for (const r of rows) {\n    const parts = r.date.split('-')\n    const label = parts[1] + '/' + parts[2]\n    points.push({ label: label, value: r.count })\n  }\n  return [\n    { name: '完成次数', color: '#2ECC71', points: points }\n  ]\n}\n\nexport type ActionDetail = {\n  name: string\n  type: string\n  durationSec: number\n  time: string\n}\n\nexport function getTodayDetail(): ActionDetail[] {\n  const logs = getTodayCompletedLogs()\n  const result: ActionDetail[] = []\n  for (const log of logs) {\n    const action = getActionById(log.action_id)\n    const name = action != null ? action.name : log.action_id\n    const type = action != null ? action.category : log.action_type\n    const durationSec = Math.floor(log.duration_ms / 1000)\n    const d = new Date(log.completed_at)\n    const h = d.getHours()\n    const m = d.getMinutes()\n    const time = (h < 10 ? '0' : '') + h + ':' + (m < 10 ? '0' : '') + m\n    result.push({\n      name: name,\n      type: type,\n      durationSec: durationSec,\n      time: time\n    })\n  }\n  return result\n}\n\nexport function saveTodaySummary(): void {\n  const date = today()\n  const threeStatus = calculateThreeStatus(date)\n  const completed = countCompletedToday()\n  insertOrUpdateSummary({\n    id: 0,\n    date: date,\n    total_completed: completed,\n    total_skipped: countSkippedToday(),\n    total_duration_sec: getTotalCompletedDurationSec(date),\n    eye_score: Math.max(0, Math.round(threeStatus.eyeScore)),\n    posture_score: Math.max(0, Math.round(threeStatus.postureScore)),\n    vitality_score: Math.max(0, Math.round(threeStatus.vitalityScore)),\n    penetration: calcPenetration(date),\n    phone_usage_min: getTodayTotalUsageMinutes(),\n    guard_minutes: 0,\n    guard_count: completed,\n    created_at: Math.floor(Date.now() / 1000)\n  })\n}\n","import { EffectiveTriggerRule, TimeWindow, ScreenConditions, TriggerLevel } from './EffectiveTriggerRule'\n\n// 持久化格式：与 effective_rules 表一一对应\nexport type PersistedEffectiveRule = {\n  id: number\n  actionId: string\n  appPackages: string[]\n  timeWindow: TimeWindow | null\n  timeThresholdMinutes: number\n  triggerLevel: TriggerLevel\n  categoryFilter: string | null\n  source: 'user' | 'llm' | 'system'\n  sourceHistoryId: number | null\n  expiresAt: number | null\n  enabled: boolean\n  priority: number\n  createdAt: number\n  updatedAt: number\n}\n\nexport function toEffectiveTriggerRule(p: PersistedEffectiveRule): EffectiveTriggerRule {\n  const screenConditions: ScreenConditions = {\n    appPackages: p.appPackages,\n    includeHome: p.appPackages.length < 1\n  }\n  const rule: EffectiveTriggerRule = {\n    id: p.id,\n    actionId: p.actionId,\n    timeWindow: p.timeWindow,\n    screenConditions: screenConditions,\n    timeThresholdMinutes: p.timeThresholdMinutes,\n    source: p.source,\n    enabled: p.enabled,\n    createdAt: p.createdAt\n  }\n  return rule\n}\n","import { dbManager, type SqlRow } from './DatabaseManager'\nimport { PersistedEffectiveRule } from '../models/PersistedEffectiveRule'\nimport { TimeWindow, TriggerLevel } from '../models/EffectiveTriggerRule'\nimport { getNum, getStr, getStrOrNull } from '../utils/DbRowUtils'\n\nfunction mapRow(row: Map<string, any>): PersistedEffectiveRule {\n  const pkgJson = getStr(row, 'app_packages_json')\n  let appPackages: string[] = []\n  if (pkgJson.length > 0) {\n    try {\n      const parsed = JSON.parse(pkgJson) as Array<any>\n      if (parsed != null) {\n        const tmp: string[] = []\n        for (let i = 0; i < parsed.length; i++) {\n          const v = parsed[i]\n          if (typeof v === 'string' && (v as string).length > 0) {\n            tmp.push(v as string)\n          }\n        }\n        appPackages = tmp\n      }\n    } catch (_) {\n      appPackages = []\n    }\n  }\n  const twJson = getStrOrNull(row, 'time_window_json')\n  let timeWindow: TimeWindow | null = null\n  if (twJson != null && twJson.length > 0) {\n    try {\n      const obj = JSON.parse(twJson) as UTSJSONObject\n      if (obj != null) {\n        const start = obj['start'] as string\n        const end = obj['end'] as string\n        if (start != null && end != null && start.length > 0 && end.length > 0) {\n          timeWindow = { start: start, end: end }\n        }\n      }\n    } catch (_) {\n      timeWindow = null\n    }\n  }\n  const srcStr = getStr(row, 'source')\n  const source: 'user' | 'llm' | 'system' = srcStr == 'llm' ? 'llm' : (srcStr == 'system' ? 'system' : 'user')\n  return {\n    id: getNum(row, 'id'),\n    actionId: getStr(row, 'action_id'),\n    appPackages: appPackages,\n    timeWindow: timeWindow,\n    timeThresholdMinutes: getNum(row, 'time_threshold_minutes'),\n    triggerLevel: getStr(row, 'trigger_level') as TriggerLevel,\n    categoryFilter: getStrOrNull(row, 'category_filter'),\n    source: source,\n    sourceHistoryId: getStrOrNull(row, 'source_history_id') == null || getStr(row, 'source_history_id').length < 1 ? null : getNum(row, 'source_history_id'),\n    expiresAt: getStrOrNull(row, 'expires_at') == null || getStr(row, 'expires_at').length < 1 ? null : getNum(row, 'expires_at'),\n    enabled: getNum(row, 'enabled') == 1,\n    priority: getNum(row, 'priority'),\n    createdAt: getNum(row, 'created_at'),\n    updatedAt: getNum(row, 'updated_at')\n  }\n}\n\nexport function insertRule(rule: PersistedEffectiveRule): number {\n  const pkgJson = JSON.stringify(rule.appPackages)\n  const twJson = rule.timeWindow == null ? null : JSON.stringify(rule.timeWindow)\n  const row: SqlRow = {\n    columns: [\n      'action_id', 'app_packages_json', 'time_window_json',\n      'time_threshold_minutes', 'trigger_level', 'category_filter',\n      'source', 'source_history_id', 'expires_at',\n      'enabled', 'priority', 'created_at', 'updated_at'\n    ],\n    values: [\n      rule.actionId, pkgJson, twJson,\n      rule.timeThresholdMinutes, rule.triggerLevel, rule.categoryFilter,\n      rule.source, rule.sourceHistoryId, rule.expiresAt,\n      rule.enabled ? 1 : 0, rule.priority, rule.createdAt, rule.updatedAt\n    ]\n  }\n  return dbManager.insert('effective_rules', row)\n}\n\nexport function updateRule(rule: PersistedEffectiveRule): void {\n  const pkgJson = JSON.stringify(rule.appPackages)\n  const twJson = rule.timeWindow == null ? null : JSON.stringify(rule.timeWindow)\n  const row: SqlRow = {\n    columns: [\n      'action_id', 'app_packages_json', 'time_window_json',\n      'time_threshold_minutes', 'trigger_level', 'category_filter',\n      'source', 'source_history_id', 'expires_at',\n      'enabled', 'priority', 'updated_at'\n    ],\n    values: [\n      rule.actionId, pkgJson, twJson,\n      rule.timeThresholdMinutes, rule.triggerLevel, rule.categoryFilter,\n      rule.source, rule.sourceHistoryId, rule.expiresAt,\n      rule.enabled ? 1 : 0, rule.priority, rule.updatedAt\n    ]\n  }\n  dbManager.update('effective_rules', row, 'id = ?', [rule.id])\n}\n\nexport function deleteRule(id: number): void {\n  dbManager.delete('effective_rules', 'id = ?', [id])\n}\n\nexport function setEnabled(id: number, enabled: boolean): void {\n  const now = Math.floor(Date.now() / 1000)\n  const row: SqlRow = {\n    columns: ['enabled', 'updated_at'],\n    values: [enabled ? 1 : 0, now]\n  }\n  dbManager.update('effective_rules', row, 'id = ?', [id])\n}\n\nexport function getActiveRules(): PersistedEffectiveRule[] {\n  const rows = dbManager.query('SELECT * FROM effective_rules WHERE enabled = 1 ORDER BY priority DESC, time_threshold_minutes ASC')\n  const result: PersistedEffectiveRule[] = []\n  for (let i = 0; i < rows.length; i++) {\n    const r = rows[i]\n    if (r == null) continue\n    result.push(mapRow(r))\n  }\n  return result\n}\n\nexport function getById(id: number): PersistedEffectiveRule | null {\n  const row = dbManager.queryOne('SELECT * FROM effective_rules WHERE id = ?', [id])\n  if (row == null) return null\n  return mapRow(row)\n}\n\nexport function getRulesByApp(pkg: string): PersistedEffectiveRule[] {\n  const all = getActiveRules()\n  const result: PersistedEffectiveRule[] = []\n  for (let i = 0; i < all.length; i++) {\n    const r = all[i]\n    if (r.appPackages.indexOf(pkg) >= 0) {\n      result.push(r)\n    }\n  }\n  return result\n}\n\nexport function disableAll(): void {\n  const now = Math.floor(Date.now() / 1000)\n  const row: SqlRow = {\n    columns: ['enabled', 'updated_at'],\n    values: [0, now]\n  }\n  dbManager.update('effective_rules', row, 'enabled = 1', [])\n}\n","// 系统应用包名识别 + 用户黑名单判断\n// 用于在触发链路（UsageStats 轮询 / AppCategory 入册 / TriggerEngine / EffectiveRuleEngine）\n// 各处统一拦截 com.android.launcher 等系统包，避免弹窗污染和 LLM 误分类\n\n// 系统应用包名前缀（命中任一前缀即视为系统包）\nconst SYSTEM_PKG_PREFIXES: string[] = [\n  'com.android.',\n  'com.google.android.',\n  'android.',\n  'com.miui.',\n  'com.huawei.',\n  'com.samsung.',\n  'com.oppo.',\n  'com.vivo.',\n  'com.oneplus.',\n  'com.sec.',\n  'com.qualcomm.',\n  'com.qti.',\n  'com.mediatek.',\n  'com.lenovo.',\n  'com.zte.',\n  'com.meizu.',\n  'com.nubia.',\n  'com.letv.',\n  'com.sonymobile.',\n  'com.motorola.',\n  'com.lge.'\n]\n\n// 已知系统包名（精确匹配，覆盖框架/launcher/dialer 等不带 com.android. 前缀的）\nconst SYSTEM_PKG_EXACT: string[] = [\n  'android',\n  'com.android.launcher',\n  'com.android.launcher2',\n  'com.android.launcher3',\n  'com.android.settings',\n  'com.android.systemui',\n  'com.android.dialer',\n  'com.android.phone',\n  'com.android.contacts',\n  'com.android.camera',\n  'com.android.gallery',\n  'com.android.music',\n  'com.android.email',\n  'com.android.browser',\n  'com.android.calendar',\n  'com.android.clock',\n  'com.android.deskclock',\n  'com.android.documentsui',\n  'com.android.downloads',\n  'com.android.inputmethod.latin',\n  'com.android.keyguard',\n  'com.android.location.fused',\n  'com.android.nfc',\n  'com.android.providers',\n  'com.android.server',\n  'com.android.shell',\n  'com.android.sms',\n  'com.android.soundrecorder',\n  'com.android.vending',\n  'com.android.webview',\n  'com.android.wifi',\n  'com.android.providers.media',\n  'com.android.providers.telephony',\n  'com.android.providers.calendar',\n  'com.android.providers.contacts'\n]\n\n/**\n * 判断包名是否为系统应用（应被排除在触发名单外）\n */\nexport function isSystemPackage(pkg: string): boolean {\n  if (pkg.length < 1) return true\n  if (pkg == 'android') return true\n  for (let i = 0; i < SYSTEM_PKG_EXACT.length; i++) {\n    if (pkg == SYSTEM_PKG_EXACT[i]) return true\n  }\n  for (let i = 0; i < SYSTEM_PKG_PREFIXES.length; i++) {\n    if (pkg.indexOf(SYSTEM_PKG_PREFIXES[i]) == 0) return true\n  }\n  return false\n}\n\n/**\n * 判断包名是否为应用自身（避免触发自身的后台服务）\n */\nexport function isSelfPackage(pkg: string, selfPkg: string): boolean {\n  if (selfPkg.length < 1) return false\n  return pkg == selfPkg\n}\n\n/**\n * 综合过滤判定：系统包 OR 自身\n * 用户自定义黑名单（app_blacklist 设置项）由各调用方在自身服务内读取，不在此处耦合\n */\nexport function shouldFilterPackage(pkg: string, selfPkg: string): boolean {\n  return isSystemPackage(pkg) || isSelfPackage(pkg, selfPkg)\n}\n","import { MicroAction } from '../models/MicroAction'\nimport { ALL_ACTIONS, getActionById as getCachedAction } from '../constants/Actions'\nimport { getSetting, putSetting } from '../database/SettingsDao'\nimport { currentHour } from '../utils/TimeUtils'\n\nconst DISABLED_ACTIONS_KEY = 'disabled_action_ids'\n\nexport function getEnabledActions(): MicroAction[] {\n  const disabledStr = getSetting(DISABLED_ACTIONS_KEY, '[]')\n  let disabledIds: string[] = []\n  try {\n    disabledIds = JSON.parse(disabledStr) as string[]\n  } catch (_) {}\n  return ALL_ACTIONS.filter(a => disabledIds.indexOf(a.id) < 0)\n}\n\nexport function getActionById(id: string): MicroAction | null {\n  return getCachedAction(id)\n}\n\nexport function isSuitableForContext(action: MicroAction, triggerType: string): boolean {\n  const hour = currentHour()\n  if (hour >= 22 || hour < 7) {\n    if (action.category === '核心') return false\n  }\n  return true\n}\n\nexport function toggleActionEnabled(id: string, enabled: boolean): void {\n  const disabledStr = getSetting(DISABLED_ACTIONS_KEY, '[]')\n  let disabledIds: string[] = []\n  try {\n    disabledIds = JSON.parse(disabledStr) as string[]\n  } catch (_) {}\n  const idx = disabledIds.indexOf(id)\n  if (enabled && idx >= 0) {\n    disabledIds.splice(idx, 1)\n  } else if (!enabled && idx < 0) {\n    disabledIds.push(id)\n  }\n  putSetting(DISABLED_ACTIONS_KEY, JSON.stringify(disabledIds))\n}\n","import { MicroAction } from '../models/MicroAction'\nimport { getEnabledActions, isSuitableForContext } from './ActionManager'\nimport { getInt, putInt } from '../database/SettingsDao'\n\ntype FrequencyState = {\n  skipCount: number\n  reductionRatio: number\n  reducedAt: number\n  recoveryDeadline: number\n}\n\ntype AdjustmentChanges = {\n  thresholdMinutes?: number\n  actionWeightsDelta?: Map<string, number>\n}\n\nconst frequencyReducer: Map<string, FrequencyState> = new Map<string, FrequencyState>()\nconst actionWeights: Map<string, number> = new Map<string, number>()\n\nexport function onConsecutiveSkip(actionType: string): void {\n  const state = getOrCreateState(actionType)\n  state.skipCount++\n\n  if (state.skipCount >= 3) {\n    state.reductionRatio = Math.max(0.125, state.reductionRatio * 0.5)\n    state.reducedAt = Date.now()\n    state.recoveryDeadline = Date.now() + 24 * 3600 * 1000\n    state.skipCount = 0\n  }\n}\n\nexport function onCompleted(actionType: string): void {\n  const state = frequencyReducer.get(actionType)\n  if (state == null) return\n  state.skipCount = 0\n  if (state.reductionRatio < 1.0) {\n    state.reductionRatio = Math.min(1.0, state.reductionRatio * 2)\n  }\n}\n\nexport function isFrequencyReduced(actionType: string): boolean {\n  const state = frequencyReducer.get(actionType)\n  if (state == null) return false\n  if (state.reductionRatio >= 1.0) return false\n  if (Date.now() >= state.recoveryDeadline) {\n    state.reductionRatio = 1.0\n    return false\n  }\n  return Math.random() >= state.reductionRatio\n}\n\nexport function selectAction(triggerType: string): string | null {\n  const enabled = getEnabledActions()\n  __f__('log','at services/RuleEngine.uts:54','[RuleEngine] selectAction: enabled.length=' + enabled.length + ' triggerType=' + triggerType)\n  if (enabled.length < 1) {\n    __f__('log','at services/RuleEngine.uts:56','[RuleEngine] selectAction: no enabled actions')\n    return null\n  }\n\n  const candidates = enabled.filter((a: MicroAction): boolean => isSuitableForContext(a, triggerType))\n  __f__('log','at services/RuleEngine.uts:61','[RuleEngine] selectAction: candidates.length=' + candidates.length)\n  if (candidates.length < 1) return enabled[0].id\n\n  return weightedRandomSelect(candidates)\n}\n\nfunction weightedRandomSelect(actions: MicroAction[]): string {\n  const weights: number[] = actions.map(a => {\n    const w = actionWeights.get(a.id)\n    if (w != null) { return w }\n    return 1.0\n  })\n  const totalWeight = weights.reduce((sum, w) => sum + w, 0)\n  let r = Math.random() * totalWeight\n  for (let i = 0; i < actions.length; i++) {\n    r -= weights[i]\n    if (r <= 0) return actions[i].id\n  }\n  return actions[actions.length - 1].id\n}\n\nexport function applyAdjustments(changes: AdjustmentChanges): void {\n  if (changes.thresholdMinutes != null) {\n    putInt('app_duration_threshold', changes.thresholdMinutes)\n  }\n  if (changes.actionWeightsDelta != null) {\n    changes.actionWeightsDelta.forEach((val, key) : void => {\n      actionWeights.set(key, val)\n    })\n  }\n}\n\nexport function exportRules(): any {\n  return {\n    thresholdMinutes: getInt('app_duration_threshold', 60),\n    actionWeights: actionWeights,\n    reductionStates: frequencyReducer\n  }\n}\n\nfunction getOrCreateState(actionType: string): FrequencyState {\n  if (frequencyReducer.get(actionType) == null) {\n    const state: FrequencyState = { skipCount: 0, reductionRatio: 1.0, reducedAt: 0, recoveryDeadline: 0 }\n    frequencyReducer.set(actionType, state)\n  }\n  return frequencyReducer.get(actionType)!\n}\n","import { getInt, putInt } from '../database/SettingsDao'\r\n\r\nconst NORMAL_INTERVAL_MS = 60 * 60 * 1000\r\nconst NEWBIE_INTERVAL_MS = 120 * 60 * 1000\r\n\r\nexport function isNewbie(): boolean {\r\n  const newbieMode = getInt('newbie_mode', 1)\r\n  if (newbieMode < 1) return false\r\n  const startDate = getInt('newbie_start_date', 0)\r\n  if (startDate < 1) return false\r\n  const daysSince = Math.floor((Date.now() - startDate) / (24 * 3600 * 1000))\r\n  return daysSince < 3\r\n}\r\n\r\nexport function getMinTriggerIntervalMs(): number {\r\n  return isNewbie() ? NEWBIE_INTERVAL_MS : NORMAL_INTERVAL_MS\r\n}\r\n\r\nexport function getNewbieTriggerLevel(originalLevel: string): string {\r\n  return 'gentle'\r\n}\r\n\r\nexport function checkGraduation(): void {\r\n  const startDate = getInt('newbie_start_date', 0)\r\n  const daysSince = Math.floor((Date.now() - startDate) / (24 * 3600 * 1000))\r\n  if (daysSince >= 3 && getInt('newbie_mode', 1) == 1) {\r\n    putInt('newbie_mode', 0)\r\n  }\r\n}\r\n","import { TriggerLog } from '../models/TriggerLog'\r\nimport { selectAction, isFrequencyReduced, onConsecutiveSkip, onCompleted } from './RuleEngine'\r\nimport { isNewbie, getMinTriggerIntervalMs, getNewbieTriggerLevel } from './NewbieGuard'\r\nimport { insertTriggerLog } from '../database/TriggerLogDao'\r\nimport { insertActionLog } from '../database/ActionLogDao'\r\nimport { getInt, getBool, getSetting as getSettingVal } from '../database/SettingsDao'\r\nimport { getActionById } from '../constants/Actions'\r\nimport { isInTimeRange, now } from '../utils/TimeUtils'\r\nimport { evaluate as evaluateRule, EffectiveRuleMatch } from './EffectiveRuleEngine'\r\nimport { PersistedEffectiveRule } from '../models/PersistedEffectiveRule'\r\nimport { MicroAction } from '../models/MicroAction'\r\nimport { isSystemPackage } from '../utils/SystemAppUtils'\r\n\r\nexport enum TriggerState {\r\n  IDLE,\r\n  SHOWING,\r\n  EXECUTING,\r\n  COMPLETING,\r\n  COOLING_DOWN\r\n}\r\n\r\nexport type TriggerContext = {\r\n  appPackage: string\r\n  appLabel: string\r\n  appCategory?: string\r\n  continuousMinutes: number\r\n  triggerType: string\r\n}\r\n\r\nexport type TriggerDecision = {\r\n  actionId: string\r\n  triggerLevel: string\r\n  triggerType: string\r\n  durationMs: number\r\n  ttsText: string\r\n  actionName: string\r\n  matchedRuleId: number\r\n  matchedRuleSource: string\r\n}\r\n\r\nlet currentState: TriggerState = TriggerState.IDLE\r\nlet lastTriggerTime: number = 0\r\nconst COOL_DOWN_MS: number = 5 * 60 * 1000\r\n\r\nexport function shouldTrigger(context: TriggerContext): TriggerDecision | null {\r\n  if (currentState !== TriggerState.IDLE) {\r\n    __f__('log','at services/TriggerEngine.uts:47','[TriggerEngine] skip: state=' + currentState)\r\n    return null\r\n  }\r\n\r\n  const nowMs = Date.now()\r\n  if (nowMs - lastTriggerTime < COOL_DOWN_MS) {\r\n    __f__('log','at services/TriggerEngine.uts:53','[TriggerEngine] skip: cooldown remaining=' + (COOL_DOWN_MS - (nowMs - lastTriggerTime)))\r\n    return null\r\n  }\r\n\r\n  let dndOk = false\r\n  try { dndOk = isInDndPeriod() } catch (e) { __f__('warn','at services/TriggerEngine.uts:58','[TriggerEngine] isInDndPeriod: ' + e) }\r\n  if (dndOk) return null\r\n\r\n  // 系统包二次保险：即使 UsageStatsForegroundService 已过滤，TriggerEngine 也要独立拦截\r\n  if (isSystemPackage(context.appPackage)) return null\r\n\r\n  let blacklisted = false\r\n  try { blacklisted = isBlacklisted(context.appPackage) } catch (e) { __f__('warn','at services/TriggerEngine.uts:65','[TriggerEngine] isBlacklisted: ' + e) }\r\n  if (blacklisted) return null\r\n\r\n  if (isNewbie()) {\r\n    const minInterval = getMinTriggerIntervalMs()\r\n    if (nowMs - lastTriggerTime < minInterval) return null\r\n  }\r\n\r\n  if (isFrequencyReduced(context.triggerType)) return null\r\n\r\n  let match: EffectiveRuleMatch | null = null\r\n  try { match = evaluateRule(context) } catch (e) { __f__('warn','at services/TriggerEngine.uts:76','[TriggerEngine] evaluateRule: ' + e) }\r\n  let action: MicroAction | null = null\r\n  let ruleSource: string = 'system'\r\n  if (match != null) {\r\n    ruleSource = match.rule.source\r\n    if (match.action == null || match.rule.actionId.length < 1) {\r\n      let fallbackId: string | null = null\r\n      try { fallbackId = selectAction(context.triggerType) } catch (e) { __f__('warn','at services/TriggerEngine.uts:83','[TriggerEngine] selectAction: ' + e) }\r\n      if (fallbackId == null) return null\r\n      action = getActionById(fallbackId)\r\n    } else {\r\n      action = match.action\r\n    }\r\n  } else {\r\n    let fallbackId: string | null = null\r\n    try { fallbackId = selectAction(context.triggerType) } catch (e) { __f__('warn','at services/TriggerEngine.uts:91','[TriggerEngine] selectAction fallback: ' + e) }\r\n    if (fallbackId == null) return null\r\n    action = getActionById(fallbackId)\r\n    if (action == null) return null\r\n  }\r\n  if (action == null) return null\r\n\r\n  let triggerLevel = decideTriggerLevel(context)\r\n  if (isNewbie()) {\r\n    triggerLevel = getNewbieTriggerLevel(triggerLevel)\r\n  }\r\n  if (match == null) {\r\n    triggerLevel = 'gentle'\r\n  }\r\n\r\n  currentState = TriggerState.SHOWING\r\n  lastTriggerTime = nowMs\r\n\r\n  const triggerLog: TriggerLog = {\r\n    id: 0,\r\n    trigger_type: context.triggerType,\r\n    trigger_level: match != null ? match.level : 'gentle',\r\n    app_package: context.appPackage,\r\n    app_category: context.appCategory != null ? context.appCategory : null,\r\n    continuous_minutes: context.continuousMinutes,\r\n    action_id: action.id,\r\n    user_action: null,\r\n    created_at: Math.floor(nowMs / 1000)\r\n  }\r\n  insertTriggerLog(triggerLog)\r\n\r\n  return {\r\n    actionId: action.id,\r\n    triggerLevel: match != null ? match.level : 'gentle',\r\n    triggerType: context.triggerType,\r\n    durationMs: action.defaultDurationMs,\r\n    ttsText: action.ttsText,\r\n    actionName: action.name,\r\n    matchedRuleId: match != null ? match.rule.id : 0,\r\n    matchedRuleSource: ruleSource\r\n  }\r\n}\r\n\r\nexport function onUserAccepted(): void {\r\n  currentState = TriggerState.EXECUTING\r\n}\r\n\r\nexport function onActionResolved(): void {\r\n  currentState = TriggerState.COOLING_DOWN\r\n  scheduleCooldownEnd()\r\n}\r\n\r\nexport function forceIdle(): void {\r\n  currentState = TriggerState.IDLE\r\n  lastTriggerTime = 0\r\n}\r\n\r\nfunction scheduleCooldownEnd(): void {\r\n  scheduleTimer(() : void => {\r\n    if (currentState === TriggerState.COOLING_DOWN) {\r\n      currentState = TriggerState.IDLE\r\n    }\r\n  }, COOL_DOWN_MS)\r\n}\r\n\r\nfunction isInDndPeriod(): boolean {\r\n  const enabled = getBool('dnd_enabled', true)\r\n  if (!enabled) return false\r\n  const start = getSettingVal('dnd_start', '22:00')\r\n  const end = getSettingVal('dnd_end', '07:00')\r\n  return isInTimeRange(start, end)\r\n}\r\n\r\nfunction isBlacklisted(packageName: string): boolean {\r\n  const listStr = getSettingVal('app_blacklist', '[]')\r\n  try {\r\n    const list = JSON.parse(listStr) as string[]\r\n    return list.indexOf(packageName) >= 0\r\n  } catch (_) {\r\n    return false\r\n  }\r\n}\r\n\r\nfunction decideTriggerLevel(context: TriggerContext): string {\r\n  if (context.continuousMinutes >= 120) return 'strong'\r\n  if (context.continuousMinutes >= 90) return 'strong'\r\n  return 'gentle'\r\n}\r\n\r\nfunction scheduleTimer(fn: () => void, ms: number): void {\r\n  setTimeout(fn, ms)\r\n}\r\n","import { getActiveRules } from '../database/EffectiveRuleDao'\nimport { getActionById } from '../constants/Actions'\nimport { TriggerContext } from './TriggerEngine'\nimport { isInTimeRange } from '../utils/TimeUtils'\nimport { PersistedEffectiveRule } from '../models/PersistedEffectiveRule'\nimport { MicroAction } from '../models/MicroAction'\nimport { isSystemPackage } from '../utils/SystemAppUtils'\n\nexport type EffectiveRuleMatch = {\n  rule: PersistedEffectiveRule\n  action: MicroAction | null\n  level: 'gentle' | 'strong' | 'forced'\n}\n\nexport function evaluate(ctx: TriggerContext): EffectiveRuleMatch | null {\n  // 系统包兜底：通用规则（appPackages 为空）也会无差别匹配所有包，\n  // 即使 TriggerEngine 已过滤，这里也要再挡一次，防止直接调用 evaluate 的旁路污染\n  if (isSystemPackage(ctx.appPackage)) return null\n\n  let candidates: PersistedEffectiveRule[] = []\n  const all = getActiveRules()\n  __f__('log','at services/EffectiveRuleEngine.uts:22','[EffectiveRuleEngine] all rules=' + all.length + ' pkg=' + ctx.appPackage + ' mins=' + ctx.continuousMinutes)\n  const nowSec = Math.floor(Date.now() / 1000)\n  for (let i = 0; i < all.length; i++) {\n    const r = all[i]\n    if (!r.enabled) continue\n    if (r.expiresAt != null && r.expiresAt > 0 && nowSec > r.expiresAt) continue\n    if (r.appPackages.length > 0 && r.appPackages.indexOf(ctx.appPackage) < 0) continue\n    if (r.timeWindow != null && !isInTimeRange(r.timeWindow.start, r.timeWindow.end)) continue\n    if (r.timeThresholdMinutes > 0 && ctx.continuousMinutes < r.timeThresholdMinutes) continue\n    candidates.push(r)\n  }\n  __f__('log','at services/EffectiveRuleEngine.uts:33','[EffectiveRuleEngine] candidates=' + candidates.length)\n  if (candidates.length < 1) return null\n  // 优先级排序：LLM > system/user；同 source 时更短时间段优先；同时间段时更多 app 指定优先\n  let best = candidates[0]\n  for (let i = 1; i < candidates.length; i++) {\n    const c = candidates[i]\n    const bIsLlm = best.source == 'llm'\n    const cIsLlm = c.source == 'llm'\n    if (cIsLlm && !bIsLlm) {\n      best = c\n      continue\n    }\n    if (!cIsLlm && bIsLlm) {\n      continue\n    }\n    // 同 source：时间段更短（更具体）优先\n    const bHasTw = best.timeWindow != null\n    const cHasTw = c.timeWindow != null\n    if (cHasTw && !bHasTw) {\n      best = c\n      continue\n    }\n    if (!cHasTw && bHasTw) {\n      continue\n    }\n    // 同时间段：指定了 app（更具体）优先\n    const bHasApp = best.appPackages.length > 0\n    const cHasApp = c.appPackages.length > 0\n    if (cHasApp && !bHasApp) {\n      best = c\n      continue\n    }\n    if (!cHasApp && bHasApp) {\n      continue\n    }\n    // 同等具体度：更短阈值优先\n    if (c.timeThresholdMinutes < best.timeThresholdMinutes) {\n      best = c\n    }\n  }\n  const action = getActionById(best.actionId)\n  return {\n    rule: best,\n    action: action,\n    level: best.triggerLevel\n  }\n}\n","export const ENCOURAGE_GENERAL: string[] = [\n  '又完成一次，身体在偷偷感谢你',\n  '很好，继续保持',\n  '微习惯的力量',\n  '身体记住了你的每一次善意',\n  '小小的动作，大大地关爱自己',\n  '你比刚才健康了一点点',\n  '积少成多，你懂的',\n  '健康就是这么攒出来的',\n  '这一刻，你选择了自己',\n  '完美，继续加油'\n]\n\nexport const ENCOURAGE_EYE: string[] = [\n  '眼睛说谢谢',\n  '给眼睛放了个小假',\n  '目光如炬，但你休息了一下',\n  '眼睛刚刚充了个电',\n  '明眸亮眼，就靠这几十秒'\n]\n\nexport const ENCOURAGE_NECK: string[] = [\n  '颈椎在鼓掌',\n  '肩膀松了一口气',\n  '脖子表示很满意',\n  '肩颈自由了那么一瞬间'\n]\n\nexport const ENCOURAGE_BREATH: string[] = [\n  '呼吸之间，找回平静',\n  '一口气的事，但身体很受用',\n  '深呼吸，世界慢了半拍',\n  '肺部刚刚做了个按摩'\n]\n\nexport const STREAK_TEXTS: string[] = [\n  '连续第 {n} 次！',\n  '你已经连续 {n} 次了，这就是习惯',\n  '连续 {n} 次坚持，了不起',\n  '第 {n} 次，数都数不过来了'\n]\n\nexport function getRandomEncourage(category: string): string {\n  let pool: string[]\n  if (category === '护眼') {\n    pool = ENCOURAGE_GENERAL.concat(ENCOURAGE_EYE)\n  } else if (category === '肩颈') {\n    pool = ENCOURAGE_GENERAL.concat(ENCOURAGE_NECK)\n  } else if (category === '呼吸') {\n    pool = ENCOURAGE_GENERAL.concat(ENCOURAGE_BREATH)\n  } else {\n    pool = ENCOURAGE_GENERAL\n  }\n  const idx = Math.floor(Math.random() * pool.length)\n  return pool[idx]\n}\n","export function shortVibrate(times: number = 1): void {\r\n  // Current HBuilderX 5.07 uni-app x compiler does not expose uni vibration APIs.\r\n  // Keep this as a no-op so callers do not need platform guards.\r\n  if (times < 1) return\r\n}\r\n\r\nexport function longVibrate(): void {\r\n  // See shortVibrate.\r\n}\r\n","export type TtsCache = {\n  text_hash: string\n  text_content: string\n  file_path: string\n  file_size: number\n  source: string\n  created_at: number\n}\n","import { dbManager, type SqlRow } from './DatabaseManager'\r\nimport { TtsCache } from '../models/TtsCache'\r\nimport { getNum, getStr } from '../utils/DbRowUtils'\r\n\r\nexport function getByHash(hash: string): TtsCache | null {\r\n  const row = dbManager.queryOne('SELECT * FROM tts_cache WHERE text_hash = ?', [hash])\r\n  if (row == null) return null\r\n  return mapRow(row)\r\n}\r\n\r\nexport function save(textHash: string, textContent: string, filePath: string, fileSize: number, source: string): void {\r\n  const row: SqlRow = {\r\n    columns: ['text_hash', 'text_content', 'file_path', 'file_size', 'source', 'created_at'],\r\n    values: [textHash, textContent, filePath, fileSize, source, Math.floor(Date.now() / 1000)]\r\n  }\r\n  dbManager.insert('tts_cache', row)\r\n}\r\n\r\nfunction mapRow(row: Map<string, any>): TtsCache {\r\n  return {\r\n    text_hash: getStr(row, 'text_hash'),\r\n    text_content: getStr(row, 'text_content'),\r\n    file_path: getStr(row, 'file_path'),\r\n    file_size: getNum(row, 'file_size'),\r\n    source: getStr(row, 'source'),\r\n    created_at: getNum(row, 'created_at')\r\n  }\r\n}\r\n","export type LlmCache = {\n  cache_key: string\n  cache_type: string\n  response: string\n  model: string\n  created_at: number\n  expires_at: number\n}\n","import { dbManager } from './DatabaseManager'\nimport { LlmCache } from '../models/LlmCache'\nimport { getNum, getStr } from '../utils/DbRowUtils'\n\nexport function getByKey(key: string): LlmCache | null {\n  const row = dbManager.queryOne('SELECT * FROM llm_cache WHERE cache_key = ?', [key])\n  if (row == null) return null\n  return mapRow(row)\n}\n\nexport function save(key: string, type: string, response: string, expiresAt: number): void {\n  dbManager.execSql(\n    'INSERT OR REPLACE INTO llm_cache (cache_key, cache_type, response, expires_at, created_at) VALUES (?,?,?,?,?)',\n    [key, type, response, expiresAt, Math.floor(Date.now() / 1000)]\n  )\n}\n\nexport function cleanExpired(): void {\n  dbManager.delete('llm_cache', 'expires_at < ?', [Math.floor(Date.now() / 1000)])\n}\n\nfunction mapRow(row: Map<string, any>): LlmCache {\n  return {\n    cache_key: getStr(row, 'cache_key'),\n    cache_type: getStr(row, 'cache_type'),\n    response: getStr(row, 'response'),\n    model: getStr(row, 'model'),\n    created_at: getNum(row, 'created_at'),\n    expires_at: getNum(row, 'expires_at')\n  }\n}\n","export function md5(text: string): string {\n  let hash = 0\n  for (let i = 0; i < text.length; i++) {\n    const ch = text.charCodeAt(i)\n    hash = ((hash << 5) - hash) + ch\n    hash |= 0\n  }\n  return Math.abs(hash).toString(16).padStart(8, '0')\n}\n\n// FNV-1a 32bit hash，用于 TTS 文本缓存键\nexport function textHash(text: string): string {\n  let hash: number = 2166136261\n  for (let i = 0; i < text.length; i++) {\n    const code = text.charCodeAt(i) as number\n    hash = (hash ^ code) * 16777619\n    hash = hash & 0xFFFFFFFF\n  }\n  return (hash >>> 0).toString(16).padStart(8, '0')\n}\n","import { getInt, getBool } from '../database/SettingsDao'\nimport { currentHour } from '../utils/TimeUtils'\nimport { speakSystemTts as pluginSpeakSystemTts } from '../uni_modules/uts-audio-player/utssdk/app-android/index'\nimport { play as pluginPlayFile, type AudioPlayerCallbacks } from '../uni_modules/uts-audio-player/utssdk/app-android/AudioPlayer.uts'\nimport { getByHash as getTtsCacheByHash, save as saveTtsCache } from '../database/TtsCacheDao'\nimport { callMinimaxTts, downloadTtsAudio } from './CloudService'\nimport { textHash } from '../utils/HashUtils'\nimport { ALL_ACTIONS } from '../constants/Actions'\nimport { FALLBACK_ADHOC_TEXTS } from '../constants/LlmPrompts'\n\ntype AdhocContext = {\n  appLabel: string\n  continuousMinutes: number\n  hour: number\n}\n\nexport function speakAdhocOpen(context: AdhocContext): void {\n  if (isSystemMuted()) return\n  const volume = getAdjustedVolume()\n  playFallbackIntro(volume)\n}\n\nexport function speakAdhoc(text: string): void {\n  if (isSystemMuted()) return\n  if (text.length < 1) return\n  const hash: string = textHash(text)\n  try {\n    const cached = getTtsCacheByHash(hash)\n    if (cached != null && cached.file_path.length > 0) {\n      const fp: string = cached.file_path\n      playLocalAudio(fp, (): void => {})\n      return\n    }\n  } catch (e) {\n    const msg = e != null ? ('' + e) : 'null'\n    __f__('warn','at services/TtsService.uts:36','[TtsService] speakAdhoc 查缓存失败: ' + msg)\n  }\n  const textCopy: string = text\n  const hashCopy: string = hash\n  callMinimaxTts(text,\n    (url: string): void => {\n      downloadTtsAudio(url, hashCopy,\n        (localPath: string): void => {\n          playLocalAudio(localPath, (): void => {})\n        },\n        (errMsg: string): void => {\n          __f__('warn','at services/TtsService.uts:47','[TtsService] speakAdhoc download 失败: ' + errMsg)\n          fallbackSystemTts(textCopy)\n        }\n      )\n    },\n    (errMsg: string): void => {\n      __f__('warn','at services/TtsService.uts:53','[TtsService] speakAdhoc tts 失败: ' + errMsg)\n      fallbackSystemTts(textCopy)\n    }\n  )\n}\n\nexport function speakFixedGuide(text: string): void {\n  if (isSystemMuted()) return\n  const vol = getAdjustedVolume()\n  try { pluginSpeakSystemTts(text, vol) } catch (e) {\n    __f__('warn','at services/TtsService.uts:63','[TtsService] speakFixedGuide plugin 调用失败: ' + JSON.stringify(e))\n  }\n}\n\n// 启动期预热：把 ALL_ACTIONS 的 ttsText + FALLBACK_ADHOC_TEXTS 全部生成并落盘\n// 限并发 3；已有缓存跳过；不阻塞启动\nexport function preGenerateAll(): void {\n  try {\n    const texts: string[] = []\n    for (let i = 0; i < ALL_ACTIONS.length; i++) {\n      const a = ALL_ACTIONS[i]\n      if (a != null && a.ttsText.length > 0) {\n        texts.push(a.ttsText)\n      }\n    }\n    for (let j = 0; j < FALLBACK_ADHOC_TEXTS.length; j++) {\n      const t = FALLBACK_ADHOC_TEXTS[j]\n      if (t != null && t.length > 0) {\n        texts.push(t)\n      }\n    }\n    if (texts.length < 1) return\n    const MAX_CONCURRENT: number = 3\n    const total: number = texts.length\n    let running: number = 0\n    let cursor: number = 0\n    let doneCount: number = 0\n    function tryStart(): void {\n      while (running < MAX_CONCURRENT && cursor < texts.length) {\n        const idx: number = cursor\n        cursor++\n        const t: string | null = texts[idx]\n        if (t == null) continue\n        const tHash: string = textHash(t)\n        let skip: boolean = false\n        try {\n          if (getTtsCacheByHash(tHash) != null) {\n            skip = true\n          }\n        } catch (_) {}\n        if (skip) {\n          doneCount++\n          continue\n        }\n        running++\n        callMinimaxTts(t,\n          (url: string): void => {\n            downloadTtsAudio(url, tHash,\n              (_local: string): void => {\n                running--\n                doneCount++\n                __f__('log','at services/TtsService.uts:114','[TtsService] preGenerateAll 进度 ' + doneCount + '/' + total)\n                tryStart()\n              },\n              (errMsg: string): void => {\n                running--\n                doneCount++\n                __f__('warn','at services/TtsService.uts:120','[TtsService] preGenerateAll download 失败: ' + errMsg)\n                tryStart()\n              }\n            )\n          },\n          (errMsg: string): void => {\n            running--\n            doneCount++\n            __f__('warn','at services/TtsService.uts:128','[TtsService] preGenerateAll tts 失败: ' + errMsg)\n            tryStart()\n          }\n        )\n      }\n    }\n    tryStart()\n  } catch (e) {\n    const msg = e != null ? ('' + e) : 'null'\n    __f__('warn','at services/TtsService.uts:137','[TtsService] preGenerateAll 整体异常: ' + msg)\n  }\n}\n\n// 启动期预热：触发一次空文本 SystemTts 让引擎初始化（不出声，仅 init）\nexport function prewarmSystemTts(): void {\n  try { pluginSpeakSystemTts('', 0) } catch (e) {\n    const msg = e != null ? ('' + e) : 'null'\n    __f__('warn','at services/TtsService.uts:145','[TtsService] prewarmSystemTts 失败: ' + msg)\n  }\n}\n\nfunction playLocalAudio(filePath: string, onEnd: () => void): void {\n  try {\n    const cbs: AudioPlayerCallbacks = {\n      onCompletion: (): void => { onEnd() },\n      onError: (err): void => {\n        const msg = err != null ? ('' + err) : 'null'\n        __f__('warn','at services/TtsService.uts:155','[TtsService] playLocalAudio onError: ' + msg)\n      },\n      onProgress: (_cur, _total): void => {}\n    }\n    pluginPlayFile(filePath, cbs)\n  } catch (e) {\n    const msg = e != null ? ('' + e) : 'null'\n    __f__('warn','at services/TtsService.uts:162','[TtsService] playLocalAudio 失败: ' + msg)\n  }\n}\n\nfunction fallbackSystemTts(text: string): void {\n  try { pluginSpeakSystemTts(text, getAdjustedVolume()) } catch (e) {\n    const msg = e != null ? ('' + e) : 'null'\n    __f__('warn','at services/TtsService.uts:169','[TtsService] fallbackSystemTts 失败: ' + msg)\n  }\n}\n\nfunction playFallbackIntro(volume: number): void {\n  const intros = [\n    '该起来动动了——',\n    '休息一下，来——',\n    '你的身体发来一条提醒——'\n  ]\n  const idx = Math.floor(Math.random() * intros.length)\n  try { pluginSpeakSystemTts(intros[idx] as string, volume) } catch (e) {\n    __f__('warn','at services/TtsService.uts:181','[TtsService] playFallbackIntro plugin 调用失败: ' + JSON.stringify(e))\n  }\n}\n\nfunction getAdjustedVolume(): number {\n  let vol: number = getInt('tts_volume', 70) / 100\n  if (isNightTime()) vol *= 0.5\n  return vol\n}\n\nfunction isNightTime(): boolean {\n  const h = currentHour()\n  return h >= 22 || h < 7\n}\n\nfunction isSystemMuted(): boolean {\n  return !getBool('tts_enabled', true)\n}\n","// 公共服务类型定义\n\nexport type AppForegroundInfo = {\n  packageName: string\n  startTime: number\n  continuousMs: number\n}\n\nexport type UsageStatEntry = {\n  packageName: string\n  totalTimeInForeground: number\n  lastTimeUsed: number\n}\n\nexport type UsageMonitorCallbacks = {\n  onAppSwitch: (fromPkg: string, toPkg: string) => void\n  onAppDurationTrigger: (info: AppForegroundInfo) => void\n  onUsageTick: (pkg: string, deltaSec: number) => void\n  onTimePeriodTrigger: (periodName: string) => void\n  onDayRollover: (oldDate: string, newDate: string) => void\n  onPermissionMissing: () => void\n}\n","import { dbManager, type SqlRow } from './DatabaseManager'\r\nimport { HeartbeatLog } from '../models/HeartbeatLog'\r\nimport { getNum, getStr } from '../utils/DbRowUtils'\r\n\r\nexport function insertHeartbeat(status: string): void {\r\n  const row: SqlRow = {\r\n    columns: ['service_status', 'timestamp'],\r\n    values: [status, Date.now()]\r\n  }\r\n  dbManager.insert('heartbeat_logs', row)\r\n}\r\n\r\nexport function getRecentHeartbeats(limit: number): HeartbeatLog[] {\r\n  const rows = dbManager.query('SELECT * FROM heartbeat_logs ORDER BY timestamp DESC LIMIT ?', [limit])\r\n  const result: HeartbeatLog[] = []\r\n  for (let i = 0; i < rows.length; i++) {\r\n    const row = rows[i]\r\n    const item: HeartbeatLog = {\r\n      id: getNum(row, 'id'),\r\n      service_status: getStr(row, 'service_status'),\r\n      timestamp: getNum(row, 'timestamp')\r\n    }\r\n    result.push(item)\r\n  }\r\n  return result\r\n}\r\n\r\nexport function cleanOldHeartbeats(): void {\r\n  const sevenDaysAgo = Date.now() - 7 * 86400000\r\n  dbManager.delete('heartbeat_logs', 'timestamp < ?', [sevenDaysAgo])\r\n}\r\n","let pendingActionId: string = ''\r\nlet pendingAdhocText: string = ''\r\n\r\nexport function setActionIdForNextPage(id: string): void {\r\n  pendingActionId = id\r\n}\r\n\r\nexport function takeActionId(): string {\r\n  const id = pendingActionId\r\n  pendingActionId = ''\r\n  return id\r\n}\r\n\r\nexport function setAdhocForNextPage(text: string): void {\r\n  pendingAdhocText = text\r\n}\r\n\r\nexport function takeAdhocText(): string {\r\n  const t = pendingAdhocText\r\n  pendingAdhocText = ''\r\n  return t\r\n}\r\n","import { EffectiveTriggerRule } from './EffectiveTriggerRule'\n\nexport type LlmHistoryStage = 'pre' | 'post'\n\nexport type ParsedLlmResult = {\n  adhocText?: string\n  stateDescription?: string\n  suggestedRule?: EffectiveTriggerRule\n  reasoning?: string\n  decision?: string\n  targetRuleId?: number\n  confidence?: number\n  alternatives?: Array<any>\n}\n\nexport type LlmHistoryEntry = {\n  id: number\n  stage: LlmHistoryStage\n  contextJson: string\n  aiRawResponse: string\n  parsedResult: ParsedLlmResult\n  adhocText: string | null\n  suggestedRule: EffectiveTriggerRule | null\n  reasoning: string | null\n  decision: string | null\n  targetRuleId: number | null\n  userAccepted: number | null\n  confidence: number\n  createdAt: number\n}\n","import { dbManager, type SqlRow } from './DatabaseManager'\nimport { LlmHistoryEntry, LlmHistoryStage, ParsedLlmResult } from '../models/LlmHistoryEntry'\nimport { EffectiveTriggerRule } from '../models/EffectiveTriggerRule'\nimport { getNum, getStr, getStrOrNull } from '../utils/DbRowUtils'\n\nexport type LlmAcceptanceRate = {\n  total: number\n  accepted: number\n  rejected: number\n  pending: number\n}\n\nfunction mapRow(row: Map<string, any>): LlmHistoryEntry {\n  const parsedJson = getStr(row, 'parsed_result_json')\n  let parsed: ParsedLlmResult = {}\n  if (parsedJson != null && parsedJson.length > 0) {\n    try {\n      const p = JSON.parse(parsedJson)\n      if (p != null) parsed = p as ParsedLlmResult\n    } catch (_) {\n      parsed = {}\n    }\n  }\n  const ruleJson = getStrOrNull(row, 'suggested_rule_json')\n  let rule: EffectiveTriggerRule | null = null\n  if (ruleJson != null && ruleJson.length > 0) {\n    try {\n      const r = JSON.parse(ruleJson)\n      if (r != null) rule = r as EffectiveTriggerRule\n    } catch (_) {\n      rule = null\n    }\n  }\n  const targetRaw = row.get('target_rule_id')\n  const targetRuleId: number | null = targetRaw == null ? null : getNum(row, 'target_rule_id')\n  const acceptedRaw = row.get('user_accepted')\n  const userAccepted: number | null = acceptedRaw == null ? null : getNum(row, 'user_accepted')\n  return {\n    id: getNum(row, 'id'),\n    stage: getStr(row, 'stage') as LlmHistoryStage,\n    contextJson: getStr(row, 'context_json'),\n    aiRawResponse: getStr(row, 'ai_raw_response'),\n    parsedResult: parsed,\n    adhocText: getStrOrNull(row, 'adhoc_text'),\n    suggestedRule: rule,\n    reasoning: getStrOrNull(row, 'reasoning'),\n    decision: getStrOrNull(row, 'decision'),\n    targetRuleId: targetRuleId,\n    userAccepted: userAccepted,\n    confidence: getNum(row, 'confidence'),\n    createdAt: getNum(row, 'created_at')\n  }\n}\n\nfunction mapRows(rows: Map<string, any>[]): LlmHistoryEntry[] {\n  const result: LlmHistoryEntry[] = []\n  for (let i = 0; i < rows.length; i++) {\n    const r = rows[i]\n    if (r == null) continue\n    try {\n      result.push(mapRow(r))\n    } catch (e) {\n      __f__('warn','at database/LlmHistoryDao.uts:63','[LlmHistoryDao] mapRow skip dirty row, err: ' + JSON.stringify(e))\n    }\n  }\n  return result\n}\n\nexport function insertHistory(\n  stage: LlmHistoryStage,\n  contextJson: string,\n  aiRawResponse: string,\n  parsedResult: ParsedLlmResult,\n  adhocText: string | null,\n  suggestedRule: EffectiveTriggerRule | null,\n  reasoning: string | null,\n  confidence: number = 0,\n  decision: string | null = null,\n  targetRuleId: number | null = null,\n  userAccepted: number | null = null,\n  alternativesJson: string | null = null\n): number {\n  const createdAt = Math.floor(Date.now() / 1000)\n  const parsedJson = JSON.stringify(parsedResult)\n  const ruleJson = suggestedRule == null ? null : JSON.stringify(suggestedRule)\n  const row: SqlRow = {\n    columns: [\n      'stage', 'context_json', 'ai_raw_response', 'parsed_result_json',\n      'adhoc_text', 'suggested_rule_json', 'reasoning',\n      'confidence', 'decision', 'target_rule_id', 'user_accepted', 'alternatives_json',\n      'created_at'\n    ],\n    values: [\n      stage, contextJson, aiRawResponse, parsedJson,\n      adhocText, ruleJson, reasoning,\n      confidence, decision, targetRuleId, userAccepted, alternativesJson,\n      createdAt\n    ]\n  }\n  return dbManager.insert('llm_history', row)\n}\n\nexport function updateUserAccepted(historyId: number, accepted: number): void {\n  const row: SqlRow = {\n    columns: ['user_accepted'],\n    values: [accepted]\n  }\n  dbManager.update('llm_history', row, 'id = ?', [historyId])\n}\n\nexport function getAllHistory(limit: number): LlmHistoryEntry[] {\n  const rows = dbManager.query(\n    'SELECT * FROM llm_history ORDER BY created_at DESC LIMIT ?',\n    [limit]\n  )\n  return mapRows(rows)\n}\n\nexport function getHistoryByStage(stage: LlmHistoryStage, limit: number): LlmHistoryEntry[] {\n  const rows = dbManager.query(\n    'SELECT * FROM llm_history WHERE stage = ? ORDER BY created_at DESC LIMIT ?',\n    [stage, limit]\n  )\n  return mapRows(rows)\n}\n\nexport function getRecentDecisions(limit: number): LlmHistoryEntry[] {\n  const rows = dbManager.query(\n    \"SELECT * FROM llm_history WHERE stage = 'post' AND decision IS NOT NULL ORDER BY created_at DESC LIMIT ?\",\n    [limit]\n  )\n  return mapRows(rows)\n}\n\nexport function getPendingRuleReviews(limit: number): LlmHistoryEntry[] {\n  const rows = dbManager.query(\n    \"SELECT * FROM llm_history WHERE stage = 'post' AND decision IN ('create_rule','modify_rule','delete_rule') AND user_accepted IS NULL ORDER BY created_at DESC LIMIT ?\",\n    [limit]\n  )\n  return mapRows(rows)\n}\n\nexport function existsRejectedByRule(targetRuleId: number, decision: string): boolean {\n  const row = dbManager.queryOne(\n    \"SELECT id FROM llm_history WHERE target_rule_id = ? AND decision = ? AND user_accepted = 0 LIMIT 1\",\n    [targetRuleId, decision]\n  )\n  return row != null\n}\n\nexport function getAcceptanceRate(days: number): LlmAcceptanceRate {\n  const cutoff = Math.floor(Date.now() / 1000) - days * 86400\n  const totalRow = dbManager.queryOne(\n    \"SELECT COUNT(*) as cnt FROM llm_history WHERE stage = 'post' AND created_at >= ? AND decision IS NOT NULL AND decision != 'no_change'\",\n    [cutoff]\n  )\n  const acceptedRow = dbManager.queryOne(\n    \"SELECT COUNT(*) as cnt FROM llm_history WHERE stage = 'post' AND created_at >= ? AND user_accepted = 1\",\n    [cutoff]\n  )\n  const rejectedRow = dbManager.queryOne(\n    \"SELECT COUNT(*) as cnt FROM llm_history WHERE stage = 'post' AND created_at >= ? AND user_accepted = 0\",\n    [cutoff]\n  )\n  const pendingRow = dbManager.queryOne(\n    \"SELECT COUNT(*) as cnt FROM llm_history WHERE stage = 'post' AND created_at >= ? AND user_accepted IS NULL AND decision IS NOT NULL AND decision != 'no_change'\",\n    [cutoff]\n  )\n  return {\n    total: getNum(totalRow, 'cnt'),\n    accepted: getNum(acceptedRow, 'cnt'),\n    rejected: getNum(rejectedRow, 'cnt'),\n    pending: getNum(pendingRow, 'cnt')\n  }\n}\n\nexport function cleanOldHistory(daysKeep: number): void {\n  const cutoff = Math.floor(Date.now() / 1000) - daysKeep * 86400\n  dbManager.delete('llm_history', 'created_at < ?', [cutoff])\n}\n","import { existsRejectedByRule, updateUserAccepted } from '../database/LlmHistoryDao'\n\nexport function hasBeenRejected(targetRuleId: number, decision: string): boolean {\n  if (targetRuleId < 1) return false\n  try {\n    return existsRejectedByRule(targetRuleId, decision)\n  } catch (e) {\n    __f__('warn','at services/LlmRejectTracker.uts:8','[LlmRejectTracker] hasBeenRejected 异常: ' + JSON.stringify(e))\n    return false\n  }\n}\n\nexport function markAccepted(historyId: number): void {\n  try {\n    updateUserAccepted(historyId, 1)\n  } catch (e) {\n    __f__('warn','at services/LlmRejectTracker.uts:17','[LlmRejectTracker] markAccepted 失败: ' + JSON.stringify(e))\n  }\n}\n\nexport function markRejected(historyId: number): void {\n  try {\n    updateUserAccepted(historyId, 0)\n  } catch (e) {\n    __f__('warn','at services/LlmRejectTracker.uts:25','[LlmRejectTracker] markRejected 失败: ' + JSON.stringify(e))\n  }\n}\n","import { callLlmEvaluate } from './CloudService'\nimport { insertHistory as insertLlmHistory } from '../database/LlmHistoryDao'\nimport { insertRule as insertEffectiveRule, updateRule as updateEffectiveRule, deleteRule as deleteEffectiveRule } from '../database/EffectiveRuleDao'\nimport { EffectiveTriggerRule, TimeWindow, ScreenConditions, TriggerLevel } from '../models/EffectiveTriggerRule'\nimport { PersistedEffectiveRule } from '../models/PersistedEffectiveRule'\nimport { ParsedLlmResult, LlmHistoryStage } from '../models/LlmHistoryEntry'\nimport {\n  PreTriggerContext,\n  PostActionContext,\n  getFallbackAdhoc\n} from '../constants/LlmPrompts'\nimport { hasBeenRejected } from './LlmRejectTracker'\n\nexport type PreTriggerResult = {\n  adhocText: string\n  stateDescription: string\n  fallback: boolean\n}\n\nexport type PostActionResult = {\n  suggestedRule: EffectiveTriggerRule | null\n  decision: string\n  reasoning: string\n  confidence: number\n  alternatives: string\n  historyId: number\n  fallback: boolean\n}\n\nlet preContextCache: PreTriggerContext | null = null\nlet postContextCache: PostActionContext | null = null\n\nexport function setPreContext(ctx: PreTriggerContext): void {\n  preContextCache = ctx\n}\n\nexport function getPreContext(): PreTriggerContext | null {\n  return preContextCache\n}\n\nexport function clearPreContext(): void {\n  preContextCache = null\n}\n\nexport function setPostContext(ctx: PostActionContext): void {\n  postContextCache = ctx\n}\n\nexport function clearPostContext(): void {\n  postContextCache = null\n}\n\n// 把内存态 EffectiveTriggerRule 转为持久化形态（落库前必走）\nexport function fromEffectiveTriggerRule(rule: EffectiveTriggerRule): PersistedEffectiveRule {\n  let pkgList: string[] = []\n  if (rule.screenConditions != null) {\n    pkgList = rule.screenConditions.appPackages\n  }\n  const nowSec = Math.floor(Date.now() / 1000)\n  return {\n    id: rule.id,\n    actionId: rule.actionId,\n    appPackages: pkgList,\n    timeWindow: rule.timeWindow,\n    timeThresholdMinutes: rule.timeThresholdMinutes,\n    // 后续可按 rule.screenConditions.includeHome 区分 'gentle' / 'normal'，当前统一 gentle 避免误触\n    triggerLevel: 'gentle',\n    categoryFilter: rule.categoryFilter,\n    source: rule.source == 'local' ? 'user' : rule.source,\n    sourceHistoryId: null,\n    expiresAt: null,\n    enabled: rule.enabled,\n    priority: 5,\n    createdAt: rule.createdAt > 0 ? rule.createdAt : nowSec,\n    updatedAt: nowSec\n  }\n}\n\nexport function evaluatePre(\n  onReady: (result: PreTriggerResult) => void,\n  onFail: () => void\n): void {\n  __f__('log','at services/LlmTriggerFlow.uts:83','[LlmFlow] evaluatePre 开始')\n  const ctx = preContextCache\n  if (ctx == null) {\n    __f__('warn','at services/LlmTriggerFlow.uts:86','[LlmFlow] evaluatePre: preContextCache 为空')\n    onFail()\n    return\n  }\n  const contextJson = JSON.stringify(ctx)\n  __f__('log','at services/LlmTriggerFlow.uts:91','[LlmFlow] evaluatePre 上下文长度: ' + contextJson.length)\n  try {\n    __f__('log','at services/LlmTriggerFlow.uts:93','[LlmFlow] evaluatePre 调用 callLlmEvaluate pre')\n    callLlmEvaluate(\n      'pre',\n      ctx,\n      (raw: string): void => {\n        __f__('log','at services/LlmTriggerFlow.uts:98','[LlmFlow] evaluatePre LLM 返回 raw 长度: ' + raw.length)\n        try {\n          const parsed = parsePreResponse(raw)\n          __f__('log','at services/LlmTriggerFlow.uts:101','[LlmFlow] evaluatePre parsePreResult adhocText=' + (parsed.adhocText != null ? parsed.adhocText.substring(0, 30) : 'null'))\n          const adhoc = parsed.adhocText != null ? parsed.adhocText : getFallbackAdhoc()\n          const stateDesc = parsed.stateDescription != null ? parsed.stateDescription : '检测到需要休息'\n          try {\n            insertLlmHistory('pre', contextJson, raw, parsed, adhoc, null, stateDesc)\n          } catch (e) {\n            __f__('warn','at services/LlmTriggerFlow.uts:107','[LlmTriggerFlow] 写 pre history 失败: ' + JSON.stringify(e))\n          }\n          const result: PreTriggerResult = {\n            adhocText: adhoc,\n            stateDescription: stateDesc,\n            fallback: false\n          }\n          onReady(result)\n        } catch (e) {\n          __f__('warn','at services/LlmTriggerFlow.uts:116','[LlmTriggerFlow] pre parse 失败: ' + JSON.stringify(e))\n          const fallback: PreTriggerResult = buildFallbackPre()\n          try {\n            insertLlmHistory('pre', contextJson, raw, {}, fallback.adhocText, null, fallback.stateDescription)\n          } catch (_) {}\n          onReady(fallback)\n        }\n      },\n      (): void => {\n        __f__('warn','at services/LlmTriggerFlow.uts:125','[LlmFlow] evaluatePre LLM 请求失败，使用 fallback')\n        const fallback: PreTriggerResult = buildFallbackPre()\n        try {\n          insertLlmHistory('pre', contextJson, '', {}, fallback.adhocText, null, fallback.stateDescription)\n        } catch (_) {}\n        onReady(fallback)\n      }\n    )\n  } catch (e) {\n    __f__('warn','at services/LlmTriggerFlow.uts:134','[LlmTriggerFlow] pre 异常: ' + JSON.stringify(e))\n    onFail()\n  }\n}\n\nexport function evaluatePost(\n  actionId: string,\n  actionName: string,\n  actionCategory: string,\n  durationMs: number,\n  onReady: (result: PostActionResult) => void,\n  onFail: () => void\n): void {\n  if (postContextCache == null) {\n    onFail()\n    return\n  }\n  const ctx = postContextCache\n  if (ctx == null) {\n    onFail()\n    return\n  }\n  const enriched: PostActionContext = {\n    actionId: actionId,\n    actionName: actionName,\n    actionCategory: actionCategory,\n    durationMs: durationMs,\n    originalContext: ctx.originalContext,\n    todayCompletedCount: ctx.todayCompletedCount,\n    guardMinutes: ctx.guardMinutes,\n    todaySkipCount: ctx.todaySkipCount,\n    recentActions: ctx.recentActions,\n    appHistory: ctx.appHistory,\n    currentRules: ctx.currentRules,\n    userPreference: ctx.userPreference,\n    lastWeekSameTime: ctx.lastWeekSameTime\n  }\n  const contextJson = JSON.stringify(enriched)\n  try {\n    callLlmEvaluate(\n      'post',\n      enriched,\n      (raw: string): void => {\n        try {\n          const parsed = parsePostResponse(raw)\n          const decision = parsed.decision != null ? parsed.decision : 'no_change'\n          const rule = parsed.suggestedRule != null ? parsed.suggestedRule : null\n          const reasoning = parsed.reasoning != null ? parsed.reasoning : ''\n          const confidence = parsed.confidence != null ? parsed.confidence : 0\n          const alternatives = parsed.alternatives != null ? JSON.stringify(parsed.alternatives) : ''\n          let finalDecision = decision\n          let finalRule = rule\n          if (decision == 'modify_rule' || decision == 'delete_rule') {\n            if (parsed.targetRuleId != null && parsed.targetRuleId > 0) {\n              if (hasBeenRejected(parsed.targetRuleId, decision)) {\n                finalDecision = 'no_change'\n                finalRule = null\n              }\n            }\n          }\n          let historyId = 0\n          try {\n            historyId = insertLlmHistory(\n              'post',\n              contextJson,\n              raw,\n              parsed,\n              null,\n              finalRule,\n              reasoning,\n              confidence,\n              finalDecision,\n              parsed.targetRuleId != null ? parsed.targetRuleId : null,\n              null,\n              alternatives\n            )\n          } catch (e) {\n            __f__('warn','at services/LlmTriggerFlow.uts:211','[LlmTriggerFlow] 写 post history 失败: ' + JSON.stringify(e))\n          }\n          // 把 LLM 建议真写入 effective_rules（评估链路闭环）\n          try {\n            const targetId = parsed.targetRuleId != null ? parsed.targetRuleId : 0\n            if (finalDecision == 'create_rule' && finalRule != null) {\n              const persisted = fromEffectiveTriggerRule(finalRule)\n              persisted.sourceHistoryId = historyId\n              insertEffectiveRule(persisted)\n              __f__('log','at services/LlmTriggerFlow.uts:220','[LlmFlow] create_rule 已落库 actionId=' + finalRule.actionId)\n            } else if (finalDecision == 'modify_rule' && finalRule != null && targetId > 0) {\n              const persisted = fromEffectiveTriggerRule(finalRule)\n              persisted.id = targetId\n              persisted.sourceHistoryId = historyId\n              updateEffectiveRule(persisted)\n              __f__('log','at services/LlmTriggerFlow.uts:226','[LlmFlow] modify_rule 已落库 id=' + targetId)\n            } else if (finalDecision == 'delete_rule' && targetId > 0) {\n              deleteEffectiveRule(targetId)\n              __f__('log','at services/LlmTriggerFlow.uts:229','[LlmFlow] delete_rule 已落库 id=' + targetId)\n            }\n          } catch (e) {\n            __f__('warn','at services/LlmTriggerFlow.uts:232','[LlmFlow] apply rule fail: ' + JSON.stringify(e))\n          }\n          const result: PostActionResult = {\n            suggestedRule: finalRule,\n            decision: finalDecision,\n            reasoning: reasoning,\n            confidence: confidence,\n            alternatives: alternatives,\n            historyId: historyId,\n            fallback: false\n          }\n          onReady(result)\n        } catch (e) {\n          __f__('warn','at services/LlmTriggerFlow.uts:245','[LlmTriggerFlow] post parse 失败: ' + JSON.stringify(e))\n          let hid = 0\n          try {\n            hid = insertLlmHistory('post', contextJson, raw, {}, null, null, '', 0, null, null, null, null)\n          } catch (_) {}\n          const result: PostActionResult = {\n            suggestedRule: null,\n            decision: 'no_change',\n            reasoning: '',\n            confidence: 0,\n            alternatives: '',\n            historyId: hid,\n            fallback: true\n          }\n          onReady(result)\n        }\n      },\n      (): void => {\n        let hid = 0\n        try {\n          hid = insertLlmHistory('post', contextJson, '', {}, null, null, '', 0, null, null, null, null)\n        } catch (_) {}\n        const result: PostActionResult = {\n          suggestedRule: null,\n          decision: 'no_change',\n          reasoning: '',\n          confidence: 0,\n          alternatives: '',\n          historyId: hid,\n          fallback: true\n        }\n        onReady(result)\n      }\n    )\n  } catch (e) {\n    __f__('warn','at services/LlmTriggerFlow.uts:280','[LlmTriggerFlow] post 异常: ' + JSON.stringify(e))\n    onFail()\n  }\n}\n\nfunction buildFallbackPre(): PreTriggerResult {\n  return {\n    adhocText: getFallbackAdhoc(),\n    stateDescription: '检测到需要休息',\n    fallback: true\n  }\n}\n\nfunction parsePreResponse(raw: string): ParsedLlmResult {\n  const obj = parseJsonThreeLevels(raw)\n  const result: ParsedLlmResult = {}\n  if (obj == null) return result\n  const adhoc = obj['adhocText']\n  if (typeof adhoc === 'string' && (adhoc as string).length > 0) {\n    result.adhocText = adhoc as string\n  }\n  const stateDesc = obj['stateDescription']\n  if (typeof stateDesc === 'string' && (stateDesc as string).length > 0) {\n    result.stateDescription = stateDesc as string\n  }\n  return result\n}\n\nfunction parsePostResponse(raw: string): ParsedLlmResult {\n  const obj = parseJsonThreeLevels(raw)\n  const result: ParsedLlmResult = {}\n  if (obj == null) return result\n  const decision = obj['decision']\n  if (typeof decision === 'string' && (decision as string).length > 0) {\n    result.decision = decision as string\n  }\n  const targetId = obj['targetRuleId']\n  if (typeof targetId === 'number') {\n    result.targetRuleId = targetId as number\n  }\n  const reasoning = obj['reasoning']\n  if (typeof reasoning === 'string' && (reasoning as string).length > 0) {\n    result.reasoning = reasoning as string\n  }\n  const conf = obj['confidence']\n  if (typeof conf === 'number') {\n    result.confidence = conf as number\n  }\n  const altArr = obj['alternatives']\n  if (altArr != null) {\n    try {\n      const altStr = JSON.stringify(altArr)\n      const alt = JSON.parse(altStr) as Array<any>\n      if (alt != null) result.alternatives = alt\n    } catch (_) {}\n  }\n  const rawRule = obj['suggestedRule']\n  if (rawRule != null && typeof rawRule === 'object') {\n    const rule = normalizeRule(rawRule as UTSJSONObject)\n    if (rule != null) {\n      result.suggestedRule = rule\n    }\n  }\n  return result\n}\n\nfunction normalizeRule(raw: UTSJSONObject): EffectiveTriggerRule | null {\n  const actionId = raw['actionId']\n  if (typeof actionId !== 'string' || (actionId as string).length < 1) return null\n  const actionIdStr = actionId as string\n  let timeWindow: TimeWindow | null = null\n  const tw = raw['timeWindow']\n  if (tw != null && typeof tw === 'object') {\n    const twObj = tw as UTSJSONObject\n    const start = twObj['start']\n    const end = twObj['end']\n    if (typeof start === 'string' && typeof end === 'string') {\n      const startStr = start as string\n      const endStr = end as string\n      if (startStr.length > 0 && endStr.length > 0) {\n        const w: TimeWindow = { start: startStr, end: endStr }\n        timeWindow = w\n      }\n    }\n  }\n  let screenConditions: ScreenConditions | null = null\n  const sc = raw['screenConditions']\n  if (sc != null && typeof sc === 'object') {\n    const scObj = sc as UTSJSONObject\n    const includeHomeRaw = scObj['includeHome']\n    const includeHome = typeof includeHomeRaw === 'boolean' && (includeHomeRaw as boolean)\n    const appPackagesRaw = scObj['appPackages']\n    const pkgs: string[] = []\n    if (appPackagesRaw != null) {\n      try {\n        const arrStr = JSON.stringify(appPackagesRaw)\n        const arr = JSON.parse(arrStr) as Array<any>\n        for (let i = 0; i < arr.length; i++) {\n          const v = arr[i]\n          if (typeof v === 'string') {\n            const vs = v as string\n            if (vs.length > 0) pkgs.push(vs)\n          }\n        }\n      } catch (_) {}\n    }\n    const cond: ScreenConditions = { appPackages: pkgs, includeHome: includeHome }\n    screenConditions = cond\n  }\n  let threshold: number = 60\n  const thresholdRaw = raw['timeThresholdMinutes']\n  if (typeof thresholdRaw === 'number') {\n    threshold = (thresholdRaw as number).toInt()\n  }\n  let categoryFilter: string | null = null\n  const cfRaw = raw['categoryFilter']\n  if (typeof cfRaw === 'string' && (cfRaw as string).length > 0) {\n    categoryFilter = cfRaw as string\n  }\n  const rule: EffectiveTriggerRule = {\n    id: 0,\n    actionId: actionIdStr,\n    timeWindow: timeWindow,\n    screenConditions: screenConditions,\n    timeThresholdMinutes: threshold,\n    categoryFilter: categoryFilter,\n    source: 'llm',\n    enabled: true,\n    createdAt: Math.floor(Date.now() / 1000)\n  }\n  return rule\n}\n\nfunction parseJsonThreeLevels(raw: string): UTSJSONObject | null {\n  let cleaned = raw\n  if (cleaned.indexOf('```') >= 0) {\n    const fenceStart = cleaned.indexOf('```')\n    const afterFence = cleaned.substring(fenceStart + 3)\n    const newlineIdx = afterFence.indexOf('\\n')\n    const afterLang = newlineIdx >= 0 ? afterFence.substring(newlineIdx + 1) : afterFence\n    const endFence = afterLang.lastIndexOf('```')\n    if (endFence > 0) {\n      cleaned = afterLang.substring(0, endFence)\n    } else {\n      cleaned = afterLang\n    }\n  }\n  try {\n    return JSON.parse(cleaned) as UTSJSONObject\n  } catch (_) {}\n  try {\n    const match = cleaned.match(/\\{[\\s\\S]*\\}/)\n    if (match != null) {\n      const m = match[0]\n      if (m != null && m.length > 0) {\n        return JSON.parse(m) as UTSJSONObject\n      }\n    }\n  } catch (_) {}\n  return null\n}\n","import { dbManager } from '../database/DatabaseManager'\nimport { getNum, getStr, getStrOrNull } from '../utils/DbRowUtils'\nimport { daysAgo } from '../utils/TimeUtils'\n\nexport type AppHistorySummary = {\n  packageName: string\n  appLabel: string\n  appCategory: string\n  totalTriggers: number\n  totalCompletes: number\n  totalSkips: number\n  acceptRate: number\n  typicalContinuousMin: number\n  avgTriggerHour: number\n  lastTriggerAt: number\n  lastWeekTrend: 'improving' | 'declining' | 'stable'\n}\n\nfunction startOfDay(date: string): number {\n  const parts = date.split('-')\n  if (parts.length < 3) return 0\n  return Math.floor(new Date(parseInt(parts[0] as string), parseInt(parts[1] as string) - 1, parseInt(parts[2] as string)).getTime() / 1000)\n}\n\nfunction rowToNum(row: Map<string, any> | null, col: string): number {\n  return getNum(row, col)\n}\n\nfunction rowToStr(row: Map<string, any> | null, col: string): string {\n  return getStr(row, col)\n}\n\nexport function getAppHistory(pkg: string, days: number = 7): AppHistorySummary | null {\n  try {\n    const start = startOfDay(daysAgo(days - 1))\n    const prevStart = startOfDay(daysAgo(days * 2 - 1))\n    const triggerRows = dbManager.query(\n      \"SELECT created_at, continuous_minutes FROM trigger_logs WHERE app_package = ? AND created_at >= ? ORDER BY created_at DESC\",\n      [pkg, start]\n    )\n    if (triggerRows.length < 1) {\n      const labelRow = dbManager.queryOne('SELECT app_label FROM app_usage_snapshots WHERE package_name = ? LIMIT 1', [pkg])\n      const catRow = dbManager.queryOne('SELECT category FROM app_tags WHERE package_name = ?', [pkg])\n      return {\n        packageName: pkg,\n        appLabel: labelRow != null ? getStr(labelRow, 'app_label') : pkg,\n        appCategory: catRow != null ? getStr(catRow, 'category') : 'other',\n        totalTriggers: 0,\n        totalCompletes: 0,\n        totalSkips: 0,\n        acceptRate: 0,\n        typicalContinuousMin: 0,\n        avgTriggerHour: 0,\n        lastTriggerAt: 0,\n        lastWeekTrend: 'stable'\n      }\n    }\n    const totalTriggers = triggerRows.length\n    let totalContinMin = 0\n    let totalHours = 0\n    let lastTriggerAt = 0\n    for (let i = 0; i < triggerRows.length; i++) {\n      const r = triggerRows[i]\n      if (r == null) continue\n      totalContinMin += getNum(r, 'continuous_minutes')\n      const ts = getNum(r, 'created_at')\n      if (ts > lastTriggerAt) lastTriggerAt = ts\n      const d = new Date(ts * 1000)\n      totalHours += d.getHours()\n    }\n    let totalCompletes = 0\n    let totalSkips = 0\n    for (let i = 0; i < triggerRows.length; i++) {\n      const r = triggerRows[i]\n      if (r == null) continue\n      const ts = getNum(r, 'created_at')\n      const actionId = getStrOrNull(r, 'action_id')\n      if (actionId == null) continue\n      const actionRow = dbManager.queryOne(\n        \"SELECT result FROM action_logs WHERE created_at >= ? AND created_at < ? AND action_id = ? LIMIT 1\",\n        [ts - 60, ts + 60, actionId]\n      )\n      const result = rowToStr(actionRow, 'result')\n      if (result == 'completed' || result == 'self_reported') {\n        totalCompletes++\n      } else if (result == 'skipped') {\n        totalSkips++\n      }\n    }\n    const prevRows = dbManager.query(\n      \"SELECT created_at FROM trigger_logs WHERE app_package = ? AND created_at >= ? AND created_at < ?\",\n      [pkg, prevStart, start]\n    )\n    const prevTriggers = prevRows.length\n    const prevCompletes = 0\n    const prevAccept = prevTriggers > 0 ? prevCompletes / prevTriggers : 0\n    const currAccept = totalTriggers > 0 ? totalCompletes / totalTriggers : 0\n    let trend: 'improving' | 'declining' | 'stable' = 'stable'\n    if (prevTriggers >= 3) {\n      if (currAccept - prevAccept > 0.1) trend = 'improving'\n      else if (currAccept - prevAccept < -0.1) trend = 'declining'\n    }\n    const labelRow = dbManager.queryOne('SELECT app_label FROM app_usage_snapshots WHERE package_name = ? LIMIT 1', [pkg])\n    const catRow = dbManager.queryOne('SELECT category FROM app_tags WHERE package_name = ?', [pkg])\n    const total = totalCompletes + totalSkips\n    const acceptRate = total > 0 ? totalCompletes / total : 0\n    return {\n      packageName: pkg,\n      appLabel: labelRow != null ? getStr(labelRow, 'app_label') : pkg,\n      appCategory: catRow != null ? getStr(catRow, 'category') : 'other',\n      totalTriggers: totalTriggers,\n      totalCompletes: totalCompletes,\n      totalSkips: totalSkips,\n      acceptRate: acceptRate,\n      typicalContinuousMin: totalTriggers > 0 ? Math.round(totalContinMin / totalTriggers) : 0,\n      avgTriggerHour: totalTriggers > 0 ? Math.round(totalHours / totalTriggers) : 0,\n      lastTriggerAt: lastTriggerAt,\n      lastWeekTrend: trend\n    }\n  } catch (e) {\n    __f__('warn','at services/AppHistoryService.uts:121','[AppHistoryService] getAppHistory 异常: ' + JSON.stringify(e))\n    return null\n  }\n}\n","import { dbManager } from '../database/DatabaseManager'\nimport { getInt, getBool, getSetting } from '../database/SettingsDao'\nimport { countCompletedToday, getTotalCompletedDurationSec } from '../database/ActionLogDao'\nimport { countTriggersToday } from '../database/TriggerLogDao'\nimport { getNum, getStr } from '../utils/DbRowUtils'\nimport { today } from '../utils/TimeUtils'\n\nexport type UserProfile = {\n  healthFocus: 'eye' | 'posture' | 'vitality' | 'balanced'\n  bodyLimit: 'none' | 'neck' | 'waist' | 'knee'\n  newbieMode: boolean\n  preferredHours: number[]\n  totalActiveDays: number\n  avgDailyCompletes: number\n  daysSinceFirstUse: number\n}\n\nfunction safeHealthFocus(v: string): 'eye' | 'posture' | 'vitality' | 'balanced' {\n  if (v == 'eye' || v == 'posture' || v == 'vitality') return v\n  return 'balanced'\n}\n\nfunction safeBodyLimit(v: string): 'none' | 'neck' | 'waist' | 'knee' {\n  if (v == 'neck' || v == 'waist' || v == 'knee') return v\n  return 'none'\n}\n\nexport function getUserProfile(): UserProfile {\n  const focus = safeHealthFocus(getSetting('health_preference', 'balanced'))\n  const limit = safeBodyLimit(getSetting('body_limit', 'none'))\n  const newbie = getBool('newbie_mode', true)\n  const preferred: number[] = []\n  try {\n    const rows = dbManager.query(\n      \"SELECT strftime('%H', created_at, 'unixepoch') as hr, COUNT(*) as cnt FROM action_logs WHERE result IN ('completed','self_reported') GROUP BY hr ORDER BY cnt DESC LIMIT 3\"\n    )\n    for (let i = 0; i < rows.length; i++) {\n      const r = rows[i]\n      if (r == null) continue\n      const hrStr = getNum(r, 'hr') as number\n      preferred.push(hrStr)\n    }\n  } catch (_) {}\n  const totalDaysRow = dbManager.queryOne('SELECT COUNT(DISTINCT date) as cnt FROM daily_summaries')\n  const totalDays = getNum(totalDaysRow, 'cnt')\n  const sumRow = dbManager.queryOne('SELECT COALESCE(SUM(total_completed),0) as total FROM daily_summaries')\n  const totalCompletes = getNum(sumRow, 'total')\n  const avg = totalDays > 0 ? totalCompletes / totalDays : 0\n  let daysSinceFirst = 0\n  const firstRow = dbManager.queryOne('SELECT value FROM user_settings WHERE key = ?', ['newbie_start_date'])\n  if (firstRow != null) {\n    const startStr = getStr(firstRow, 'value')\n    const startTs = parseInt(startStr)\n    if (startTs > 0) {\n      const now = Math.floor(Date.now() / 1000)\n      daysSinceFirst = Math.floor((now - startTs) / 86400)\n      if (daysSinceFirst < 0) daysSinceFirst = 0\n    }\n  }\n  return {\n    healthFocus: focus,\n    bodyLimit: limit,\n    newbieMode: newbie,\n    preferredHours: preferred,\n    totalActiveDays: totalDays,\n    avgDailyCompletes: Math.round(avg * 10) / 10,\n    daysSinceFirstUse: daysSinceFirst\n  }\n}\n","import { getActiveRules, getRulesByApp, isRuleActive as daoIsRuleActive } from '../database/EffectiveRuleDao'\nimport { PersistedEffectiveRule } from '../models/PersistedEffectiveRule'\nimport { TimeWindow } from '../models/EffectiveTriggerRule'\nimport { isInTimeRange } from '../utils/TimeUtils'\n\nexport function getActiveRuleList(): PersistedEffectiveRule[] {\n  return getActiveRules()\n}\n\nexport function getRulesForApp(pkg: string): PersistedEffectiveRule[] {\n  return getRulesByApp(pkg)\n}\n\nexport function isRuleActive(rule: PersistedEffectiveRule, pkg: string, nowSec: number): boolean {\n  if (!rule.enabled) return false\n  if (rule.expiresAt != null && rule.expiresAt > 0 && nowSec > rule.expiresAt) return false\n  if (rule.appPackages.length > 0 && rule.appPackages.indexOf(pkg) < 0) return false\n  if (rule.timeWindow != null) {\n    if (!isInTimeRange(rule.timeWindow.start, rule.timeWindow.end)) return false\n  }\n  return true\n}\n\nexport function parseTimeWindow(json: string | null): TimeWindow | null {\n  if (json == null || json.length < 1) return null\n  try {\n    const obj = JSON.parse(json) as UTSJSONObject\n    if (obj == null) return null\n    const start = obj['start'] as string\n    const end = obj['end'] as string\n    if (start != null && end != null && start.length > 0 && end.length > 0) {\n      return { start: start, end: end }\n    }\n  } catch (_) {}\n  return null\n}\n","export type AppCategory = 'social' | 'video' | 'game' | 'work' | 'study' | 'reading' | 'other'\n\nexport type TagSource = 'pending' | 'llm' | 'user'\n\nexport type AppTag = {\n  packageName: string\n  appLabel: string\n  category: AppCategory\n  tagSource: TagSource\n  isUserLocked: boolean\n  isInRule: boolean\n  totalUses: number\n  lastSeenAt: number\n  createdAt: number\n  updatedAt: number\n}\n","import { dbManager, type SqlRow } from './DatabaseManager'\nimport { AppTag, AppCategory, TagSource } from '../models/AppTag'\nimport { getNum, getStr, getStrOrNull } from '../utils/DbRowUtils'\n\nfunction mapRow(row: Map<string, any>): AppTag {\n  const total = getNum(row, 'total_uses')\n  return {\n    packageName: getStr(row, 'package_name'),\n    appLabel: getStr(row, 'app_label'),\n    category: getStr(row, 'category') as AppCategory,\n    tagSource: getStr(row, 'tag_source') as TagSource,\n    isUserLocked: getNum(row, 'is_user_locked') == 1,\n    isInRule: getNum(row, 'is_in_rule') == 1,\n    totalUses: total,\n    lastSeenAt: getNum(row, 'last_seen_at'),\n    createdAt: getNum(row, 'created_at'),\n    updatedAt: getNum(row, 'updated_at')\n  }\n}\n\nexport function getByPackage(pkg: string): AppTag | null {\n  const row = dbManager.queryOne('SELECT * FROM app_tags WHERE package_name = ?', [pkg])\n  if (row == null) return null\n  return mapRow(row)\n}\n\nexport function listByCategory(category: string): AppTag[] {\n  const rows = dbManager.query('SELECT * FROM app_tags WHERE category = ? ORDER BY total_uses DESC', [category])\n  const result: AppTag[] = []\n  for (let i = 0; i < rows.length; i++) {\n    const r = rows[i]\n    if (r == null) continue\n    result.push(mapRow(r))\n  }\n  return result\n}\n\nexport function listAll(): AppTag[] {\n  const rows = dbManager.query('SELECT * FROM app_tags ORDER BY last_seen_at DESC')\n  const result: AppTag[] = []\n  for (let i = 0; i < rows.length; i++) {\n    const r = rows[i]\n    if (r == null) continue\n    result.push(mapRow(r))\n  }\n  return result\n}\n\nexport function listPendingForLlm(): AppTag[] {\n  const rows = dbManager.query(\n    \"SELECT * FROM app_tags WHERE tag_source = 'pending' AND is_user_locked = 0 ORDER BY last_seen_at DESC\"\n  )\n  const result: AppTag[] = []\n  for (let i = 0; i < rows.length; i++) {\n    const r = rows[i]\n    if (r == null) continue\n    result.push(mapRow(r))\n  }\n  return result\n}\n\nexport function upsert(tag: AppTag): void {\n  const existing = dbManager.queryOne('SELECT package_name FROM app_tags WHERE package_name = ?', [tag.packageName])\n  if (existing != null) {\n    const row: SqlRow = {\n      columns: ['app_label', 'last_seen_at', 'updated_at', 'total_uses'],\n      values: [tag.appLabel, tag.lastSeenAt, tag.updatedAt, tag.totalUses]\n    }\n    dbManager.update('app_tags', row, 'package_name = ?', [tag.packageName])\n  } else {\n    const row: SqlRow = {\n      columns: [\n        'package_name', 'app_label', 'category', 'tag_source',\n        'is_user_locked', 'is_in_rule', 'total_uses',\n        'last_seen_at', 'created_at', 'updated_at'\n      ],\n      values: [\n        tag.packageName, tag.appLabel, tag.category, tag.tagSource,\n        tag.isUserLocked ? 1 : 0, tag.isInRule ? 1 : 0, tag.totalUses,\n        tag.lastSeenAt, tag.createdAt, tag.updatedAt\n      ]\n    }\n    dbManager.insert('app_tags', row)\n  }\n}\n\nexport function updateCategory(pkg: string, category: AppCategory, source: TagSource): void {\n  const now = Math.floor(Date.now() / 1000)\n  const row: SqlRow = {\n    columns: ['category', 'tag_source', 'updated_at'],\n    values: [category, source, now]\n  }\n  dbManager.update('app_tags', row, 'package_name = ?', [pkg])\n}\n\nexport function setUserLocked(pkg: string, locked: boolean): void {\n  const now = Math.floor(Date.now() / 1000)\n  const row: SqlRow = {\n    columns: ['is_user_locked', 'updated_at'],\n    values: [locked ? 1 : 0, now]\n  }\n  dbManager.update('app_tags', row, 'package_name = ?', [pkg])\n}\n\nexport function incrementUses(pkg: string): void {\n  try {\n    const existing = getByPackage(pkg)\n    if (existing == null) return\n    const newCount = existing.totalUses + 1\n    const now = Math.floor(Date.now() / 1000)\n    const row: SqlRow = {\n      columns: ['total_uses', 'last_seen_at', 'updated_at'],\n      values: [newCount, now, now]\n    }\n    dbManager.update('app_tags', row, 'package_name = ?', [pkg])\n  } catch (_) {}\n}\n","import * as AppTagsDao from '../database/AppTagsDao'\nimport { AppTag, AppCategory } from '../models/AppTag'\nimport { callMinimaxChat } from './CloudService'\nimport { today } from '../utils/TimeUtils'\nimport { shouldFilterPackage } from '../utils/SystemAppUtils'\n\nconst SYSTEM_PROMPT_CLASSIFY =\n  '你是一个 App 分类助手。\\n根据用户的应用名和包名，分类到以下之一：social | video | game | work | study | reading | other\\n严格按 JSON 输出，不要任何额外文字：{\"results\":[{\"packageName\":\"...\",\"category\":\"...\"}]}'\n\nconst VALID_CATEGORIES: AppCategory[] = ['social', 'video', 'game', 'work', 'study', 'reading', 'other']\n\nfunction isValidCategory(s: string): boolean {\n  for (let i = 0; i < VALID_CATEGORIES.length; i++) {\n    if (VALID_CATEGORIES[i] == s) return true\n  }\n  return false\n}\n\nexport function ensureCategory(pkg: string, appLabel: string): void {\n  // 系统包不入册：避免污染 app_tags / 拖到 LLM 分类 / 出现在 pie chart\n  if (shouldFilterPackage(pkg, '')) return\n  try {\n    const existing = AppTagsDao.getByPackage(pkg)\n    if (existing != null) {\n      AppTagsDao.incrementUses(pkg)\n      return\n    }\n    const now = Math.floor(Date.now() / 1000)\n    const tag: AppTag = {\n      packageName: pkg,\n      appLabel: appLabel,\n      category: 'other',\n      tagSource: 'pending',\n      isUserLocked: false,\n      isInRule: false,\n      totalUses: 1,\n      lastSeenAt: now,\n      createdAt: now,\n      updatedAt: now\n    }\n    AppTagsDao.upsert(tag)\n  } catch (e) {\n    __f__('warn','at services/AppCategoryService.uts:43','[AppCategoryService] ensureCategory 失败: ' + JSON.stringify(e))\n  }\n}\n\nexport function batchClassifyTodayNewApps(onComplete: ((n: number) => void) | null = null): void {\n  try {\n    const pending = AppTagsDao.listPendingForLlm()\n    if (pending.length < 1) {\n      if (onComplete != null) onComplete(0)\n      return\n    }\n    const items: string[] = []\n    for (let i = 0; i < pending.length; i++) {\n      const p = pending[i]\n      items.push('{\"packageName\":\"' + p.packageName + '\",\"appLabel\":\"' + p.appLabel + '\"}')\n    }\n    const userPrompt = '请分类以下应用：\\n' + items.join('\\n')\n    callMinimaxChat(SYSTEM_PROMPT_CLASSIFY, userPrompt, 800, (raw: string): void => {\n      try {\n        const obj = parseClassifyResponse(raw, pending)\n        let n = 0\n        for (let i = 0; i < obj.length; i++) {\n          const item = obj[i]\n          // 二次保险：LLM 返回的包名也按系统包过滤\n          if (shouldFilterPackage(item.pkg, '')) continue\n          const tag = AppTagsDao.getByPackage(item.pkg)\n          if (tag == null) continue\n          if (tag.isUserLocked) continue\n          AppTagsDao.updateCategory(item.pkg, item.category, 'llm')\n          n++\n        }\n        if (onComplete != null) onComplete(n)\n      } catch (e) {\n        __f__('warn','at services/AppCategoryService.uts:76','[AppCategoryService] batchClassify 解析失败: ' + JSON.stringify(e))\n        if (onComplete != null) onComplete(0)\n      }\n    }, (): void => {\n      __f__('warn','at services/AppCategoryService.uts:80','[AppCategoryService] batchClassify LLM 失败')\n      if (onComplete != null) onComplete(0)\n    })\n  } catch (e) {\n    __f__('warn','at services/AppCategoryService.uts:84','[AppCategoryService] batchClassifyTodayNewApps 异常: ' + JSON.stringify(e))\n    if (onComplete != null) onComplete(0)\n  }\n}\n\ntype ClassifyItem = { pkg: string; category: AppCategory }\n\nfunction parseClassifyResponse(raw: string, pending: AppTag[]): ClassifyItem[] {\n  const result: ClassifyItem[] = []\n  let text = raw.trim()\n  const startIdx = text.indexOf('[')\n  const endIdx = text.lastIndexOf(']')\n  if (startIdx < 0 || endIdx < 0 || endIdx < startIdx) return result\n  text = text.substring(startIdx, endIdx + 1)\n  let arr: Array<UTSJSONObject> = []\n  try {\n    const parsed = JSON.parse(text) as Array<any>\n    if (parsed != null) {\n      for (let i = 0; i < parsed.length; i++) {\n        const v = parsed[i]\n        if (v != null && typeof v === 'object') {\n          arr.push(v as UTSJSONObject)\n        }\n      }\n    }\n  } catch (_) {\n    return result\n  }\n  for (let i = 0; i < arr.length; i++) {\n    const obj = arr[i]\n    const pkg = obj['packageName'] as string\n    const cat = obj['category'] as string\n    if (pkg == null || cat == null) continue\n    if (!isValidCategory(cat)) continue\n    const item: ClassifyItem = { pkg: pkg, category: cat as AppCategory }\n    result.push(item)\n  }\n  return result\n}\n\nexport function manualSetCategory(pkg: string, category: AppCategory): void {\n  AppTagsDao.setUserLocked(pkg, true)\n  AppTagsDao.updateCategory(pkg, category, 'user')\n}\n","// 成就系统数据模型\n\nexport type AchievementCategory = '累计' | '坚持' | '评分' | '动作' | '时段' | '单日'\n\nexport type AchievementConditionType =\n  | 'total_count'        // 累计完成次数\n  | 'streak_days'        // 连续天数\n  | 'eye_score'          // 护眼评分（单日）\n  | 'category_count'     // 某一动作分类累计完成次数\n  | 'hour_range_count'   // 某时段累计完成次数\n  | 'daily_count'        // 单日完成次数\n\n// 成就预设定义（前端常量表中）\nexport type AchievementDef = {\n  id: string\n  name: string\n  icon: string           // emoji\n  description: string    // 解锁条件描述\n  category: AchievementCategory\n  conditionType: AchievementConditionType\n  threshold: number\n  rewardText: string     // 解锁后显示的奖励\n  historyText: string    // 历程/进度文字\n  // 条件参数（如 category_count 需要指定 action_type，hour_range_count 需要指定 startHour/endHour）\n  actionType: string\n  startHour: number\n  endHour: number\n}\n\n// 用户当前成就项（带解锁状态 + 进度）\nexport type AchievementItem = {\n  def: AchievementDef\n  isUnlocked: boolean\n  currentProgress: number\n  unlockedAt: number     // 0 表示未解锁\n  isNew: boolean         // 已解锁但用户未在主页查看过\n}\n\n// 进度显示文本（\"3/10\" / \"✓\"）\nexport type AchievementProgress = {\n  current: number\n  target: number\n  text: string\n  percent: number        // 0~1\n}\n","// 12 个预设成就定义\r\n\r\nimport { type AchievementDef } from '../models/Achievement'\r\n\r\nexport const ACHIEVEMENTS: AchievementDef[] = [\r\n  {\r\n    id: 'first_action',\r\n    name: '初出茅庐',\r\n    icon: '🌱',\r\n    description: '完成第 1 次微动作',\r\n    category: '累计',\r\n    conditionType: 'total_count',\r\n    threshold: 1,\r\n    rewardText: '🏅 健康之旅正式启程',\r\n    historyText: '0 → 1：迈出第一步',\r\n    actionType: '',\r\n    startHour: 0,\r\n    endHour: 0\r\n  },\r\n  {\r\n    id: 'streak_3',\r\n    name: '初见曙光',\r\n    icon: '✦',\r\n    description: '连续 3 天每天完成至少 1 次',\r\n    category: '坚持',\r\n    conditionType: 'streak_days',\r\n    threshold: 3,\r\n    rewardText: '🏅 习惯的种子已发芽',\r\n    historyText: '连续天数 1 → 2 → 3',\r\n    actionType: '',\r\n    startHour: 0,\r\n    endHour: 0\r\n  },\r\n  {\r\n    id: 'total_10',\r\n    name: '小有所成',\r\n    icon: '🌿',\r\n    description: '累计完成 10 次微动作',\r\n    category: '累计',\r\n    conditionType: 'total_count',\r\n    threshold: 10,\r\n    rewardText: '🏅 健康生活的初学者',\r\n    historyText: '1 → 5 → 10：稳步前进',\r\n    actionType: '',\r\n    startHour: 0,\r\n    endHour: 0\r\n  },\r\n  {\r\n    id: 'total_30',\r\n    name: '习惯养成',\r\n    icon: '🌳',\r\n    description: '累计完成 30 次微动作',\r\n    category: '累计',\r\n    conditionType: 'total_count',\r\n    threshold: 30,\r\n    rewardText: '🏅 习惯已成自然',\r\n    historyText: '10 → 20 → 30：质的飞跃',\r\n    actionType: '',\r\n    startHour: 0,\r\n    endHour: 0\r\n  },\r\n  {\r\n    id: 'total_100',\r\n    name: '守护百次',\r\n    icon: '🏆',\r\n    description: '累计完成 100 次微动作',\r\n    category: '累计',\r\n    conditionType: 'total_count',\r\n    threshold: 100,\r\n    rewardText: '🏆 健康守护者',\r\n    historyText: '30 → 60 → 100：百日筑基',\r\n    actionType: '',\r\n    startHour: 0,\r\n    endHour: 0\r\n  },\r\n  {\r\n    id: 'eye_score_90',\r\n    name: '眼明心亮',\r\n    icon: '◐',\r\n    description: '单日护眼评分达 90 分以上',\r\n    category: '评分',\r\n    conditionType: 'eye_score',\r\n    threshold: 90,\r\n    rewardText: '◐ 护眼小达人',\r\n    historyText: '70 → 80 → 90：明眸善睐',\r\n    actionType: '',\r\n    startHour: 0,\r\n    endHour: 0\r\n  },\r\n  {\r\n    id: 'neck_10',\r\n    name: '颈肩舒畅',\r\n    icon: '💆',\r\n    description: '累计完成 10 次肩颈类动作',\r\n    category: '动作',\r\n    conditionType: 'category_count',\r\n    threshold: 10,\r\n    rewardText: '💆 肩颈不再僵硬',\r\n    historyText: '1 → 5 → 10：肩颈舒展',\r\n    actionType: '肩颈',\r\n    startHour: 0,\r\n    endHour: 0\r\n  },\r\n  {\r\n    id: 'breath_10',\r\n    name: '深呼吸者',\r\n    icon: '◎',\r\n    description: '累计完成 10 次腹式呼吸',\r\n    category: '动作',\r\n    conditionType: 'category_count',\r\n    threshold: 10,\r\n    rewardText: '◎ 调息养神大师',\r\n    historyText: '1 → 5 → 10：呼吸有度',\r\n    actionType: '呼吸',\r\n    startHour: 0,\r\n    endHour: 0\r\n  },\r\n  {\r\n    id: 'morning_5',\r\n    name: '晨型人',\r\n    icon: '🌅',\r\n    description: '凌晨 5 点至 9 点累计完成 5 次',\r\n    category: '时段',\r\n    conditionType: 'hour_range_count',\r\n    threshold: 5,\r\n    rewardText: '🌅 拥抱清晨第一缕阳光',\r\n    historyText: '1 → 3 → 5：晨起打卡',\r\n    actionType: '',\r\n    startHour: 5,\r\n    endHour: 9\r\n  },\r\n  {\r\n    id: 'night_5',\r\n    name: '夜猫子',\r\n    icon: '🌙',\r\n    description: '晚 22 点至凌晨 2 点累计完成 5 次',\r\n    category: '时段',\r\n    conditionType: 'hour_range_count',\r\n    threshold: 5,\r\n    rewardText: '🌙 深夜的健康守护者',\r\n    historyText: '1 → 3 → 5：夜半灯下',\r\n    actionType: '',\r\n    startHour: 22,\r\n    endHour: 2\r\n  },\r\n  {\r\n    id: 'daily_30',\r\n    name: '极限挑战',\r\n    icon: '🚀',\r\n    description: '单日完成 30 次微动作',\r\n    category: '单日',\r\n    conditionType: 'daily_count',\r\n    threshold: 30,\r\n    rewardText: '🚀 一天 30 次的硬核玩家',\r\n    historyText: '10 → 20 → 30：单日极限',\r\n    actionType: '',\r\n    startHour: 0,\r\n    endHour: 0\r\n  },\r\n  {\r\n    id: 'streak_7',\r\n    name: '持之以恒',\r\n    icon: '⭐',\r\n    description: '连续 7 天每天完成至少 1 次',\r\n    category: '坚持',\r\n    conditionType: 'streak_days',\r\n    threshold: 7,\r\n    rewardText: '⭐ 恒心之王',\r\n    historyText: '3 → 5 → 7：七日成章',\r\n    actionType: '',\r\n    startHour: 0,\r\n    endHour: 0\r\n  }\r\n]\r\n\r\nconst ACHIEVEMENT_MAP: Map<string, AchievementDef> = new Map()\r\n\r\nfunction buildMap(): void {\r\n  for (let i = 0; i < ACHIEVEMENTS.length; i++) {\r\n    const a = ACHIEVEMENTS[i]\r\n    ACHIEVEMENT_MAP.set(a.id, a)\r\n  }\r\n}\r\n\r\nbuildMap()\r\n\r\nexport function getAchievementDef(id: string): AchievementDef | null {\r\n  return ACHIEVEMENT_MAP.get(id)\r\n}\r\n\r\nexport function getAllAchievementDefs(): AchievementDef[] {\r\n  return ACHIEVEMENTS\r\n}\r\n","import { dbManager, type SqlRow } from './DatabaseManager'\nimport { getNum, getStr, getStrOrNull } from '../utils/DbRowUtils'\n\nexport type UserAchievementRow = {\n  id: number\n  achievementId: string\n  unlockedAt: number\n  currentProgress: number\n  createdAt: number\n}\n\nfunction mapRow(row: Map<string, any>): UserAchievementRow {\n  return {\n    id: getNum(row, 'id'),\n    achievementId: getStr(row, 'achievement_id'),\n    unlockedAt: getNum(row, 'unlocked_at'),\n    currentProgress: getNum(row, 'current_progress'),\n    createdAt: getNum(row, 'created_at')\n  }\n}\n\nexport function getAllUnlocked(): UserAchievementRow[] {\n  const result: UserAchievementRow[] = []\n  try {\n    const rows = dbManager.query('SELECT * FROM user_achievements ORDER BY unlocked_at DESC')\n    for (let i = 0; i < rows.length; i++) {\n      const r = rows[i]\n      if (r == null) continue\n      try {\n        result.push(mapRow(r))\n      } catch (e) {\n        __f__('warn','at database/AchievementDao.uts:32','[AchievementDao] mapRow skip dirty row: ' + JSON.stringify(e))\n      }\n    }\n  } catch (e) {\n    __f__('warn','at database/AchievementDao.uts:36','[AchievementDao] getAllUnlocked 异常（表可能尚未创建）: ' + JSON.stringify(e))\n  }\n  return result\n}\n\nexport function isUnlocked(achievementId: string): boolean {\n  try {\n    const row = dbManager.queryOne(\n      'SELECT id FROM user_achievements WHERE achievement_id = ? LIMIT 1',\n      [achievementId]\n    )\n    return row != null\n  } catch (e) {\n    __f__('warn','at database/AchievementDao.uts:49','[AchievementDao] isUnlocked 异常（表可能尚未创建）: ' + JSON.stringify(e))\n    return false\n  }\n}\n\nexport function insertUnlock(achievementId: string, progress: number): void {\n  const now = Math.floor(Date.now() / 1000)\n  const row: SqlRow = {\n    columns: ['achievement_id', 'unlocked_at', 'current_progress', 'created_at'],\n    values: [achievementId, now, progress, now]\n  }\n  try {\n    dbManager.insert('user_achievements', row)\n  } catch (e) {\n    __f__('warn','at database/AchievementDao.uts:63','[AchievementDao] insertUnlock 失败: ' + JSON.stringify(e))\n  }\n}\n\nexport function clearAll(): void {\n  try {\n    dbManager.delete('user_achievements', '', [])\n  } catch (e) {\n    __f__('warn','at database/AchievementDao.uts:71','[AchievementDao] clearAll 异常: ' + JSON.stringify(e))\n  }\n}\n","// 成就系统核心服务：检查解锁条件 + 计算进度\n\nimport { ACHIEVEMENTS, getAllAchievementDefs, getAchievementDef } from '../constants/Achievements'\nimport { type AchievementDef, type AchievementItem, type AchievementProgress } from '../models/Achievement'\nimport * as AchievementDao from '../database/AchievementDao'\nimport { dbManager } from '../database/DatabaseManager'\nimport { getNum } from '../utils/DbRowUtils'\nimport { today } from '../utils/TimeUtils'\n\n// 计算指定成就的当前进度\nfunction computeProgress(def: AchievementDef): number {\n  switch (def.conditionType) {\n    case 'total_count':\n      return getTotalCompletedCount()\n    case 'streak_days':\n      return getCurrentStreakDays()\n    case 'eye_score':\n      return getTodayEyeScore()\n    case 'category_count':\n      return getCategoryCompletedCount(def.actionType)\n    case 'hour_range_count':\n      return getHourRangeCompletedCount(def.startHour, def.endHour)\n    case 'daily_count':\n      return getTodayCompletedCount()\n    default:\n      return 0\n  }\n}\n\nfunction getTotalCompletedCount(): number {\n  try {\n    const row = dbManager.queryOne(\n      \"SELECT COUNT(*) as cnt FROM action_logs WHERE result IN ('completed', 'self_reported')\"\n    )\n    return getNum(row, 'cnt')\n  } catch (_) { return 0 }\n}\n\nfunction getTodayCompletedCount(): number {\n  try {\n    const startOfDay = Math.floor(new Date().getTime() / 1000)\n    const dayStart = startOfDay - (new Date().getHours() * 3600 + new Date().getMinutes() * 60 + new Date().getSeconds())\n    const row = dbManager.queryOne(\n      \"SELECT COUNT(*) as cnt FROM action_logs WHERE result IN ('completed', 'self_reported') AND created_at >= ?\",\n      [dayStart]\n    )\n    return getNum(row, 'cnt')\n  } catch (_) { return 0 }\n}\n\nfunction getCurrentStreakDays(): number {\n  try {\n    const rows = dbManager.query(\n      'SELECT date, total_completed FROM daily_summaries ORDER BY date DESC LIMIT 30'\n    )\n    if (rows.length < 1) return 0\n    let streak = 0\n    let expectedDate = today()\n    for (let i = 0; i < rows.length; i++) {\n      const r = rows[i]\n      if (r == null) continue\n      const dateVal = r.get('date') as string\n      if (dateVal == null || dateVal.length < 1) continue\n      if (dateVal != expectedDate) {\n        break\n      }\n      const total = getNum(r, 'total_completed')\n      if (total > 0) {\n        streak++\n        expectedDate = prevDateString(expectedDate)\n      } else {\n        break\n      }\n    }\n    return streak\n  } catch (_) { return 0 }\n}\n\nfunction prevDateString(dateStr: string): string {\n  const parts = dateStr.split('-')\n  if (parts.length < 3) return dateStr\n  const y = parseInt(parts[0] as string)\n  const m = parseInt(parts[1] as string)\n  const d = parseInt(parts[2] as string)\n  const dt = new Date(y, m - 1, d)\n  dt.setDate(dt.getDate() - 1)\n  return dt.getFullYear() + '-' + ('' + (dt.getMonth() + 1)).padStart(2, '0') + '-' + ('' + dt.getDate()).padStart(2, '0')\n}\n\nfunction getTodayEyeScore(): number {\n  try {\n    const t = today()\n    const row = dbManager.queryOne(\n      'SELECT eye_score FROM daily_summaries WHERE date = ?',\n      [t]\n    )\n    if (row == null) return 0\n    return getNum(row, 'eye_score')\n  } catch (_) { return 0 }\n}\n\nfunction getCategoryCompletedCount(category: string): number {\n  try {\n    if (category.length < 1) return 0\n    const row = dbManager.queryOne(\n      \"SELECT COUNT(*) as cnt FROM action_logs WHERE result IN ('completed', 'self_reported') AND action_type = ?\",\n      [category]\n    )\n    return getNum(row, 'cnt')\n  } catch (_) { return 0 }\n}\n\nfunction getHourRangeCompletedCount(startHour: number, endHour: number): number {\n  try {\n    const rows = dbManager.query(\n      \"SELECT created_at FROM action_logs WHERE result IN ('completed', 'self_reported')\"\n    )\n    let n = 0\n    for (let i = 0; i < rows.length; i++) {\n      const r = rows[i]\n      if (r == null) continue\n      const ts = getNum(r, 'created_at')\n      const d = new Date(ts * 1000)\n      const h = d.getHours()\n      if (isHourInRange(h, startHour, endHour)) n++\n    }\n    return n\n  } catch (_) { return 0 }\n}\n\nfunction isHourInRange(h: number, startHour: number, endHour: number): boolean {\n  if (startHour <= endHour) {\n    return h >= startHour && h < endHour\n  }\n  // 跨天（如 22-2）\n  return h >= startHour || h < endHour\n}\n\n// 公开：检查所有成就，命中则写入 DB，返回新解锁的 id 列表\nexport function checkAndUnlock(): string[] {\n  const newUnlocked: string[] = []\n  const defs = getAllAchievementDefs()\n  for (let i = 0; i < defs.length; i++) {\n    const def = defs[i]\n    if (AchievementDao.isUnlocked(def.id)) continue\n    let cur = 0\n    try {\n      cur = computeProgress(def)\n    } catch (e) {\n      __f__('warn','at services/AchievementService.uts:150','[AchievementService] computeProgress 失败 id=' + def.id + ' type=' + (typeof e))\n      continue\n    }\n    if (cur >= def.threshold) {\n      try {\n        AchievementDao.insertUnlock(def.id, cur)\n        newUnlocked.push(def.id)\n      } catch (e) {\n        __f__('warn','at services/AchievementService.uts:158','[AchievementService] insertUnlock 失败: ' + JSON.stringify(e))\n      }\n    }\n  }\n  return newUnlocked\n}\n\n// 公开：返回带状态的成就列表（用于主页展示）\nexport function getAchievementItems(seenSet: Set<string>): AchievementItem[] {\n  const unlockedRows: AchievementDao.UserAchievementRow[] = AchievementDao.getAllUnlocked()\n  const unlockedMap: Map<string, number> = new Map()\n  for (let i = 0; i < unlockedRows.length; i++) {\n    const r = unlockedRows[i]\n    unlockedMap.set(r.achievementId, r.unlockedAt)\n  }\n  const result: AchievementItem[] = []\n  const defs = getAllAchievementDefs()\n  for (let i = 0; i < defs.length; i++) {\n    const def = defs[i]\n    const unlockedAt = unlockedMap.get(def.id)\n    const isUnlocked = unlockedAt != null\n    let cur = 0\n    try {\n      cur = computeProgress(def)\n    } catch (e) {\n      __f__('warn','at services/AchievementService.uts:183','[AchievementService] computeProgress 失败 id=' + def.id + ' type=' + (typeof e))\n    }\n    const item: AchievementItem = {\n      def: def,\n      isUnlocked: isUnlocked,\n      currentProgress: cur,\n      unlockedAt: unlockedAt != null ? unlockedAt : 0,\n      isNew: isUnlocked && !seenSet.has(def.id)\n    }\n    result.push(item)\n  }\n  return result\n}\n\n// 公开：获取指定成就的展示进度\nexport function getProgressText(item: AchievementItem): AchievementProgress {\n  const def = item.def\n  if (item.isUnlocked) {\n    return {\n      current: def.threshold,\n      target: def.threshold,\n      text: '已达成',\n      percent: 1\n    }\n  }\n  const current = Math.min(item.currentProgress, def.threshold)\n  const target = def.threshold\n  const percent = target > 0 ? Math.min(current / target, 1) : 0\n  return {\n    current: current,\n    target: target,\n    text: current + ' / ' + target,\n    percent: percent\n  }\n}\n","import 'D:/Program Files (x86)/HBuilderX/plugins/uniapp-cli-vite/node_modules/@dcloudio/uni-console/src/runtime/app/index.ts';import App from './App.uvue'\r\n\r\nimport { createSSRApp } from 'vue'\r\nexport function createApp() {\r\n\tconst app = createSSRApp(App)\r\n\treturn {\r\n\t\tapp\r\n\t}\r\n}\nexport function main(app: IApp) {\n    enableStyleIsolation();\n    definePageRoutes();\n    defineAppConfig();\n    (createApp()['app'] as VueApp).mount(app, GenUniApp());\n}\n\nexport class UniAppConfig extends io.dcloud.uniapp.appframe.AppConfig {\n    override name: string = \"微习惯健康伴侣\"\n    override appid: string = \"__UNI__B805CE2\"\n    override versionName: string = \"1.0.5\"\n    override versionCode: string = \"105\"\n    override uniCompilerVersion: string = \"5.11\"\n    \n    constructor() { super() }\n}\n\nimport GenPagesGuideIndexClass from './pages/guide/index.uvue'\nimport GenPagesHomeIndexClass from './pages/home/index.uvue'\nimport GenPagesActionExecuteClass from './pages/action/execute.uvue'\nimport GenPagesDataDashboardClass from './pages/data/dashboard.uvue'\nimport GenPagesSettingsIndexClass from './pages/settings/index.uvue'\nimport GenPagesDebugLogsClass from './pages/debug/logs.uvue'\nimport G