  '#2ECC71',\n  '#9B59B6',\n  '#E67E22',\n  '#E74C3C',\n  '#1ABC9C',\n  '#F1C40F',\n  '#34495E',\n  '#16A085',\n  '#D35400'\n]\n\nexport function getTodayPhoneUsageSummary(): PhoneUsageSummary {\n  const totalSeconds = getTodayTotalUsageSeconds()\n  const minutes = Math.floor(totalSeconds / 60)\n  const hours = Math.floor(minutes / 60)\n  const remainMin = minutes % 60\n  const breakdown = getTodayAppBreakdown()\n  return {\n    totalMinutes: minutes,\n    totalSeconds: totalSeconds,\n    hourText: hours + ' 小时',\n    minuteText: remainMin + ' 分钟',\n    appCount: breakdown.length\n  }\n}\n\nexport function getTodayPieSegments(): PieSegment[] {\n  const all = getTodayAppBreakdown()\n  let sumSec = 0\n  for (let i = 0; i < all.length; i++) {\n    sumSec += all[i].foregroundSec\n  }\n  if (sumSec < 1) return []\n  const segments: PieSegment[] = []\n  let start = 0\n  const cap = all.length > 10 ? 10 : all.length\n  for (let i = 0; i < cap; i++) {\n    const item = all[i]\n    const pct = (item.foregroundSec / sumSec) * 100\n    const end = start + pct\n    const color: string = i < PALETTE.length ? (PALETTE[i] as string) : '#BDC3C7'\n    const seg: PieSegment = {\n      pkg: item.packageName,\n      label: item.appLabel.length > 0 ? item.appLabel : item.packageName,\n      minutes: item.minutes,\n      percent: Math.round(pct * 10) / 10,\n      color: color,\n      startAngle: start,\n      endAngle: end\n    }\n    segments.push(seg)\n    start = end\n  }\n  if (all.length > cap) {\n    let othersMin = 0\n    for (let i = cap; i < all.length; i++) {\n      othersMin += all[i].minutes\n    }\n    const pct = 100 - start\n    const seg: PieSegment = {\n      pkg: '__others__',\n      label: '其他',\n      minutes: othersMin,\n      percent: Math.round(pct * 10) / 10,\n      color: '#BDC3C7',\n      startAngle: start,\n      endAngle: 100\n    }\n    segments.push(seg)\n  }\n  return segments\n}\n\nexport function getTop5PhoneApps(): AppUsageItem[] {\n  return getTop5Apps()\n}\n\nconst LLM_RESERVED_NOTE = 'LLM 接口待配置'\n\nexport function aiEvaluateTodayUsage(onComplete: (text: string) => void): void {\n  onComplete(LLM_RESERVED_NOTE)\n}\n\nexport type PhoneUsageFromSystem = {\n  summary: PhoneUsageSummary\n  segments: PieSegment[]\n}\n\nfunction startOfTodayMs(): number {\n  const d = new Date()\n  d.setHours(0, 0, 0, 0)\n  return d.getTime()\n}\n\ntype SystemUsageEntry = {\n  packageName: string\n  totalTimeInForeground: number\n  lastTimeUsed: number\n}\n\n// 从系统 UsageStatsManager.queryUsageStats(todayStart, now) 直接读\n// 用于本地 app_usage_snapshots 为空时的兜底显示\nexport function getPhoneUsageFromSystem(): PhoneUsageFromSystem {\n  const emptySummary: PhoneUsageSummary = {\n    totalMinutes: 0,\n    totalSeconds: 0,\n    hourText: '0 小时',\n    minuteText: '0 分钟',\n    appCount: 0\n  }\n  const startMs = startOfTodayMs()\n  const endMs = Date.now()\n  let entries: SystemUsageEntry[] = []\n  try {\n    const raw = queryUsageStatsOnce(startMs, endMs)\n    if (raw != null) {\n      for (let i = 0; i < raw.length; i++) {\n        const e = raw[i]\n        if (e == null) continue\n        const item: SystemUsageEntry = {\n          packageName: e.packageName,\n          totalTimeInForeground: e.totalTimeInForeground as number,\n          lastTimeUsed: e.lastTimeUsed as number\n        }\n        entries.push(item)\n      }\n    }\n  } catch (e) {\n    __f__('error','at services/PhoneUsageService.uts:153','[PhoneUsageService] queryUsageStatsOnce 失败: ' + JSON.stringify(e))\n    const emptyResult: PhoneUsageFromSystem = { summary: emptySummary, segments: [] }\n    return emptyResult\n  }\n  if (entries.length < 1) {\n    const emptyResult: PhoneUsageFromSystem = { summary: emptySummary, segments: [] }\n    return emptyResult\n  }\n\n  // 转 AppUsageItem 列表\n  const items: AppUsageItem[] = []\n  for (let i = 0; i < entries.length; i++) {\n    const e = entries[i]\n    if (e == null) continue\n    const sec = Math.floor((e.totalTimeInForeground as number) / 1000)\n    const label = e.packageName != null ? e.packageName : ''\n    items.push({\n      packageName: e.packageName,\n      appLabel: label,\n      foregroundSec: sec,\n      minutes: Math.floor(sec / 60)\n    })\n  }\n  // 按 desc 排序\n  items.sort((a: AppUsageItem, b: AppUsageItem): number => b.foregroundSec - a.foregroundSec)\n\n  // 汇总秒数\n  let totalSeconds = 0\n  for (let i = 0; i < items.length; i++) {\n    totalSeconds += items[i].foregroundSec\n  }\n  const totalMinutes = Math.floor(totalSeconds / 60)\n  const hours = Math.floor(totalMinutes / 60)\n  const remainMin = totalMinutes % 60\n  const summary: PhoneUsageSummary = {\n    totalMinutes: totalMinutes,\n    totalSeconds: totalSeconds,\n    hourText: hours + ' 小时',\n    minuteText: remainMin + ' 分钟',\n    appCount: items.length\n  }\n\n  if (totalSeconds < 1) {\n    const noSegResult: PhoneUsageFromSystem = { summary, segments: [] }\n    return noSegResult\n  }\n\n  // 构造 segments（与 getTodayPieSegments 同样的逻辑）\n  const segments: PieSegment[] = []\n  let start = 0\n  const cap = items.length > 10 ? 10 : items.length\n  for (let i = 0; i < cap; i++) {\n    const item = items[i]\n    const pct = (item.foregroundSec / totalSeconds) * 100\n    const end = start + pct\n    const color: string = i < PALETTE.length ? (PALETTE[i] as string) : '#BDC3C7'\n    const seg: PieSegment = {\n      pkg: item.packageName,\n      label: item.appLabel.length > 0 ? item.appLabel : item.packageName,\n      minutes: item.minutes,\n      percent: Math.round(pct * 10) / 10,\n      color: color,\n      startAngle: start,\n      endAngle: end\n    }\n    segments.push(seg)\n    start = end\n  }\n  if (items.length > cap) {\n    let othersMin = 0\n    for (let i = cap; i < items.length; i++) {\n      othersMin += items[i].minutes\n    }\n    const pct = 100 - start\n    const seg: PieSegment = {\n      pkg: '__others__',\n      label: '其他',\n      minutes: othersMin,\n      percent: Math.round(pct * 10) / 10,\n      color: '#BDC3C7',\n      startAngle: start,\n      endAngle: 100\n    }\n    segments.push(seg)\n  }\n  const finalResult: PhoneUsageFromSystem = { summary, segments }\n  return finalResult\n}\n\n","<template>\n  <view class=\"chart-wrapper\" :style=\"{ height: wrapperH + 'px' }\">\n    <view class=\"header-row\">\n      <text class=\"header-month\">{{ monthLabel }}</text>\n    </view>\n    <view class=\"grid-area\">\n      <view class=\"weekday-col\">\n        <view v-for=\"(d, di) in weekdayLabels\" :key=\"'wd-' + di\" class=\"weekday-cell\">\n          <text class=\"weekday-text\">{{ d }}</text>\n        </view>\n      </view>\n      <view class=\"cells-col\">\n        <view\n          v-for=\"(row, ri) in cellGrid\"\n          :key=\"'r-' + ri\"\n          class=\"cell-row\"\n        >\n          <view\n            v-for=\"(cell, ci) in row\"\n            :key=\"'c-' + ri + '-' + ci\"\n            class=\"cell\"\n            :class=\"cell.day == null ? 'cell-empty' : 'cell-filled'\"\n            :style=\"cellStyle(cell.count)\"\n          >\n            <text v-if=\"cell.day != null\" class=\"cell-text\" :class=\"cell.count > 0 ? 'cell-text-on' : 'cell-text-off'\">{{ cell.day }}</text>\n          </view>\n        </view>\n      </view>\n    </view>\n    <view class=\"legend-row\">\n      <text class=\"legend-text\">少</text>\n      <view class=\"legend-cell\" style=\"background-color: rgba(219, 200, 237, 0.16);\"></view>\n      <view class=\"legend-cell\" style=\"background-color: #9A86D6;\"></view>\n      <view class=\"legend-cell\" style=\"background-color: #8DA2FF;\"></view>\n      <view class=\"legend-cell\" style=\"background-color: #8FF0C3;\"></view>\n      <text class=\"legend-text\">多</text>\n    </view>\n  </view>\n</template>\n\n<script setup lang=\"uts\">\ntype CellInfo = {\n  day: number | null\n  count: number\n}\n\nconst props = withDefaults(defineProps<{\n  dates: string[]\n  counts: number[]\n  height: number\n}>(), {\n  dates: () => [],\n  counts: () => [],\n  height: 220\n})\n\nconst wrapperH = props.height\nconst weekdayLabels: string[] = ['一', '', '三', '', '五', '', '日']\n\nfunction getMonthLabel(): string {\n  if (props.dates.length < 1) return ''\n  const first = props.dates[0]\n  if (first == null) return ''\n  const parts = first.split('-')\n  return parts[0] + ' 年 ' + (parseInt(parts[1] as string)) + ' 月'\n}\n\nfunction getCellGrid(): CellInfo[][] {\n  const rows: CellInfo[][] = []\n  let firstDayOfWeek = 0\n  if (props.dates.length > 0) {\n    const first = props.dates[0]\n    if (first != null) {\n      const parts = first.split('-')\n      const yy = parseInt(parts[0] as string)\n      const mm = parseInt(parts[1] as string) - 1\n      const dd = parseInt(parts[2] as string)\n      const fd = new Date(yy, mm, dd)\n      let dow = fd.getDay()\n      if (dow < 1) dow = 7\n      firstDayOfWeek = dow - 1\n    }\n  }\n\n  for (let i = 0; i < props.dates.length; i++) {\n    const pos = i + firstDayOfWeek\n    const r = Math.floor(pos / 7)\n    const c = pos % 7\n    while (rows.length <= r) {\n      const row: CellInfo[] = []\n      for (let k = 0; k < 7; k++) row.push({ day: null, count: 0 })\n      rows.push(row)\n    }\n    const targetRow = rows[r]\n    if (targetRow == null) continue\n    const dateStr = props.dates[i]\n    if (dateStr == null) continue\n    const parts = dateStr.split('-')\n    const day = parseInt(parts[2] as string)\n    const cnt = i < props.counts.length ? (props.counts[i] as number) : 0\n    targetRow[c] = { day: day, count: cnt }\n  }\n  return rows\n}\n\nconst monthLabel = computed<string>(getMonthLabel)\nconst cellGrid = computed<CellInfo[][]>(getCellGrid)\n\nfunction cellStyle(count: number): UTSJSONObject {\n  if (count >= 5) return { backgroundColor: '#8FF0C3' }\n  if (count >= 3) return { backgroundColor: '#8DA2FF' }\n  if (count >= 1) return { backgroundColor: '#9A86D6' }\n  return { backgroundColor: 'rgba(219, 200, 237, 0.16)' }\n}\n</script>\n\n<style scoped>\n.chart-wrapper { flex-direction: column; width: 100%; background-color: transparent; border-radius: 10px; padding: 8px 8px 4px 8px; }\n.header-row { padding: 0 4px 6px 4px; }\n.header-month { font-size: 13px; font-weight: bold; color: #FFFFFF; }\n.grid-area { flex-direction: row; flex: 1; }\n.weekday-col { width: 20px; flex-direction: column; padding-top: 0px; }\n.weekday-cell { height: 32px; align-items: center; justify-content: center; margin-bottom: 4px; }\n.weekday-text { font-size: 9px; color: rgba(255, 255, 255, 0.56); }\n.cells-col { flex: 1; flex-direction: column; padding-left: 4px; min-height: 200px; }\n.cell-row { flex-direction: row; margin-bottom: 4px; height: 32px; }\n.cell { width: 32px; height: 32px; margin-right: 4px; border-radius: 8px; align-items: center; justify-content: center; background-color: rgba(255, 255, 255, 0.1); }\n.cell-empty { background-color: transparent; }\n.cell-filled { border-width: 1px; border-color: rgba(219, 200, 237, 0.18); border-style: solid; }\n.cell-text { font-size: 10px; font-weight: 500; }\n.cell-text-on { color: #111832; }\n.cell-text-off { color: rgba(255, 255, 255, 0.56); }\n.legend-row { flex-direction: row; align-items: center; justify-content: center; padding: 8px 0 4px 0; }\n.legend-text { font-size: 10px; color: rgba(255, 255, 255, 0.58); margin: 0 6px; }\n.legend-cell { width: 12px; height: 12px; border-radius: 3px; margin: 0 2px; }\n</style>\n","import { MicroAction } from '../models/MicroAction'\nimport { getEnabledActions } from './ActionManager'\nimport { getTodayLogs } from '../database/ActionLogDao'\nimport { currentHour } from '../utils/TimeUtils'\n\ntype ScoredItem = {\n  action: MicroAction\n  score: number\n}\n\nexport function getRecommendedActions(): MicroAction[] {\n  const enabledActions = getEnabledActions()\n  if (enabledActions.length.toInt() < 1) return []\n\n  const hour = currentHour()\n  const todayLogs = getTodayLogs()\n\n  const categoryCount: Map<string, number> = new Map<string, number>()\n  for (const action of enabledActions) {\n    categoryCount.set(action.category, 0)\n  }\n  for (const log of todayLogs) {\n    if (log.result === 'completed' || log.result === 'self_reported') {\n      const current = categoryCount.get(log.action_type)\n      if (current != null) {\n        categoryCount.set(log.action_type, current + 1)\n      }\n    }\n  }\n\n  let minCategory = ''\n  let minCount: number = 999999999\n  const allCats: string[] = ['护眼', '肩颈', '核心', '下肢', '呼吸']\n  for (let i = 0; i < allCats.length; i++) {\n    const cnt = categoryCount.get(allCats[i])\n    if (cnt != null && cnt < minCount) {\n      minCount = cnt\n      minCategory = allCats[i]\n    }\n  }\n\n  const preferredTypes = getPreferredTypes(hour)\n\n  const scored: ScoredItem[] = enabledActions.map((a: MicroAction): ScoredItem => {\n    const rawCount = categoryCount.get(a.category)\n    const catCount = rawCount != null ? rawCount : 0\n    const isPreferred = preferredTypes.indexOf(a.category) >= 0 ? 0 : 1\n    const isMinCategory = a.category === minCategory ? -1 : 0\n    const item: ScoredItem = { action: a, score: catCount + isPreferred + isMinCategory }\n    return item\n  })\n\n  scored.sort((a: ScoredItem, b: ScoredItem): number => a.score - b.score)\n  return scored.slice(0, 3).map((s: ScoredItem): MicroAction => s.action)\n}\n\nfunction getPreferredTypes(hour: number): string[] {\n  if (hour >= 22 || hour < 7) return ['护眼', '呼吸', '肩颈']\n  if (hour >= 7 && hour <= 12) return ['肩颈', '核心', '护眼']\n  if (hour >= 13 && hour <= 18) return ['核心', '下肢', '护眼']\n  return ['护眼', '肩颈', '呼吸']\n}\n","export type LlmCache = {\n  cache_key: string\n  cache_type: string\n  response: string\n  model: string\n  created_at: number\n  expires_at: number\n}\n","import { dbManager } from './DatabaseManager'\nimport { LlmCache } from '../models/LlmCache'\nimport { getNum, getStr } from '../utils/DbRowUtils'\n\nexport function getByKey(key: string): LlmCache | null {\n  const row = dbManager.queryOne('SELECT * FROM llm_cache WHERE cache_key = ?', [key])\n  if (row == null) return null\n  return mapRow(row)\n}\n\nexport function save(key: string, type: string, response: string, expiresAt: number): void {\n  dbManager.execSql(\n    'INSERT OR REPLACE INTO llm_cache (cache_key, cache_type, response, expires_at, created_at) VALUES (?,?,?,?,?)',\n    [key, type, response, expiresAt, Math.floor(Date.now() / 1000)]\n  )\n}\n\nexport function cleanExpired(): void {\n  dbManager.delete('llm_cache', 'expires_at < ?', [Math.floor(Date.now() / 1000)])\n}\n\nfunction mapRow(row: Map<string, any>): LlmCache {\n  return {\n    cache_key: getStr(row, 'cache_key'),\n    cache_type: getStr(row, 'cache_type'),\n    response: getStr(row, 'response'),\n    model: getStr(row, 'model'),\n    created_at: getNum(row, 'created_at'),\n    expires_at: getNum(row, 'expires_at')\n  }\n}\n","export function isNetworkAvailable(): boolean {\n  return true\n}\n","import { getHomepageData } from './ScoreCalculator'\nimport { daysAgo } from '../utils/TimeUtils'\nimport { callWeekly } from './CloudService'\nimport { isNetworkAvailable } from '../utils/NetworkUtils'\nimport { WeeklyReport, WeeklyReportStats } from '../models/WeeklyReport'\n\nexport function generateWeeklyData(): WeeklyReportStats {\n  let totalCompleted = 0\n  let totalDurationSec = 0\n  let totalPenetration = 0\n  let totalGuardMinutes = 0\n  let bestDay = ''\n  let bestDayCount = -1\n  let worstDay = ''\n  let worstDayCount = 999999\n  let daysWithData = 0\n\n  for (let i = 6; i >= 0; i--) {\n    const d = daysAgo(i)\n    const data = getHomepageData(d)\n    totalCompleted += data.todayCompletedCount\n    totalDurationSec += data.guardCount * 60\n    totalPenetration += data.penetration\n    totalGuardMinutes += data.guardCount\n\n    if (data.todayCompletedCount > 0) {\n      daysWithData++\n    }\n\n    if (data.todayCompletedCount > bestDayCount) {\n      bestDayCount = data.todayCompletedCount\n      bestDay = d\n    }\n\n    if (data.todayCompletedCount < worstDayCount && data.todayCompletedCount >= 0) {\n      worstDayCount = data.todayCompletedCount\n      worstDay = d\n    }\n  }\n\n  if (daysWithData < 1) {\n    return {\n      totalCompleted: 0,\n      totalDurationSec: 0,\n      avgPenetration: 0,\n      avgGuardMinutes: 0,\n      bestDay: '',\n      bestDayCount: 0,\n      worstDay: '',\n      worstDayCount: 0\n    }\n  }\n\n  return {\n    totalCompleted: totalCompleted,\n    totalDurationSec: totalDurationSec,\n    avgPenetration: Math.round(totalPenetration / 7 * 100) / 100,\n    avgGuardMinutes: Math.round(totalGuardMinutes / 7),\n    bestDay: bestDay,\n    bestDayCount: bestDayCount,\n    worstDay: worstDay,\n    worstDayCount: worstDayCount\n  }\n}\n\nfunction cleanMarkdown(raw: string): string {\n  if (raw == null) return ''\n  let text = raw\n  text = text.replace(/^```[\\s\\S]*?\\n/, '')\n  text = text.replace(/```$/, '')\n  text = text.replace(/^#+\\s*/gm, '')\n  text = text.replace(/\\*\\*([^*]+)\\*\\*/g, '$1')\n  text = text.replace(/\\*([^*]+)\\*/g, '$1')\n  text = text.replace(/`([^`]+)`/g, '$1')\n  text = text.replace(/[ \\t]+\\n/g, '\\n')\n  text = text.replace(/\\n{3,}/g, '\\n\\n')\n  return text.trim()\n}\n\nfunction buildLocalReport(stats: WeeklyReportStats): WeeklyReport {\n  const hasData = stats.totalCompleted > 0\n  if (hasData) {\n    const body = '本周完成了 ' + stats.totalCompleted + ' 次微动作，累计守护 ' +\n      Math.round(stats.totalDurationSec / 60) + ' 分钟。\\n\\n' +\n      '你的平均每日守护时长为 ' + stats.avgGuardMinutes + ' 分钟，整体节奏稳定。' +\n      '表现值得肯定。\\n\\n' +\n      '下周可以尝试每天固定时间做一个微动作，把守护变成习惯。\\n\\n' +\n      '目标：每天至少完成 3 次微动作。'\n    return { bodyMarkdown: body, stats: stats }\n  }\n  const body = '本周暂无数据，从今天开始吧。\\n\\n' +\n    '完成你的第一个微动作，开启健康守护之旅。\\n\\n' +\n    '开启无障碍服务以自动提醒，设定你的健康偏好。\\n\\n' +\n    '目标：开始你的第一个微动作。'\n  return { bodyMarkdown: body, stats: stats }\n}\n\nexport function generateWeeklyReport(onComplete: (report: WeeklyReport) => void): void {\n  const stats = generateWeeklyData()\n\n  if (!isNetworkAvailable()) {\n    onComplete(buildLocalReport(stats))\n    return\n  }\n\n  callWeekly(stats, (raw: string): void => {\n    try {\n      const cleaned = cleanMarkdown(raw)\n      if (cleaned.length > 10) {\n        onComplete({ bodyMarkdown: cleaned, stats: stats })\n        return\n      }\n      __f__('warn','at services/WeeklyReportService.uts:113','[WeeklyReportService] LLM 返回内容过短, fallback')\n    } catch (e) {\n      __f__('warn','at services/WeeklyReportService.uts:115','[WeeklyReportService] 处理失败, fallback: ' + JSON.stringify(e))\n    }\n    onComplete(buildLocalReport(stats))\n  }, () => {\n    onComplete(buildLocalReport(stats))\n  })\n}\n","import { getHomepageData, saveTodaySummary } from '../services/ScoreCalculator'\nimport { getRecommendedActions } from '../services/Recommendation'\nimport { MicroAction } from '../models/MicroAction'\nimport { today, yesterday, getHour } from '../utils/TimeUtils'\nimport { getByKey, save } from '../database/LlmCacheDao'\nimport { getInt, getSetting } from '../database/SettingsDao'\nimport { isNetworkAvailable } from '../utils/NetworkUtils'\nimport { DailyCount } from '../models/DailyCount'\nimport { callDaily } from '../services/CloudService'\nimport { DailyData } from '../models/DailySummary'\nimport { WeeklyReport } from '../models/WeeklyReport'\nimport { generateWeeklyReport } from '../services/WeeklyReportService'\nimport { getTodayTotalUsageMinutes } from '../database/AppUsageDao'\nimport * as LlmHistoryDao from '../database/LlmHistoryDao'\nimport { LlmHistoryEntry } from '../models/LlmHistoryEntry'\nimport { AchievementItem } from '../models/Achievement'\nimport * as AchievementService from '../services/AchievementService'\n\nexport type DailyOutput = {\n  bodyText: string\n}\n\nexport type AppStore = {\n  eyeScore: Ref<number>\n  eyeStatus: Ref<string>\n  postureScore: Ref<number>\n  postureStatus: Ref<string>\n  vitalityScore: Ref<number>\n  vitalityStatus: Ref<string>\n  guardCount: Ref<number>\n  penetration: Ref<number>\n  phoneMinutes: Ref<number>\n  todayCompletedCount: Ref<number>\n  recommendedActions: Ref<MicroAction[]>\n  heatmapData: Ref<DailyCount[]>\n  dailySummary: Ref<DailyOutput | null>\n  dailySummaryLoading: Ref<boolean>\n  homeDataLoaded: Ref<boolean>\n  weeklyReport: Ref<WeeklyReport | null>\n  weeklyReportLoading: Ref<boolean>\n  llmHistory: Ref<LlmHistoryEntry[]>\n  achievements: Ref<AchievementItem[]>\n  pendingUnlockIds: Ref<string[]>\n  refreshHomeData(): void\n  refreshWeeklyReport(): void\n  refreshLlmHistory(): void\n  refreshAchievements(): void\n  setPendingUnlocks(ids: string[]): void\n  shiftPendingUnlock(): void\n}\n\nconst eyeScore = ref<number>(0)\nconst eyeStatus = ref<string>('no_data')\nconst postureScore = ref<number>(0)\nconst postureStatus = ref<string>('no_data')\nconst vitalityScore = ref<number>(0)\nconst vitalityStatus = ref<string>('no_data')\nconst guardCount = ref<number>(0)\nconst penetration = ref<number>(0)\nconst phoneMinutes = ref<number>(0)\nconst todayCompletedCount = ref<number>(0)\nconst recommendedActions = ref<MicroAction[]>([])\nconst heatmapData = ref<DailyCount[]>([])\nconst dailySummary = ref<DailyOutput | null>(null)\nconst dailySummaryLoading = ref<boolean>(false)\nconst homeDataLoaded = ref<boolean>(false)\nconst weeklyReport = ref<WeeklyReport | null>(null)\nconst weeklyReportLoading = ref<boolean>(false)\nconst llmHistory = ref<LlmHistoryEntry[]>([])\nconst achievements = ref<AchievementItem[]>([])\nconst pendingUnlockIds = ref<string[]>([])\n\nfunction emptySeenSet(): Set<string> {\n  return new Set<string>()\n}\n\nfunction refreshAchievementsFn(): void {\n  try {\n    achievements.value = AchievementService.getAchievementItems(emptySeenSet())\n  } catch (e) {\n    __f__('warn','at stores/appStore.uts:81','[appStore] refreshAchievements 失败 type=' + (typeof e) + ' msg=' + (e != null ? ('' + e) : 'null'))\n    achievements.value = []\n  }\n}\n\nfunction setPendingUnlocksFn(ids: string[]): void {\n  pendingUnlockIds.value = ids\n}\n\nfunction shiftPendingUnlockFn(): void {\n  if (pendingUnlockIds.value.length < 1) return\n  const newArr: string[] = []\n  for (let i = 1; i < pendingUnlockIds.value.length; i++) {\n    newArr.push(pendingUnlockIds.value[i])\n  }\n  pendingUnlockIds.value = newArr\n}\n\nfunction refreshLlmHistory(): void {\n  try {\n    llmHistory.value = LlmHistoryDao.getAllHistory(200)\n  } catch (e) {\n    __f__('warn','at stores/appStore.uts:103','[appStore] refreshLlmHistory 失败: ' + JSON.stringify(e))\n    llmHistory.value = []\n  }\n}\n\nexport function useAppStore(): AppStore {\n  const store: AppStore = {\n    eyeScore,\n    eyeStatus,\n    postureScore,\n    postureStatus,\n    vitalityScore,\n    vitalityStatus,\n    guardCount,\n    penetration,\n    phoneMinutes,\n    todayCompletedCount,\n    recommendedActions,\n    heatmapData,\n    dailySummary,\n    dailySummaryLoading,\n    homeDataLoaded,\n    weeklyReport,\n    weeklyReportLoading,\n    llmHistory,\n    achievements,\n    pendingUnlockIds,\n\n    refreshLlmHistory(): void {\n      refreshLlmHistory()\n    },\n\n    refreshAchievements(): void {\n      refreshAchievementsFn()\n    },\n\n    setPendingUnlocks(ids: string[]): void {\n      setPendingUnlocksFn(ids)\n    },\n\n    shiftPendingUnlock(): void {\n      shiftPendingUnlockFn()\n    },\n\n    refreshHomeData(): void {\n      homeDataLoaded.value = false\n      try {\n        const date = today()\n        const nowMs = Date.now()\n\n        try { saveTodaySummary() } catch (_) {}\n        const data = getHomepageData(date)\n        try { phoneMinutes.value = getTodayTotalUsageMinutes() } catch (_) {}\n\n        eyeScore.value = Math.round(data.eyeScore)\n        eyeStatus.value = data.eyeLevel\n        postureScore.value = Math.round(data.postureScore)\n        postureStatus.value = data.postureLevel\n        vitalityScore.value = Math.round(data.vitalityScore)\n        vitalityStatus.value = data.vitalityLevel\n        guardCount.value = data.guardCount\n        penetration.value = Math.round(data.penetration * 100) / 100\n        todayCompletedCount.value = data.todayCompletedCount\n        heatmapData.value = data.heatmapData\n\n        const todayKey = 'daily_summary:' + date\n        const todayCache = getByKey(todayKey)\n        if (todayCache != null) {\n          try {\n            const parsed = JSON.parse(todayCache.response)\n            dailySummary.value = parsed as DailyOutput\n          } catch (_) {}\n          dailySummaryLoading.value = false\n        } else {\n          dailySummaryLoading.value = true\n          generateDailySummary(date, (summary: DailyOutput) => {\n            save(todayKey, 'daily_summary', JSON.stringify(summary), nowMs + 7 * 24 * 3600 * 1000)\n            dailySummary.value = summary\n            dailySummaryLoading.value = false\n          })\n        }\n\n        const yDate = yesterday()\n        const yesterdayKey = 'daily_summary:' + yDate\n        if (getByKey(yesterdayKey) == null) {\n          const ydata = getHomepageData(yDate)\n          const fallback: DailyOutput = {\n            bodyText: '昨日完成' + ydata.todayCompletedCount + '次微动作，累计' + ydata.guardCount + '次。\\n\\n今天继续加油！'\n          }\n          save(yesterdayKey, 'daily_summary', JSON.stringify(fallback), nowMs + 30 * 24 * 3600 * 1000)\n        }\n      } catch (_) {}\n      try {\n        recommendedActions.value = getRecommendedActions()\n      } catch (_) {}\n      homeDataLoaded.value = true\n    },\n\n    refreshWeeklyReport(): void {\n      weeklyReportLoading.value = true\n      generateWeeklyReport((report: WeeklyReport) => {\n        weeklyReport.value = report\n        weeklyReportLoading.value = false\n      })\n    }\n  }\n  return store\n}\n\n// 每日小结 LLM 调用冷却：1h 内不重复调\nlet lastDailySummaryAt: number = 0\nconst DAILY_SUMMARY_COOLDOWN_MS: number = 60 * 60 * 1000\n\nfunction buildLocalSummary(completedCount: number, count: number): DailyOutput {\n  if (completedCount > 0) {\n    return {\n      bodyText: '今天已经完成' + completedCount + '次微动作，累计守护' + count + '次。\\n\\n保持节奏，明天继续！'\n    }\n  }\n  return {\n    bodyText: '今天还在热身区蓄力中~\\n\\n没有关系，明天只需要完成1次小动作就算是胜利啦。从零到一是最酷的跨越！'\n  }\n}\n\nfunction generateDailySummary(date: string, onComplete: (summary: DailyOutput) => void): void {\n  // 1h 冷却：上次调用后 1h 内不再调 LLM，直接返回本地降级\n  const nowMs = Date.now()\n  if (lastDailySummaryAt > 0 && nowMs - lastDailySummaryAt < DAILY_SUMMARY_COOLDOWN_MS) {\n    const data = getHomepageData(date)\n    onComplete(buildLocalSummary(data.todayCompletedCount, data.guardCount))\n    return\n  }\n\n  const data = getHomepageData(date)\n\n  if (!isNetworkAvailable()) {\n    onComplete(buildLocalSummary(data.todayCompletedCount, data.guardCount))\n    return\n  }\n\n  const dto: DailyData = {\n    totalCompleted: data.todayCompletedCount,\n    totalSkipped: 0,\n    totalDurationSec: 0,\n    guardMinutes: 0,\n    guardCount: data.guardCount,\n    penetration: data.penetration,\n    eyeScore: Math.max(0, Math.round(data.eyeScore)),\n    postureScore: Math.max(0, Math.round(data.postureScore)),\n    vitalityScore: Math.max(0, Math.round(data.vitalityScore)),\n    todayCompletedCount: data.todayCompletedCount\n  }\n\n  callDaily(date, dto, (raw: string): void => {\n    if (raw.length > 10) {\n      lastDailySummaryAt = Date.now()  // 记录成功调用时刻\n      onComplete({ bodyText: raw })\n      return\n    }\n    onComplete(buildLocalSummary(data.todayCompletedCount, data.guardCount))\n  }, () => {\n    onComplete(buildLocalSummary(data.todayCompletedCount, data.guardCount))\n  })\n}\n","export function getGreetingHint(hour: number): string {\n  if (hour < 6) return '夜深了，小星球建议把屏幕放远一点，给眼睛留条回家的路'\n  if (hour < 9) return '早晨先慢慢亮起来，今天也从一个很小的照顾开始'\n  if (hour < 12) return '上午专注力在线，也记得偶尔眨眨眼、松松肩'\n  if (hour < 14) return '午间适合轻轻重启一下，别让身体一直待机'\n  if (hour < 18) return '下午的小疲惫很正常，做个 10 秒动作就能缓一缓'\n  if (hour < 22) return '晚上别和屏幕硬撑，给眼睛和肩颈一点余地'\n  return '夜深了，小星球会轻一点提醒，也希望你早点休息'\n}\n\nexport function getExecuteIntro(actionId: string): string {\n  if (actionId == 'eye_blink') return '给眼睛补一点水分，轻轻眨几下就好'\n  if (actionId == 'eye_rotate') return '让眼球慢慢活动一圈，别急着用力'\n  if (actionId == 'neck_rotate') return '把脖子从固定姿势里慢慢请出来'\n  if (actionId == 'shoulder_roll') return '肩膀向后画个小圈，把紧绷放下'\n  if (actionId == 'neck_stretch') return '坐直一点，给肩颈一段温柔拉伸'\n  if (actionId == 'core_tighten') return '唤醒核心肌群，像给身体按下稳定键'\n  if (actionId == 'heel_raise') return '让小腿和脚踝动起来，顺便叫醒循环'\n  if (actionId == 'deep_breath') return '慢慢吸气，再慢慢呼出，把节奏降下来'\n  if (actionId == 'far_gaze') return '看向远处，让眼睛从近距离里松一口气'\n  return '跟着小星球做一个短短的微动作'\n}\n\nexport function getExecuteGuide(actionId: string): string {\n  if (actionId == 'eye_blink') return '轻闭双眼 2 秒再睁开，重复几次，保持自然呼吸'\n  if (actionId == 'eye_rotate') return '眼球缓慢顺时针转一圈，再逆时针转一圈'\n  if (actionId == 'neck_rotate') return '肩膀放松，头慢慢转向一侧，停一下再回正'\n  if (actionId == 'shoulder_roll') return '双肩向上提起，再向后画圈放下，动作放慢'\n  if (actionId == 'neck_stretch') return '头轻轻侧向一边，感受肩颈外侧被拉长'\n  if (actionId == 'core_tighten') return '收紧腹部和骨盆底，保持自然呼吸，不要憋气'\n  if (actionId == 'heel_raise') return '双脚踩稳，慢慢踮起脚跟，再控制速度落回'\n  if (actionId == 'deep_breath') return '鼻吸 4 秒，让腹部鼓起；口呼 6 秒，慢慢送出'\n  if (actionId == 'far_gaze') return '看向 6 米外的固定目标，放松眉心和眼周'\n  return '保持放松、缓慢和可控，跟随倒计时完成动作'\n}\n","<template>\n  <view class=\"page\">\n    <view class=\"page-bg\">\n      <image class=\"page-bg-img\" src=\"/static/images/micro-habit-page-bg.png\" mode=\"aspectFill\"></image>\n    </view>\n    <view class=\"header\">\n      <view class=\"header-left\" @tap=\"goBack\">\n        <text class=\"header-back\">‹</text>\n      </view>\n      <text class=\"header-title\">调试日志</text>\n      <view class=\"header-right\" @tap=\"refresh\">\n        <text class=\"header-refresh\">↻</text>\n      </view>\n    </view>\n\n    <view class=\"stats-row\">\n      <view class=\"stat-card\">\n        <text class=\"stat-num\">{{ triggerLogs.length }}</text>\n        <text class=\"stat-label\">今日触发</text>\n      </view>\n      <view class=\"stat-card\">\n        <text class=\"stat-num\">{{ actionLogs.length }}</text>\n        <text class=\"stat-label\">今日动作</text>\n      </view>\n      <view class=\"stat-card\">\n        <text class=\"stat-num\">{{ completedCount }}</text>\n        <text class=\"stat-label\">完成数</text>\n      </view>\n      <view class=\"stat-card\">\n        <text class=\"stat-num\">{{ skippedCount }}</text>\n        <text class=\"stat-label\">跳过数</text>\n      </view>\n    </view>\n\n    <view class=\"tab-bar\">\n      <view class=\"tab\" :class=\"{ active: currentTab === 'trigger' }\" @tap=\"switchTab('trigger')\">\n        <text class=\"tab-text\">触发日志</text>\n      </view>\n      <view class=\"tab\" :class=\"{ active: currentTab === 'action' }\" @tap=\"switchTab('action')\">\n        <text class=\"tab-text\">动作日志</text>\n      </view>\n      <view class=\"tab\" :class=\"{ active: currentTab === 'db' }\" @tap=\"switchTab('db')\">\n        <text class=\"tab-text\">数据库</text>\n      </view>\n      <view class=\"tab\" :class=\"{ active: currentTab === 'config' }\" @tap=\"switchTab('config')\">\n        <text class=\"tab-text\">配置</text>\n      </view>\n    </view>\n\n    <scroll-view class=\"log-scroll\" scroll-y=\"true\">\n      <view v-if=\"currentTab === 'trigger'\">\n        <view v-if=\"triggerLogs.length < 1\" class=\"empty\">\n          <text class=\"empty-text\">今日暂无触发记录</text>\n          <text class=\"empty-hint\">去使用某个 App 1 分钟以上会触发提醒</text>\n        </view>\n        <view v-for=\"(log, idx) in triggerLogs\" :key=\"log.id\" class=\"log-item\">\n          <view class=\"log-row1\">\n            <text class=\"log-time\">{{ formatTime(log.created_at) }}</text>\n            <text class=\"log-tag\" :class=\"'tag-' + log.trigger_type\">{{ formatTriggerType(log.trigger_type) }}</text>\n            <text class=\"log-level\">{{ formatTriggerLevel(log.trigger_level) }}</text>\n          </view>\n          <view class=\"log-row2\">\n            <text class=\"log-field-label\">动作：</text>\n            <text class=\"log-field-val\">{{ formatActionId(log.action_id) }}</text>\n          </view>\n          <view class=\"log-row2\">\n            <text class=\"log-field-label\">App：</text>\n            <text class=\"log-field-val\">{{ formatStr(log.app_package) }}</text>\n            <text class=\"log-field-label\" style=\"margin-left:12px;\">连续：</text>\n            <text class=\"log-field-val\">{{ log.continuous_minutes }}分</text>\n          </view>\n          <view class=\"log-row3\">\n            <text class=\"log-field-label\">用户操作：</text>\n            <text class=\"log-user-action\" :class=\"'ua-' + log.user_action\">{{ formatUserAction(log.user_action) }}</text>\n          </view>\n        </view>\n      </view>\n\n      <view v-if=\"currentTab === 'action'\">\n        <view v-if=\"actionLogs.length < 1\" class=\"empty\">\n          <text class=\"empty-text\">今日暂无动作记录</text>\n          <text class=\"empty-hint\">点击首页\"全部微动作库\"开始第一次动作</text>\n        </view>\n        <view v-for=\"(log, idx) in actionLogs\" :key=\"log.id\" class=\"log-item\">\n          <view class=\"log-row1\">\n            <text class=\"log-time\">{{ formatTime(log.created_at) }}</text>\n            <text class=\"log-tag\" :class=\"'tag-' + log.trigger_type\">{{ formatTriggerType(log.trigger_type) }}</text>\n            <text class=\"log-result\" :class=\"'res-' + log.result\">{{ formatResult(log.result) }}</text>\n          </view>\n          <view class=\"log-row2\">\n            <text class=\"log-field-label\">动作ID：</text>\n            <text class=\"log-field-val\">{{ formatActionId(log.action_id) }}</text>\n            <text class=\"log-field-label\" style=\"margin-left:12px;\">分类：</text>\n            <text class=\"log-field-val\">{{ formatActionType(log.action_type) }}</text>\n          </view>\n          <view class=\"log-row2\">\n            <text class=\"log-field-label\">用时：</text>\n            <text class=\"log-field-val\">{{ formatDuration(log.duration_ms) }} / {{ formatDuration(log.target_ms) }}</text>\n            <text class=\"log-field-label\" style=\"margin-left:12px;\">等级：</text>\n            <text class=\"log-field-val\">{{ formatTriggerLevel(log.trigger_level) }}</text>\n          </view>\n          <view v-if=\"log.skip_reason != null && log.skip_reason.length > 0\" class=\"log-row3\">\n            <text class=\"log-field-label\">跳过原因：</text>\n            <text class=\"log-skip-reason\">{{ formatSkipReason(log.skip_reason) }}</text>\n          </view>\n        </view>\n      </view>\n\n      <view v-if=\"currentTab === 'db'\">\n        <view class=\"section-header\">\n          <text class=\"section-header-text\">数据库表概览</text>\n        </view>\n        <view v-for=\"(info, idx) in dbTableInfos\" :key=\"idx\" class=\"db-table-card\">\n          <view class=\"db-table-row\">\n            <text class=\"db-table-name\">{{ formatTableName(info.name) }}</text>\n            <text class=\"db-table-count\">{{ info.count }} 行</text>\n          </view>\n        </view>\n        <view class=\"section-header\">\n          <text class=\"section-header-text\">最新动作日志（最近5条）</text>\n        </view>\n        <view v-for=\"(log, idx) in dbRecentActions\" :key=\"'ra-' + idx\" class=\"log-item\">\n          <view class=\"log-row1\">\n            <text class=\"log-time\">{{ formatTime(log.created_at) }}</text>\n            <text class=\"log-tag tag-manual\">{{ formatActionId(log.action_id) }}</text>\n            <text class=\"log-result\" :class=\"'res-' + log.result\">{{ formatResult(log.result) }}</text>\n          </view>\n          <view class=\"log-row2\">\n            <text class=\"log-field-val\">{{ formatActionType(log.action_type) }} · {{ formatDuration(log.duration_ms) }} · {{ formatTriggerType(log.trigger_type) }}</text>\n          </view>\n        </view>\n      </view>\n\n      <view v-if=\"currentTab === 'config'\">\n        <view class=\"section-header\">\n          <text class=\"section-header-text\">用户设置</text>\n        </view>\n        <view v-if=\"configList.length < 1\" class=\"empty\">\n          <text class=\"empty-text\">暂无配置数据</text>\n        </view>\n        <view v-for=\"(item, idx) in configList\" :key=\"idx\" class=\"config-item\">\n          <view class=\"config-row\">\n            <text class=\"config-key\">{{ formatConfigKey(item.key) }}</text>\n            <text class=\"config-val\">{{ formatConfigValue(item.key, item.value) }}</text>\n          </view>\n        </view>\n      </view>\n    </scroll-view>\n  </view>\n</template>\n\n<script setup lang=\"uts\">\nimport { getTodayTriggerLogs } from '../../database/TriggerLogDao'\nimport { getTodayLogs, countCompletedToday, countSkippedToday } from '../../database/ActionLogDao'\nimport { TriggerLog, UserAction } from '../../models/TriggerLog'\nimport { ActionLog, ActionResult } from '../../models/ActionLog'\nimport { dbManager } from '../../database/DatabaseManager'\nimport { getActionById } from '../../constants/Actions'\n\nconst triggerLogs = ref<TriggerLog[]>([])\nconst actionLogs = ref<ActionLog[]>([])\nconst completedCount = ref<number>(0)\nconst skippedCount = ref<number>(0)\nconst currentTab = ref<string>('trigger')\n\nconst KNOWN_TABLES: string[] = [\n  'action_logs', 'trigger_logs', 'user_settings',\n  'daily_summaries', 'app_usage_snapshots',\n  'tts_cache', 'heartbeat_logs', 'llm_cache',\n  'llm_history', 'app_tags', 'effective_rules'\n]\n\ntype DbTableInfo = { name: string, count: number }\nconst dbTableInfos = ref<DbTableInfo[]>([])\nconst dbRecentActions = ref<ActionLog[]>([])\n\ntype ConfigItem = { key: string, value: string }\nconst configList = ref<ConfigItem[]>([])\n\nfunction pad2(n: number): string {\n  return n < 10 ? '0' + n : '' + n\n}\n\nfunction formatTime(t: number): string {\n  if (t == null || t <= 0) return '-'\n  const d = new Date(t * 1000)\n  const yyyy = d.getFullYear()\n  const mm = d.getMonth() + 1\n  const dd = d.getDate()\n  const hh = d.getHours()\n  const mi = d.getMinutes()\n  const ss = d.getSeconds()\n  return yyyy + '-' + pad2(mm) + '-' + pad2(dd) + ' ' + pad2(hh) + ':' + pad2(mi) + ':' + pad2(ss)\n}\n\nfunction formatDuration(ms: number): string {\n  if (ms == null || ms <= 0) return '0秒'\n  const s = Math.floor(ms / 1000)\n  if (s < 60) return s + '秒'\n  const m = Math.floor(s / 60)\n  return m + '分' + (s % 60) + '秒'\n}\n\nfunction formatStr(s: string | null): string {\n  if (s == null || s.length < 1) return '-'\n  return s\n}\n\nfunction formatTriggerType(t: string): string {\n  if (t === 'app_duration') return 'APP时长'\n  if (t === 'manual') return '手动'\n  if (t === 'scheduled') return '定时'\n  if (t === 'time_period') return '时段'\n  if (t === 'usage_threshold') return '阈值'\n  if (t === 'app_switch') return '切换'\n  return t\n}\n\nfunction formatActionId(id: string | null): string {\n  if (id == null || id.length < 1) return '-'\n  const a = getActionById(id)\n  if (a != null) return a.name\n  if (id === 'eye_blink') return '眨眼休息'\n  if (id === 'eye_rotate') return '眼球转动'\n  if (id === 'far_gaze') return '远眺放松'\n  if (id === 'neck_rotate') return '颈部转动'\n  if (id === 'shoulder_roll') return '肩膀绕环'\n  if (id === 'neck_stretch') return '肩颈拉伸'\n  if (id === 'core_tighten') return '核心收紧'\n  if (id === 'heel_raise') return '踮脚唤醒'\n  if (id === 'deep_breath') return '减压呼吸'\n  return id\n}\n\nfunction formatActionType(t: string | null): string {\n  if (t == null || t.length < 1) return '-'\n  if (t === 'eye') return '护眼'\n  if (t === 'posture') return '体态'\n  if (t === 'vitality') return '活力'\n  if (t === 'breath') return '呼吸'\n  if (t === 'neck_shoulder') return '肩颈'\n  if (t === 'core') return '核心'\n  if (t === 'lower_body') return '下肢'\n  return t\n}\n\nfunction formatTriggerLevel(level: string | null): string {\n  if (level == null || level.length < 1) return '-'\n  if (level === 'gentle') return '轻提醒'\n  if (level === 'strong') return '强提醒'\n  if (level === 'night') return '夜间轻提醒'\n  return level\n}\n\nfunction formatSkipReason(reason: string | null): string {\n  if (reason == null || reason.length < 1) return '-'\n  if (reason === 'busy') return '正在忙'\n  if (reason === 'too_hard') return '动作有点难'\n  if (reason === 'bad_timing') return '时间不合适'\n  if (reason === 'dont_want') return '现在不想做'\n  if (reason === 'other') return '其他原因'\n  return reason\n}\n\nfunction formatTableName(name: string): string {\n  if (name === 'action_logs') return '动作记录'\n  if (name === 'trigger_logs') return '提醒触发记录'\n  if (name === 'user_settings') return '用户设置'\n  if (name === 'daily_summaries') return '每日小结'\n  if (name === 'trigger_rules') return '提醒规则'\n  if (name === 'app_usage_snapshots') return 'App 使用快照'\n  if (name === 'tts_cache') return '语音缓存'\n  if (name === 'heartbeat_logs') return '守护心跳记录'\n  if (name === 'llm_cache') return 'AI 缓存'\n  return name\n}\n\nfunction formatConfigKey(key: string): string {\n  if (key === 'action_duration_pref') return '默认动作时长'\n  if (key === 'category_target_count') return '每日目标次数'\n  if (key === 'dnd_start') return '免打扰开始'\n  if (key === 'dnd_end') return '免打扰结束'\n  if (key === 'guide_completed') return '引导页状态'\n  if (key === 'llm_trigger_enabled') return 'AI 实时建议'\n  if (key === 'llm_trigger_ask_each_time') return '每次询问 AI 建议'\n  if (key === 'app_duration_threshold') return '连续使用提醒阈值'\n  if (key === 'trigger_enabled') return '自动触发'\n  return key\n}\n\nfunction formatConfigValue(key: string, value: string): string {\n  if (key === 'guide_completed') return value === '1' ? '已完成' : '未完成'\n  if (key === 'llm_trigger_enabled' || key === 'llm_trigger_ask_each_time' || key === 'trigger_enabled') {\n    return value === 'true' || value === '1' ? '开启' : '关闭'\n  }\n  if (key === 'action_duration_pref') return value + ' 秒'\n  if (key === 'category_target_count') return value + ' 次'\n  if (key === 'app_duration_threshold') return value + ' 分钟'\n  return value\n}\n\nfunction formatUserAction(ua: UserAction | null): string {\n  if (ua == null) return '未响应'\n  if (ua === 'completed') return '完成'\n  if (ua === 'self_reported') return '自我报告'\n  if (ua === 'skipped') return '跳过'\n  if (ua === 'feedback') return '反馈'\n  if (ua === 'ignored') return '忽略'\n  if (ua === 'timeout') return '超时'\n  if (ua === 'busy_remind_later') return '忙，稍后'\n  return ua\n}\n\nfunction formatResult(r: ActionResult): string {\n  if (r === 'completed') return '完成'\n  if (r === 'self_reported') return '已做'\n  if (r === 'skipped') return '跳过'\n  if (r === 'feedback') return '反馈'\n  return r\n}\n\nfunction loadDbOverview(): void {\n  const infos: DbTableInfo[] = []\n  for (let i = 0; i < KNOWN_TABLES.length; i++) {\n    const t = KNOWN_TABLES[i]\n    try {\n      const row = dbManager.queryOne('SELECT COUNT(*) AS cnt FROM ' + t, [])\n      const rawCnt = row != null ? row.get(\"cnt\") : null\n      const cnt: number = rawCnt != null ? parseFloat('' + rawCnt) : 0\n      infos.push({ name: t, count: cnt })\n    } catch (e) {\n      console.error('[debug] loadDbOverview count error for ' + t + ': ' + e)\n      infos.push({ name: t, count: 0 })\n    }\n  }\n  dbTableInfos.value = infos\n\n  try {\n    const raw = dbManager.query('SELECT * FROM action_logs ORDER BY created_at DESC LIMIT 5', [])\n    const logs: ActionLog[] = []\n    for (let i = 0; i < raw.length; i++) {\n      const r = raw[i]\n      logs.push({\n        id: r.get(\"id\") as number,\n        action_id: r.get(\"action_id\") as string,\n        action_type: r.get(\"action_type\") as string,\n        result: r.get(\"result\") as ActionResult,\n        skip_reason: r.get(\"skip_reason\") as string | null,\n        trigger_type: r.get(\"trigger_type\") as string,\n        trigger_level: r.get(\"trigger_level\") as string,\n        duration_ms: r.get(\"duration_ms\") as number,\n        target_ms: r.get(\"target_ms\") as number,\n        triggered_at: r.get(\"triggered_at\") as number,\n        completed_at: r.get(\"completed_at\") as number,\n        created_at: r.get(\"created_at\") as number\n      })\n    }\n    dbRecentActions.value = logs\n  } catch (_) {\n    dbRecentActions.value = []\n  }\n}\n\nfunction loadConfig(): void {\n  try {\n    const raw = dbManager.query('SELECT key, value FROM user_settings ORDER BY key ASC', [])\n    const items: ConfigItem[] = []\n    for (let i = 0; i < raw.length; i++) {\n      const r = raw[i]\n      items.push({ key: r.get(\"key\") as string, value: r.get(\"value\") as string })\n    }\n    configList.value = items\n  } catch (_) {\n    configList.value = []\n  }\n}\n\nfunction refresh(): void {\n  try {\n    triggerLogs.value = getTodayTriggerLogs()\n    console.log('[debug] triggerLogs count=' + triggerLogs.value.length)\n  } catch (e) {\n    console.error('[debug] getTodayTriggerLogs error: ' + e)\n    triggerLogs.value = []\n  }\n  try {\n    actionLogs.value = getTodayLogs()\n    console.log('[debug] actionLogs count=' + actionLogs.value.length)\n  } catch (e) {\n    console.error('[debug] getTodayLogs error: ' + e)\n    actionLogs.value = []\n  }\n  try { completedCount.value = countCompletedToday() } catch (e) { console.error('[debug] countCompletedToday error: ' + e); completedCount.value = 0 }\n  try { skippedCount.value = countSkippedToday() } catch (e) { console.error('[debug] countSkippedToday error: ' + e); skippedCount.value = 0 }\n  loadDbOverview()\n  loadConfig()\n}\n\nfunction switchTab(tab: string): void {\n  currentTab.value = tab\n}\n\nfunction goBack(): void {\n  uni.navigateBack({})\n}\n\nonPageShow(() => {\n  console.log('[debug] onPageShow firing refresh')\n  refresh()\n})\n</script>\n\n<style scoped>\n.page { flex: 1; background-color: #162038; position: relative; overflow: hidden; }\n.page-bg { position: absolute; left: 0; top: 0; width: 100%; height: 100%; z-index: 0; }\n.page-bg-img { width: 100%; height: 100%; }\n.header,\n.stats-row,\n.tab-bar,\n.log-item,\n.db-table-card,\n.config-item { background-color: rgba(29, 25, 62, 0.82); background-image: linear-gradient(135deg, rgba(48,